-- Poems batch 284
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cb8d121d-98dc-45d9-8c27-12c1d0b2c8c0','可笑口號  其二','文同','宋','宋诗','song-poetry','','[]','可笑陵陽太守家，閑無一事只栽花。',32,'全唐诗/poet.song.25000.json','["可笑陵陽太守家，閑無一事只栽花。", "已開漸落并纔發，長作亭中五色霞。"]'),
('cf280541-16fa-4258-8f6f-610e49317ac1','可笑口號  其三','文同','宋','宋诗','song-poetry','','[]','可笑此公何太惑，讀書寫字到三更。',32,'全唐诗/poet.song.25000.json','["可笑此公何太惑，讀書寫字到三更。", "也知學得終無用，自肯辛勤比後生。"]'),
('0e18e648-a987-446f-aeb0-0103584761a9','可笑口號  其四','文同','宋','宋诗','song-poetry','','[]','可笑生平事迂闊，向人不肯强云云。',32,'全唐诗/poet.song.25000.json','["可笑生平事迂闊，向人不肯强云云。", "到頭官職難遷轉，一似城南蕭次君。"]'),
('0a47b8f7-cbd2-4430-8339-c1d2cc83093d','可笑口號  其五','文同','宋','宋诗','song-poetry','','[]','可笑爲官太徼幸，養愚藏拙在深山。',32,'全唐诗/poet.song.25000.json','["可笑爲官太徼幸，養愚藏拙在深山。", "君看處置繁難者，日夜經營心不閑。"]'),
('3b7f8afd-fd99-445f-a63a-f8bb21e741bf','可笑口號  其六','文同','宋','宋诗','song-poetry','','[]','可笑兒孫亦滿眼，朝朝庭下立參差。',32,'全唐诗/poet.song.25000.json','["可笑兒孫亦滿眼，朝朝庭下立參差。", "謂言飽讀詩書去，憔悴如翁亦好爲。"]'),
('be361549-de47-413a-a607-7c4e95fffab6','可笑口號  其七','文同','宋','宋诗','song-poetry','','[]','可笑山州爲刺史，寂寥都不似川城。',32,'全唐诗/poet.song.25000.json','["可笑山州爲刺史，寂寥都不似川城。", "若無書籍兼圖畫，便不教人白髪生。"]'),
('a9084820-5607-4acb-9d65-faa2ff661e00','近日','文同','宋','宋诗','song-poetry','','[]','近日簿書全簡少，吏人惟趁兩衙休。',32,'全唐诗/poet.song.25000.json','["近日簿書全簡少，吏人惟趁兩衙休。", "歸來便只尋冠屨，遶遍林亭山上頭。"]'),
('e60821ee-a279-472d-8e95-24795f543dc0','送知府吳龍圖','文同','宋','宋诗','song-poetry','','[]','國初已來治蜀者，處置盡自乖崖公。',320,'全唐诗/poet.song.25000.json','["國初已來治蜀者，處置盡自乖崖公。", "當時奏使便宜敕，不與天下州府同。", "行之已及八十載，姦宄消伏誰之功。", "因循至此漸抏敝，有未曉者時相攻。", "鞭笞小罪亦檢察，不許略出常科中。", "下民知之頗不懼，州縣往往藏群凶。", "側身斂足未動者，實以累朝恩澤隆。", "公之初來蜀人喜，慈愛舊熟民情通。", "衆心歡然耻犯法，捄藥浮薄歸醇醲。", "盡將約束付僚吏，興起學校還文翁。", "二年美化極沾洽，遠近循服如偃風。", "上將歸公問誰代，當使間作如笙鏞。", "遂求元老得青社，其人廊廟之宗工。", "往年鎮撫有異績，大旆再遣來於東。", "公今與之合符去，到必奉詔參夔龍。", "大資舊德固無慮，剖判自出其心胸。", "所憂厥後嗣之者，忠定良法還如空。", "養頑活狡作淵藪，不免剪殄煩興戎。", "同之憤懣久填臆，言賤不得通九重。", "願公上殿起居罷，第一用此聞宸聰。"]'),
('c349e206-e641-45fd-b77c-7b2601925ba3','送通判喻郎中','文同','宋','宋诗','song-poetry','','[]','前年爲郡得陵時，不謂其州陋如此。',240,'全唐诗/poet.song.25000.json','["前年爲郡得陵時，不謂其州陋如此。", "蕭條官宇岩嶺上，零落民家坑谷裏。", "西城初入已可厭，竊謂豈堪余所止。", "幸逢之彥倅郡事，日月漸深殊可喜。", "予之所稟至迂謬，君亦恬然尤自委。", "每來聚議一朝罷，各去掩門歸隠几。", "雖然有時亦爲會，此事可知誰得已。", "酒肴粗糲妓樂可，况復譊譊滿公使。", "惟於試茶并看畫，以此過從不知幾。", "幕中有客乃佳士，愛遣高談聽亹亹。", "如斯共處五百日，索寞情懷未嘗起。", "君今官滿忽先去，撩動予愁安可柅。", "英溪長亭一揮手，自此吳蜀五千里。", "謂言川江會北固，中亦有船多上水。", "願君因出到金山，遇此莫忘批紙尾。"]'),
('75755b99-3953-4ca0-92eb-0ac0c7b4547e','送通判喻郎中  其一','文同','宋','宋诗','song-poetry','','[]','晴霞照西城，漠漠卷宿霧。',96,'全唐诗/poet.song.25000.json','["晴霞照西城，漠漠卷宿霧。", "高空繚危磴，此乃君去路。", "吳蜀向萬里，上馬初一步。", "莫言道途遠，况已嗟久寓。", "今茲有行色，便可到北固。", "長亭聊把手，幾日更逢遇。", "不敢醉君酒，君意實急遽。", "惟是送君心，相隨亦東騖。"]'),
('612fe167-2eab-4a8b-9b10-fc44da5b8762','送通判喻郎中  其二','文同','宋','宋诗','song-poetry','','[]','群居五百日，日日如初見。',216,'全唐诗/poet.song.25000.json','["群居五百日，日日如初見。", "一日忽遠別，能不成愴戀。", "人生三萬日，光景若激箭。", "何苦於其間，喜慍費顔面。", "茲緣勝心在，胸內每交戰。", "既欲多上人，計校須自衒。", "於事固無補，在己亦非便。", "仕路繁此徒，可謂丈夫賤。", "愛君性渾厚，殊不與時變。", "相共爲此州，敢說皆盡善。", "何嘗分彼此，惟務乃職辦。", "所以將二年，無有長短辨。", "爲人倘如此，所至復何患。", "官滿去還臺，豈能忘眷眷。", "陽關調雖苦，且盡西城宴。", "問君到京國，幾月方下汴。", "予亦想是時，移守至梁甸。", "佳音幸見及，西南足郵傳。"]'),
('cf583e4e-b0fe-489d-ae73-4322c47ea3be','山城秋日野望感事書懷詩五章呈吳龍圖  其一','文同','宋','宋诗','song-poetry','','[]','原隰蕭條草木衰，倚風渾類楚人悲。',64,'全唐诗/poet.song.25000.json','["原隰蕭條草木衰，倚風渾類楚人悲。", "便成孤憤終何事，且寄遥懷對此時。", "千里暝陰雲杳靄，一川寒影雁參差。", "登臨自不宜羈旅，更敢憑高賸作詩。"]'),
('62519c7c-09c0-4ea4-b6ba-b839a664e848','山城秋日野望感事書懷詩五章呈吳龍圖  其二','文同','宋','宋诗','song-poetry','','[]','已是秋陰更夕曛，亂山高下起寒雲。',64,'全唐诗/poet.song.25000.json','["已是秋陰更夕曛，亂山高下起寒雲。", "危樓願見客何處，遠笛不知人厭聞。", "身外流年波渺渺，眼前生事葉紛紛。", "此愁萬斛誰量得，直爲重拈庾信文。"]'),
('9dbab1b7-644a-404f-afb1-ad433d47fb6d','山城秋日野望感事書懷詩五章呈吳龍圖  其三','文同','宋','宋诗','song-poetry','','[]','才力雖難敵楚騷，賦詩常亦在秋多。',64,'全唐诗/poet.song.25000.json','["才力雖難敵楚騷，賦詩常亦在秋多。", "自然野思元無限，不爾閑愁可奈何。", "要路故人皆廢忘，偏州佳客少經過。", "明時且爲貪榮祿，豈學湘纍便九歌。"]'),
('ecd0d602-f1ae-423c-9086-cba95e436614','山城秋日野望感事書懷詩五章呈吳龍圖  其四','文同','宋','宋诗','song-poetry','','[]','岩谷雨餘生晚烟，高城危閣坐蕭然。',64,'全唐诗/poet.song.25000.json','["岩谷雨餘生晚烟，高城危閣坐蕭然。", "側身仕路本誰使，回首家山空自憐。", "遠信斷來從過雁，苦吟多後敵鳴蟬。", "郡齋有客唯莊叟，常與高譚內外篇。"]'),
('d84ed866-c0ca-4a59-a870-f37cdd1aeb06','山城秋日野望感事書懷詩五章呈吳龍圖  其五','文同','宋','宋诗','song-poetry','','[]','早是蓬山預校讎，起居常赴殿東頭。',64,'全唐诗/poet.song.25000.json','["早是蓬山預校讎，起居常赴殿東頭。", "鵷鸞擁陛聯簪笏，日月開天拜冕旒。", "一出光陰銷遠郡，兩形篇什詠清秋。", "有人更在楊莊上，文似相如肯見休。"]'),
('c8b93d22-67fc-460c-afe8-f099b4d24af5','東丘老人','文同','宋','宋诗','song-poetry','','[]','東丘老人眉有毫，皮肉光潤牙齒牢。',128,'全唐诗/poet.song.25000.json','["東丘老人眉有毫，皮肉光潤牙齒牢。", "自云新年九十九，鬚髪白者無一毛。", "問之吾術本無有，咽津納息徒嘈嘈。", "莫將元氣佐喜怒，自然所得春秋高。", "吾嘗行之五十載，此事至易曾不勞。", "飲之以酒謝使去，手足輕利如猿猱。", "嘗聞唐人柳公度，八十許歲精力豪。", "其言與人亦如此，老人無乃斯人曹。"]'),
('fc7b7462-52c2-46cc-8192-e447b0fc154a','送堅甫同年  其一','文同','宋','宋诗','song-poetry','','[]','堅甫神太清，不謂久流落。',120,'全唐诗/poet.song.25000.json','["堅甫神太清，不謂久流落。", "別來二十載，論議轉深博。", "其中富所有，種道以文穫。", "鋪張講治亂，破若勁弩彍。", "衆人誚青衫，可笑俗眼薄。", "蘭筋隠瘦骨，垂耳受羈絡。", "拳攣喙拄地，過者無伯樂。", "去蜀持底歸，雄藁滿壞橐。", "朝辭玉壘關，暮上石柜閣。", "知子者云誰，獨我懷抱惡。"]'),
('7be712a8-16b8-4d92-9f92-076ca3de651a','送堅甫同年  其二','文同','宋','宋诗','song-poetry','','[]','得數常奇懶下籌，肯來荒徼治纍囚。',64,'全唐诗/poet.song.25000.json','["得數常奇懶下籌，肯來荒徼治纍囚。", "三年笑別浙江遠，萬里吟歸岷嶺秋。", "趙壹囊空常骯髒，虞卿書就愈窮愁。", "跖香回臭都休問，未有林泉且宦游。"]'),
('b4765001-d994-4f4d-b025-3d4a630d8ba0','送堅甫同年  其三','文同','宋','宋诗','song-poetry','','[]','春深行劍棧，羨子此時歸。',48,'全唐诗/poet.song.25000.json','["春深行劍棧，羨子此時歸。", "照日江浮馬，迎風花聚衣。", "下程家累省，對景俗題稀。", "若遇西來客，書言不可違。"]'),
('a28cf743-b332-4399-8501-bfa499a8b844','送堅甫同年  其四','文同','宋','宋诗','song-poetry','','[]','春風吹雪滿西窗，此夜無人對酒缸。',32,'全唐诗/poet.song.25000.json','["春風吹雪滿西窗，此夜無人對酒缸。", "若到杭州見蘇子，爲言常夢過松江。"]'),
('6996fe51-e0ab-4797-ab84-dda4517fdb0e','送堅甫同年  其五','文同','宋','宋诗','song-poetry','','[]','華亭有珍禽，毛豐而骨細。',24,'全唐诗/poet.song.25000.json','["華亭有珍禽，毛豐而骨細。", "他日上隋渠，爲我致清唳。"]'),
('a6ebacff-7f54-442a-8b76-8754bf14e5fe','送李道士歸','文同','宋','宋诗','song-poetry','','[]','先生狀貌古，瘦健若老鶴。',48,'全唐诗/poet.song.25000.json','["先生狀貌古，瘦健若老鶴。", "秋風唳清霄，寒響滿寥廓。", "一腹冰雪詞，勿爲俗人作。", "便可住鵝池，乾死守岩壑。"]'),
('5c3ddf00-e794-4e68-8c3f-df2c36c5a676','師厚還朝','文同','宋','宋诗','song-poetry','','[]','聞公之名三十年，常恨與公不相值。',96,'全唐诗/poet.song.25000.json','["聞公之名三十年，常恨與公不相值。", "豈期今乃出門下，每一見公心自醉。", "詞章豪蕩已難敵，辨論注射尤可畏。", "諮詢故事要蔣乂，講正大體須賈誼。", "荆山拾玉抵乾鵲，虞坂裝鹽壓良驥。", "用人最忌非所宜，願莫使公嗟俗吏。"]'),
('9f503a38-7413-4b2f-aa3c-e1a52ca8e642','牽牛織女','文同','宋','宋诗','song-poetry','','[]','桂陽有仙人，姓成名武丁。',156,'全唐诗/poet.song.25000.json','["桂陽有仙人，姓成名武丁。", "胡爲墮人世，人惟識其形。", "一日語其弟，吾將返青冥。", "乃曰此七夕，上天呼群靈。", "織女欲渡河，暫詣牽牛星。", "諸仙盡還宮，天路羅雲軿。", "吾亦向祈召，當往不得停。", "弟問何時還，答云三千齡。", "明日失丁在，恍惚迷所經。", "後世凡此節，兒女喧家庭。", "縱橫具鍼縷，花果排甘馨。", "貪巧但云得，欲寐曾莫寧。", "俗尚每怪妄，吾言誰見聽。"]'),
('08db7df6-535b-496e-881f-a1a14d3200d6','金鳳花','文同','宋','宋诗','song-poetry','','[]','花有金鳳爲小叢，秋色已深方盛發。',147,'全唐诗/poet.song.25000.json','["花有金鳳爲小叢，秋色已深方盛發。", "英英秀質實具體，文采爛然無少缺。", "纖莖翩翩翠影動，紅白紛亂如點纈。", "誰云脆弱易飄墮，自卵至翼亦數月。", "美人形相欲摹畫，巧不得施暫自拙。", "鋪茸剪綵轉難似，只把長條恣穿結。", "眼前草木盡零落，憐爾開於此時節。", "常疑一如小兒花，性命所繫不忍折。", "君不見昨夜雨，今朝風，一隊驚飛返丹穴。"]'),
('69e593d3-03f6-4203-880e-1ec0fd113622','亭前高柏','文同','宋','宋诗','song-poetry','','[]','石田磽磽地力燥，誰種雙柏已高大。',64,'全唐诗/poet.song.25000.json','["石田磽磽地力燥，誰種雙柏已高大。", "長材夭矯堪巨棟，老頂縈紆若層蓋。", "雪下孔翠寒不起，風中笙簧清可愛。", "菟絲幸好求女蘿，莫倚纖柔欲無頼。"]'),
('817bb6c3-d182-48e8-827b-b02539c0e38a','凌霄附柏','文同','宋','宋诗','song-poetry','','[]','古柏蒼蒼高入雲，凌霄萬朵擁其身。',32,'全唐诗/poet.song.25000.json','["古柏蒼蒼高入雲，凌霄萬朵擁其身。", "有如巨君染須髪，新娶杜陵佳麗人。"]'),
('64d6466f-3c1c-4735-9e0c-aa47e7aed112','謝黄森惠詩并草書','文同','宋','宋诗','song-poetry','','[]','南䣢黄夫子，生平氣凜然。',48,'全唐诗/poet.song.25000.json','["南䣢黄夫子，生平氣凜然。", "吟詩舊有癖，寫字近方顛。", "可惜空山老，須爲後世傳。", "蘭溪修禊否，願續永和年。"]'),
('ad057982-da70-460e-a68b-7996b2b8d05a','東齋悶書','文同','宋','宋诗','song-poetry','','[]','讀書已無效，何用轉勞苦。',48,'全唐诗/poet.song.25000.json','["讀書已無效，何用轉勞苦。", "閑齋幸無事，日共古人語。", "古人議論好，善惡皆有補。", "舍此欲奚爲，惟應睡滿午。"]'),
('24f0209b-2927-49a2-9f9a-7c75a96a8094','寒食感事呈同官','文同','宋','宋诗','song-poetry','','[]','三月八日值寒食，陰霾蔽空不肯收。',64,'全唐诗/poet.song.25000.json','["三月八日值寒食，陰霾蔽空不肯收。", "北園花木殊未動，到處哭雨惟鳴鳩。", "吾曹可憐愛薄宦，甘此寂寞來山州。", "酒肴有無更莫問，逢遇相與清談休。"]'),
('4277815d-c2ae-47ab-872c-5a3a490f7e90','惜杏','文同','宋','宋诗','song-poetry','','[]','北園山杏皆高株，新枝放花如點酥。',64,'全唐诗/poet.song.25000.json','["北園山杏皆高株，新枝放花如點酥。", "早來其間有啼鳥，兒女盡識名提壺。", "急教取酒對之飲，滿頭亂插紅模糊。", "可憐後日再來此，定見隨風如錦鋪。"]'),
('8690bfe1-e37f-4e92-b475-85bf159e9722','讀蔣都官畫像記','文同','宋','宋诗','song-poetry','','[]','聞昔妖氛滿巴蜀，所臨州縣偃如風。',64,'全唐诗/poet.song.25000.json','["聞昔妖氛滿巴蜀，所臨州縣偃如風。", "其城陷者盡從賊，以義死之惟有公。", "節與岷山高莫敵，名隨皁水注無窮。", "蘭臺秉筆今誰氏，舍此何由壯史功。"]'),
('7b2affd7-3515-434e-9f9b-260d3025f12e','題黎公照序訓堂','文同','宋','宋诗','song-poetry','','[]','常愛三峨臨古郡，君之別業在其城。',64,'全唐诗/poet.song.25000.json','["常愛三峨臨古郡，君之別業在其城。", "近營大第當高處，更起新堂立美名。", "滿外江山皆秀絕，入中文史自縱橫。", "如何置得烏尤住，相與談經過此生。"]'),
('a5ccea8f-13b3-4077-8d7b-2487ec55e418','朝陽亭','文同','宋','宋诗','song-poetry','','[]','峨峨乎守居，已與前峰對。',48,'全唐诗/poet.song.25000.json','["峨峨乎守居，已與前峰對。", "朝陽乃危榭，更在守居外。", "烟雲一川滿，林麓三山會。", "近檻有胡床，無忘傲公退。"]'),
('b147e1bf-6e84-4ec6-a48e-6934e5c7c129','觀風閣','文同','宋','宋诗','song-poetry','','[]','危閣覆高林，晚步聊徙倚。',72,'全唐诗/poet.song.25000.json','["危閣覆高林，晚步聊徙倚。", "東南兩峰斷，空闊見萬里。", "茫茫落霞外，苒苒孤烟裏。", "忽暗識歸雲，乍明知積水。", "風從半天下，月向平地起。", "夜久殊未還，峨冠露盈几。"]'),
('7584b9e7-82eb-4594-aae5-93fe4d826957','山池','文同','宋','宋诗','song-poetry','','[]','偪側蒼苔地，𠇗邪白石池。',48,'全唐诗/poet.song.25000.json','["偪側蒼苔地，𠇗邪白石池。", "數枝紅菡萏，幾尺碧漣漪。", "魚鱉爭香餌，兒童簇釣絲。", "愛來芳蔭下，每日日西時。"]'),
('c0b9312f-9981-4fc0-87de-57d110f314ae','憶西湖舊游','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖晴碧晚溶溶，與客常來坐好風。',32,'全唐诗/poet.song.25000.json','["西湖晴碧晚溶溶，與客常來坐好風。", "記得有人歌小玉，月明猶在畫船中。"]'),
('a2c94131-8090-48e2-8f49-4cc04d44b07d','再送師厚','文同','宋','宋诗','song-poetry','','[]','久使西南此召還，鹿頭東去漸雲山。',64,'全唐诗/poet.song.25000.json','["久使西南此召還，鹿頭東去漸雲山。", "莫嫌策馬經燒棧，正好題詩到散關。", "財利文書猶絡繹，邊防田地已朱殷。", "奇謀不吐將何用，况是歸臨咫尺顔。"]'),
('d7f7f070-591c-4a73-bde5-03c5721d768b','平雲閣觀雨','文同','宋','宋诗','song-poetry','','[]','黑雲漆天雷破地，風卷雷射雨傾瀉。',64,'全唐诗/poet.song.25000.json','["黑雲漆天雷破地，風卷雷射雨傾瀉。", "噴崖倒壑恣頹蕩，咫尺不可辨牛馬。", "鷄豚已見逐高浪，禾稻應須沒平野。", "莫言魚鱉走堂厨，且看泥沙漫屋瓦。"]'),
('92b384fb-5092-4bab-a633-893a5c10ac5c','不雨','文同','宋','宋诗','song-poetry','','[]','陵陽官居遇久旱，發喘渾如起新病。',64,'全唐诗/poet.song.25000.json','["陵陽官居遇久旱，發喘渾如起新病。", "已驚赤日晨可畏，更恨炎風午尤盛。", "徒嗟禾黍盡焦落，無奈蠅虻轉豪橫。", "安得神龍駕九霄，大霔滿傾如倒井。"]'),
('3d23bd58-f2b6-4789-b1b9-02cede40a23e','久雨','文同','宋','宋诗','song-poetry','','[]','寒鳩劬劬屋上鳴，欲使此雨何時晴。',64,'全唐诗/poet.song.25000.json','["寒鳩劬劬屋上鳴，欲使此雨何時晴。", "山中有客抱幽鬰，日日起望東方明。", "今朝晚霞發光焰，喜極再拜當西楹。", "須臾雲陰又蒙沒，遣我涕淚流沾纓。"]'),
('03c12395-a801-4f41-b3ec-3e6915a28ebe','山園','文同','宋','宋诗','song-poetry','','[]','久雨無所適，新晴步山園。',48,'全唐诗/poet.song.25000.json','["久雨無所適，新晴步山園。", "西風滿高林，敗葉驚已翻。", "時節急如此，世事安可論。", "夜歸燈下吟，寒蟲伴幽喧。"]'),
('de78fe11-f985-4dc3-9949-14a10d0794fc','石泉','文同','宋','宋诗','song-poetry','','[]','儼儼聳石壁，拆穴中流泉。',48,'全唐诗/poet.song.25000.json','["儼儼聳石壁，拆穴中流泉。", "斷崖散激激，曲竇藏涓涓。", "蓄潤活古蘚，烝虛發晴烟。", "時懷一勺惠，使我心泠然。"]'),
('956f5df8-f6ac-4a9b-8eb7-484211f3eac8','史少訥見許江豚未得以詩戲','文同','宋','宋诗','song-poetry','','[]','霜重水落岸有冰，江豚乘寒弄晴日。',64,'全唐诗/poet.song.25000.json','["霜重水落岸有冰，江豚乘寒弄晴日。", "摇波拍浪乍群起，尾厚喙長鬐鬣赤。", "魚人清曉橫巨舟，一舉大網凡數頭。", "想君盤筯已厭足，何不略遣來陵州。"]'),
('90687ad4-a2ee-458b-aa81-dd9f9f7e826e','北園梨花','文同','宋','宋诗','song-poetry','','[]','寒食北園春已深，梨花滿枝雪圍遍。',64,'全唐诗/poet.song.25000.json','["寒食北園春已深，梨花滿枝雪圍遍。", "清香每向風外得，秀艷應難月中見。", "苦嫌桃李共妖冶，多謝松篁相葱蒨。", "黄鸝紫燕莫過從，時有一聲拖白練。"]'),
('985409b4-6ed1-4b47-a668-0ac4c817b42a','華山  其一','文同','宋','宋诗','song-poetry','','[]','岩頭漠漠衛卿雲，谷口紛紛張楷霧。',32,'全唐诗/poet.song.25000.json','["岩頭漠漠衛卿雲，谷口紛紛張楷霧。", "安得鈎梯上石龜，欲看明星洗頭處。"]'),
('8f308616-9ee1-46bf-9df1-038dd4c7569a','華山  其二','文同','宋','宋诗','song-poetry','','[]','石蓮峨峨橫紫霄，中瀉萬丈銀河水。',32,'全唐诗/poet.song.25000.json','["石蓮峨峨橫紫霄，中瀉萬丈銀河水。", "安得大箭長八尺，欲與天神博於此。"]'),
('0954f0e0-9694-45ff-9c89-712a9209c947','黄崖洞','文同','宋','宋诗','song-poetry','','[]','黄崖大洞埋古雲，入去所履平如席。',32,'全唐诗/poet.song.25000.json','["黄崖大洞埋古雲，入去所履平如席。", "其中玉髓盡可餐，只恐歸來變爲石。"]'),
('214b2951-40a1-4d88-987d-5a8b165d12ed','師魯推官惠甘蔗戲謝','文同','宋','宋诗','song-poetry','','[]','滿節甘滋滲齒寒，醍醐誰與釀琅玕。',32,'全唐诗/poet.song.25000.json','["滿節甘滋滲齒寒，醍醐誰與釀琅玕。", "不知佳境何時入，試似前人取倒餐。"]'),
('6abc9c68-7227-4b83-8e74-b438475474ae','寄呈溫江安寺丞','文同','宋','宋诗','song-poetry','','[]','高崖古驛荒凉甚，過客何嘗住久之。',32,'全唐诗/poet.song.25000.json','["高崖古驛荒凉甚，過客何嘗住久之。", "獨有門邊君寫處，每來無不讀多時。"]'),
('a4c38807-388b-495e-bbb8-b9a572bb5b0f','嘲任昉','文同','宋','宋诗','song-poetry','','[]','幸自文章亦可憐，不消一事已爲賢。',32,'全唐诗/poet.song.25000.json','["幸自文章亦可憐，不消一事已爲賢。", "何如却逐蟲兒去，忍耻更來王亮前。"]'),
('ca9d6e0d-de0a-4a5f-b90e-184412fc9303','袁術','文同','宋','宋诗','song-poetry','','[]','四代司空倚世勞，可嗟不肖事姦豪。',32,'全唐诗/poet.song.25000.json','["四代司空倚世勞，可嗟不肖事姦豪。", "妄云名字與讖合，直欲起應當塗高。"]'),
('98d7c579-2688-4586-97e4-4b93cbfc0b63','偶成','文同','宋','宋诗','song-poetry','','[]','僻陋爲州耻不才，偃然空見兩星回。',32,'全唐诗/poet.song.25000.json','["僻陋爲州耻不才，偃然空見兩星回。", "祇應歸舉謠言日，三府諸君口盡枚。"]'),
('36df3ced-8886-4a53-b224-9f9459111add','即事','文同','宋','宋诗','song-poetry','','[]','公禮欲下格，具觀人所存。',24,'全唐诗/poet.song.25000.json','["公禮欲下格，具觀人所存。", "須知范孟博，豈肯伏陳蕃。"]'),
('f8ae0dc4-1549-458e-8dcc-e4434b2226c4','薄命女','文同','宋','宋诗','song-poetry','','[]','夭夭東鄰姝，艷色如春柔。',48,'全唐诗/poet.song.25000.json','["夭夭東鄰姝，艷色如春柔。", "去嫁不得偶，羅衣空自羞。", "輕埃掩菱花，不分鉛華休。", "回首視庸奴，寂寞還卷收。"]'),
('5951aa67-31f6-402d-b46f-6d08cef4629d','子平寄惠希夷陳先生服唐福山藥方因戲作雜言謝之','文同','宋','宋诗','song-poetry','','["\u534e\u5c71"]','蜀江之東山色盡如赭，有道人云此是丹砂伏其下。',260,'全唐诗/poet.song.25000.json','["蜀江之東山色盡如赭，有道人云此是丹砂伏其下。", "烟雲光潤若洗濯，澗谷玲瓏如刻畫。", "我聞神仙草藥不在凡土生，是中當有靈苗異卉之根莖。", "果然人言所出山芋爲第一，西南諸郡有者皆虛名。", "就中唐福衆稱賞，肥實甘香天所養。", "有時岩頭倒垂三尺壯士臂，忽然洞口直舉一合仙人掌。", "土人入冬農事閑，千篝萬鍤來此山。", "可憐所鬻不甚貴，著價即售曾不慳。", "往年子瞻爲余說，言君所部之內此物尤奇絕。", "後復寄書勸我當餌之，滿紙親題華嶽先生訣。", "予因購之不惜錢，依方服餌將二年。", "其功神聖久乃覺，筋牢體溢支節堅。", "自問丹霄幾時上，早生兩翅教高颺。", "塵世如帤不可居，待看鴻濛對雲將。"]'),
('5e6b7526-721f-41e9-8f93-576df727874f','李太尉','文同','宋','宋诗','song-poetry','','[]','昏雺翳紫極，橫霓勢光大。',240,'全唐诗/poet.song.25000.json','["昏雺翳紫極，橫霓勢光大。", "妖威集凶冀，忍穢實中頼。", "姦鋩日增剡，誰汝觸取害。", "驕根愈自固，所植利孱昧。", "容容彼群輔，竄伏皆鼠輩。", "側視况未敢，肯復形嘆慨。", "太尉漢中士，氣引八極外。", "岌然處大麓，天下聳風采。", "自開煮餠禍，賊意已莫快。", "移書瀝憤膽，語激益睚眥。", "罹冤卒用此，數與六九會。", "基茲被沈酷，燮免乃天貸。", "高忠揭萬古，宇宙莫能載。", "垂晶耀簡策，糞土視廣戒。", "歸來葬墝埆，祠冢茲儼在。", "宏垣敞深豁，巨木森晻曖。", "神靈皎如日，過者知再拜。", "同愚忝郡寄，公里曰境內。", "心期款舉像，所顧官有礙。", "精衷託明酌，舉手向東酹。"]'),
('f6ff95c5-076c-42d2-89b6-6a7a79febcd1','趙壹','文同','宋','宋诗','song-poetry','','[]','壹也本西縣，狀貌徒磊砢。',144,'全唐诗/poet.song.25000.json','["壹也本西縣，狀貌徒磊砢。", "其才固難得，行有所不可。", "世人詎能掩，而爾輒自我。", "既慾焉得剛，所守實未果。", "抵罪當至死，其中遂水火。", "一爲人所活，上賦何瑣瑣。", "爲文好譏駡，惡吻事掀簸。", "逢陟與規輩，次第滋爾禍。", "無成困鄉里，倔僵老愈叵。", "何煩遣相視，器識自幺麽。", "余因守漢中，作詩揭墓左。", "勸君莫學壹，學壹終坎軻。"]'),
('2b369ab6-d307-460d-b992-db49f8bb9a84','張騫冢祠','文同','宋','宋诗','song-poetry','','[]','中梁山麓漢水濱，路側有墓高嶙峋。',67,'全唐诗/poet.song.25000.json','["中梁山麓漢水濱，路側有墓高嶙峋。", "叢祠蓊蔚蔽野霧，榜曰博望侯之神。", "當年寶幣走絕域，此日鷄豚邀小民。", "君不見武帝甘心事遠略，靡壞財力由斯人。"]'),
('5c837873-6ba5-4ae1-8623-7eb4f729cf99','駱谷','文同','宋','宋诗','song-poetry','','[]','高峰偃蹇雲崔嵬，層崖巨壑長峽開。',67,'全唐诗/poet.song.25000.json','["高峰偃蹇雲崔嵬，層崖巨壑長峽開。", "龍蛇縱橫虎豹亂，古棧朽裂埋深苔。", "行人側足恐懼過，飛鳥斂翅哀鳴回。", "君不見德宗注意用姦慝，大駕從此蒼黄來。"]'),
('00644afe-c6a2-48e9-9c62-8047709b9f53','慈濟院雙楠','文同','宋','宋诗','song-poetry','','[]','雙楠高聳綠氤氳，密葉長柯蔭四鄰。',64,'全唐诗/poet.song.25000.json','["雙楠高聳綠氤氳，密葉長柯蔭四鄰。", "佛現寶幢經幾劫，天開雲帳待何人。", "護持必有諸賢聖，觸犯寧無惡鬼神。", "付囑寺僧常灑掃，莫令向下有纖塵。"]'),
('bf8e8998-acd7-4f09-9a21-2223d42b32eb','觀音院怪松','文同','宋','宋诗','song-poetry','','[]','怪松屢見無如此，每度來觀說向僧。',64,'全唐诗/poet.song.25000.json','["怪松屢見無如此，每度來觀說向僧。", "若遇風雷宜守護，恐生頭角便飛騰。", "秋聲遶殿隨齋磬，夜影侵廊對佛燈。", "韋偃畢宏今不在，欲求人畫有誰能。"]'),
('188233c3-df0d-4a2d-8661-ffbacad1b2ec','江原張景通善頌堂','文同','宋','宋诗','song-poetry','','[]','庭前雲蓋碧巉岩，堂上先生雪滿髯。',64,'全唐诗/poet.song.25000.json','["庭前雲蓋碧巉岩，堂上先生雪滿髯。", "說藥客來聊下榻，謁齋僧去便垂簾。", "種時法好花難謝，買處錢多石易添。", "子舍光榮身壯健，只將香火事華嚴。"]'),
('f689783c-2a70-4e44-a330-b46cd9678c3e','夏夕','文同','宋','宋诗','song-poetry','','[]','池館蕭然夜欲分，滿林蟲鳥寂無聞。',64,'全唐诗/poet.song.25000.json','["池館蕭然夜欲分，滿林蟲鳥寂無聞。", "風吹松子下如雨，月照荷花繁若雲。", "泉作小灘聲淅瀝，笋成新竹氣氤氳。", "清陰正覆吟詩石，更引高梧拂練裙。"]'),
('e42059f2-b8c2-45b2-b124-0699daabb37c','寄宇文公南','文同','宋','宋诗','song-poetry','','[]','彭澤長謠便歸去，君辭曲水亦其徒。',64,'全唐诗/poet.song.25000.json','["彭澤長謠便歸去，君辭曲水亦其徒。", "一官何藉五斗米，二子况皆千里駒。", "懶對俗人常答颯，厭聞時事但盧胡。", "從來綿竹多賢者，唯是楊雄識壯夫。"]'),
('56ca706e-f401-4651-9d29-a9329c23b4b3','北禪龍井','文同','宋','宋诗','song-poetry','','[]','城北神龍去幾年，近日人言歸舊止。',64,'全唐诗/poet.song.25000.json','["城北神龍去幾年，近日人言歸舊止。", "澄潭沈沈不可近，百步之外毛骨起。", "今年興元輒愆雨，衆懇問龍求滴水。", "香烟纔上雲滿空，一夜滂沱遍千里。"]'),
('e9ff9121-fe79-4aa0-8d9d-a0b6a4004782','送潘司理秘校  其一','文同','宋','宋诗','song-poetry','','[]','已自多時賦式微，五峰佳景夢長飛。',64,'全唐诗/poet.song.25000.json','["已自多時賦式微，五峰佳景夢長飛。", "四年遠地爲官去，萬里高堂喜客歸。", "下馬便呈新授敕，開箱爭認舊縫衣。", "鄉人覓次來相賀，蒓菜鱸魚正軟肥。"]'),
('c0af65d7-155b-4cad-9eb5-96aaf0a8c6af','送潘司理秘校  其二','文同','宋','宋诗','song-poetry','','[]','曲棧繞斜谷，鈎欄天際分。',48,'全唐诗/poet.song.25000.json','["曲棧繞斜谷，鈎欄天際分。", "吟鞭摇嶺月，倦枕拂溪雲。", "好景不關俗，新詩皆屬君。", "西南有歸客，一一幸相聞。"]'),
('62a173d6-f62d-43cc-9206-3290484c690f','收復河湟故地','文同','宋','宋诗','song-poetry','','[]','啞兒峽西山已塵，馱金輦帛無斷群。',64,'全唐诗/poet.song.25000.json','["啞兒峽西山已塵，馱金輦帛無斷群。", "河湟故疆盡收復，解辮厥角歸如雲。", "堂中玉带賜丞相，隴外金節酬將軍。", "唐兵萬里若日月，請作古今人未聞。"]'),
('7fce61fc-73a4-429e-bd6c-1286291228c9','自斜谷第一堰泝舟上觀石門兩岸奇峰最爲佳絕','文同','宋','宋诗','song-poetry','','[]','北風吹雲落寒水，逆波刺船行五里。',64,'全唐诗/poet.song.25000.json','["北風吹雲落寒水，逆波刺船行五里。", "層巒夾空抱叢石，萬劍側脊翠烟起。", "草木枝葉自殊別，禽蟲羽毛亦奇詭。", "安得鷄冠數棱田，便可誅茅此居止。"]'),
('2719bc15-fd39-40b9-aa69-de5b39d56c80','宿斗山奉真宮','文同','宋','宋诗','song-poetry','','[]','山形如斗勢坡陀，魁枕杓携萬尺高。',64,'全唐诗/poet.song.25000.json','["山形如斗勢坡陀，魁枕杓携萬尺高。", "近世無人知火棗，當年有客得蟠桃。", "靈蟾尚隠凝瓊髓，神鶴常歸墮玉毛。", "一夜杉松響天籟，滿空疑是奏雲璈。"]'),
('d4cede26-80ed-4599-beed-d673d6c23e98','晴望漢川','文同','宋','宋诗','song-poetry','','[]','城頭看雨霽，天地若新浴。',48,'全唐诗/poet.song.25000.json','["城頭看雨霽，天地若新浴。", "晚容變雲霞，秋意著草木。", "四時易遷改，萬事苦迫促。", "舊山何日歸，三徑有松菊。"]'),
('2cbe9c44-f509-4782-bb21-ad19dc73036e','清景堂','文同','宋','宋诗','song-poetry','','[]','公外捐塵慮，閑中見物情。',48,'全唐诗/poet.song.25000.json','["公外捐塵慮，閑中見物情。", "蕉花紅炬密，竹節粉環輕。", "燕泊簾鈎語，蜂尋筆架鳴。", "靜能知此趣，吃吃笑勞生。"]'),
('33402b15-9529-4399-9d18-a01a7b66bc7c','梁山大雪','文同','宋','宋诗','song-poetry','','[]','嚴風吹屋鳴，向曉尤凜冽。',48,'全唐诗/poet.song.25000.json','["嚴風吹屋鳴，向曉尤凜冽。", "應從北山上，一夜吹猛雪。", "幽人不能飲，身體冷如鐵。", "空向龍具中，苦吟聲不絕。"]'),
('6aa1113c-357f-4a90-85a0-3159f6fc36e2','寄夏文州左藏佾  其一','文同','宋','宋诗','song-poetry','','[]','翩翩貴公子，佳譽本能文。',48,'全唐诗/poet.song.25000.json','["翩翩貴公子，佳譽本能文。", "大第辭京輦，高旌擁塞雲。", "勸農唐刺史，養士漢將軍。", "莫刻和戎誓，朝廷立功勳。"]'),
('4575dc5a-4c63-46e9-a213-d05918684342','寄夏文州左藏佾  其二','文同','宋','宋诗','song-poetry','','[]','寄語文州守，謀邊想甚勞。',48,'全唐诗/poet.song.25000.json','["寄語文州守，謀邊想甚勞。", "封疆通鳥鼠，種落雜猿猱。", "甲馬廉頗少，詩書郄縠高。", "當須辦乃事，不用耻弓刀。"]'),
('a0ffb207-db37-4673-860a-061dab8b05be','狗溪迎湫祈雨輒應','文同','宋','宋诗','song-poetry','','[]','夏雨渴久矣，秋苗憂槁然。',48,'全唐诗/poet.song.25000.json','["夏雨渴久矣，秋苗憂槁然。", "至誠通祝版，靈貺逐香烟。", "桐祓應無訟，囷倉定有年。", "曹公三大堰，一夜滿民田。"]'),
('9ed20877-6781-47f7-a0e3-2eb2a7c1322f','晚興','文同','宋','宋诗','song-poetry','','[]','衆吏晚已散，西園常訪尋。',48,'全唐诗/poet.song.25000.json','["衆吏晚已散，西園常訪尋。", "覆棋苔閣靜，行藥草橋深。", "草色晴承屐，松陰密灑襟。", "山蚿欲重賦，倚竹聽清音。"]'),
('c4da625c-2d21-421c-8235-6f39fba8808a','嘉川道中寄周正孺','文同','宋','宋诗','song-poetry','','[]','草木春深後，山川雨過時。',48,'全唐诗/poet.song.25000.json','["草木春深後，山川雨過時。", "清佳常滿目，衰倦敢忘詩。", "好尚舊若此，飄零今比誰。", "爭如畫堂上，日日聽新詞。"]'),
('78399f91-365d-4c93-81f6-07a44bc51226','還李中舍奉使集','文同','宋','宋诗','song-poetry','','[]','奉使道中詩百首，古人遺落盡冥搜。',32,'全唐诗/poet.song.25000.json','["奉使道中詩百首，古人遺落盡冥搜。", "自憐吳蜀佳山水，一夜燈前得遍遊。"]'),
('33df94a6-ff5f-4dc6-8e35-523698690832','雪後寄景孺提刑','文同','宋','宋诗','song-poetry','','[]','雲陰低重雪花繁，夾道歡謠引使軒。',32,'全唐诗/poet.song.25000.json','["雲陰低重雪花繁，夾道歡謠引使軒。", "何處郵亭鍊佳句，綵毫揮罷索清樽。"]'),
('9d8895cc-2d2a-46d1-88af-2d1926b04d75','寄永興吳龍圖給事  其一','文同','宋','宋诗','song-poetry','','[]','高舂鈴下索焚香，鏤管紋箋發綵章。',32,'全唐诗/poet.song.25000.json','["高舂鈴下索焚香，鏤管紋箋發綵章。", "應在後園凉榭裏，玄霜仙帽紫霓裳。"]'),
('099e529a-c4a8-4e80-950b-d2c5395e32c3','寄永興吳龍圖給事  其二','文同','宋','宋诗','song-poetry','','[]','見山樓迥倚晴虛，看展終南百幅圖。',32,'全唐诗/poet.song.25000.json','["見山樓迥倚晴虛，看展終南百幅圖。", "聞說二林尤勝絕，想公高興在香爐。"]'),
('e970b851-645d-4f1e-bddb-9eb3c9bb5441','寄永興吳龍圖給事  其三','文同','宋','宋诗','song-poetry','','[]','土風豪盛古長安，誰謂元侯卧治難。',32,'全唐诗/poet.song.25000.json','["土風豪盛古長安，誰謂元侯卧治難。", "使客不來公事少，一床蘄簟石林寒。"]'),
('42d59c0f-321b-4e95-9fa4-3bf35b137c69','不飲自嘲','文同','宋','宋诗','song-poetry','','[]','能詩何水曹，眼不識杯鐺。',36,'全唐诗/poet.song.25000.json','["能詩何水曹，眼不識杯鐺。", "而我豈解吟，亦得不飲名。", "持此以立世，可笑實浪生。"]'),
('d75876a1-f900-4d4b-b6f8-fa5a5092bcc0','寄紀禪師','文同','宋','宋诗','song-poetry','','[]','自笑塵中游宦客，長輸林下坐禪僧。',32,'全唐诗/poet.song.25000.json','["自笑塵中游宦客，長輸林下坐禪僧。", "水田百畝一區宅，歸老城南何日能。"]'),
('dd775e77-f87a-45f8-bed7-683107e39718','中梁山寺  其一','文同','宋','宋诗','song-poetry','','[]','臺殿晻曖山嶕嶢，雲霞鮮明天泬寥。',32,'全唐诗/poet.song.25000.json','["臺殿晻曖山嶕嶢，雲霞鮮明天泬寥。", "側身下望厭塵世，安得羽翼凌九霄。"]'),
('80d37fb3-2431-40cc-be22-d81e2aeac32f','中梁山寺  其二','文同','宋','宋诗','song-poetry','','[]','烟巒彩翠霜林紅，層樓複閣雲霧中。',32,'全唐诗/poet.song.25000.json','["烟巒彩翠霜林紅，層樓複閣雲霧中。", "襟懷太爽睡不得，一夜滿山鈴鐸風。"]'),
('63b2e4fa-d821-424b-bd90-c104713fe8a2','中梁山寺  其三','文同','宋','宋诗','song-poetry','','[]','群峰南北爭嵯峨，如瀉大壑翻衆波。',32,'全唐诗/poet.song.25000.json','["群峰南北爭嵯峨，如瀉大壑翻衆波。", "愛之欲把入圖畫，世無好手將奈何。"]'),
('3ed1aa81-cb42-4461-8701-7ffaba7aa3c9','中梁山寺  其四','文同','宋','宋诗','song-poetry','','[]','上方梯磴繞岩頭，誰就孤高更起樓。',32,'全唐诗/poet.song.25000.json','["上方梯磴繞岩頭，誰就孤高更起樓。", "直望漢江三百里，一條如綫下洋州。"]'),
('f6114598-4220-4c2a-a43d-8d589007f6af','仙人  其一','文同','宋','宋诗','song-poetry','','[]','身著青羅緋衣裙，口誦白羽黑翮文。',32,'全唐诗/poet.song.25000.json','["身著青羅緋衣裙，口誦白羽黑翮文。", "半空欲下復不下，回首翩然歸五雲。"]'),
('1a97da69-3148-4503-92de-63f87e102546','仙人  其二','文同','宋','宋诗','song-poetry','','[]','頭梳三角髻，餘髪散垂腰。',24,'全唐诗/poet.song.25000.json','["頭梳三角髻，餘髪散垂腰。", "時伴秦樓女，月明吹紫簫。"]'),
('44849323-8dab-4029-98ad-b22d035a679a','山堂前庭有奇石數種其狀皆與物形相類在此久矣自余始名而詩之 鸚鵡石','文同','宋','宋诗','song-poetry','','[]','靜立身微聳，驚窺首略回。',24,'全唐诗/poet.song.25000.json','["靜立身微聳，驚窺首略回。", "何人將至此，應自隴山來。"]'),
('bbe6dd15-758c-457d-b4a1-cc1028f4068d','山堂前庭有奇石數種其狀皆與物形相類在此久矣自余始名而詩之 柘枝石','文同','宋','宋诗','song-poetry','','[]','紫蘚裝花帽，紅藤纏臂。',24,'全唐诗/poet.song.25000.json','["紫蘚裝花帽，紅藤纏臂。", "㡚被誰留斷拍，長舞不教休。"]'),
('da8eaac2-c17f-4998-821d-4d7dd6c7e626','山堂前庭有奇石數種其狀皆與物形相類在此久矣自余始名而詩之 狻猊石','文同','宋','宋诗','song-poetry','','[]','巨尾蟠深草，豐毛覆古苔。',24,'全唐诗/poet.song.25000.json','["巨尾蟠深草，豐毛覆古苔。", "雕欄臨綺席，長欲上香臺。"]'),
('14ad3b68-bff2-47c5-b7fa-7798656cc9be','山堂前庭有奇石數種其狀皆與物形相類在此久矣自余始名而詩之 崑崙石','文同','宋','宋诗','song-poetry','','[]','雨漬身如漆，苔侵面若藍。',24,'全唐诗/poet.song.25000.json','["雨漬身如漆，苔侵面若藍。", "問時都不語，應是憶扶南。"]'),
('e657697f-f9e3-4e9c-882f-e0e40844ad49','山堂前庭有奇石數種其狀皆與物形相類在此久矣自余始名而詩之 羅剎石','文同','宋','宋诗','song-poetry','','[]','洗濯形容露，剜挑口眼通。',24,'全唐诗/poet.song.25000.json','["洗濯形容露，剜挑口眼通。", "試教常點檢，每夜定飛空。"]'),
('67de3c6d-1e17-46ea-b787-cceebe96f958','山堂前庭有奇石數種其狀皆與物形相類在此久矣自余始名而詩之 珊瑚石','文同','宋','宋诗','song-poetry','','[]','海底初生處，扶疏苦未全。',24,'全唐诗/poet.song.25000.json','["海底初生處，扶疏苦未全。", "幾時隨鐵網，流落漢江邊。"]'),
('046ae9da-bdd8-4a59-9a47-ab7605b522ab','病眼','文同','宋','宋诗','song-poetry','','[]','病眼每至午，其視何𥉂𥉂。',24,'全唐诗/poet.song.25000.json','["病眼每至午，其視何𥉂𥉂。", "安得張中書，就欲求古方。"]'),
('aff5a79c-98c7-4c48-a437-c1b386c5d339','吾友務深有嘆琴之什運使子駿答之佳章務深亦使余繼作','文同','宋','宋诗','song-poetry','','[]','白水滿方湖，山中好秋色。',72,'全唐诗/poet.song.25000.json','["白水滿方湖，山中好秋色。", "逋翁促瑶軫，來坐湖水側。", "臨風起高調，此興浩無極。", "波靜戢游鱗，雲空矯飛翼。", "蕭條變林野，萬籟一以息。", "且莫緩商弦，令人涕橫臆。"]'),
('c07ce52e-e705-439c-a4ff-0e1f235bb2fa','子駿運使八咏堂 寶峰亭','文同','宋','宋诗','song-poetry','','[]','嘉陵抱江回，平衍出橫澨。',192,'全唐诗/poet.song.25000.json','["嘉陵抱江回，平衍出橫澨。", "中間築雄壘，獨據兩川會。", "行臺敞嚴府，磊砢北城外。", "潭潭走群楹，直上巒嶺背。", "危牆繚空闊，飛閣入茫昧。", "上有寶峰亭，仰見白雲內。", "岧嶢占孤絕，下與萬山對。", "層檐動寥廓，曲檻枕闤闠。", "主人從籃轝，晚興在公退。", "心掩萬象遠，目引八極大。", "鈎簾拂坐榻，隠几緩衣带。", "詩書抉關鍵，筆硯産珠貝。", "是時衆吏去，不敢呈計會。", "雖然彼郡邑，原本窮利害。", "自取金穀饒，無煩米鹽碎。", "此地寄清襟，歲書從屢最。"]'),
('d537efea-dc36-44c1-a311-f81010a39564','子駿運使八咏堂 桐軒','文同','宋','宋诗','song-poetry','','[]','晴影滿空壁，晨曦上清軒。',72,'全唐诗/poet.song.25000.json','["晴影滿空壁，晨曦上清軒。", "庭下雙高桐，枝葉蔚以繁。", "種者意自遠，豈並群木論。", "謂可絙朱絲，中有雅韻存。", "成之在誰手，但爲培霜根。", "須知治世音，盡付於此孫。"]'),
('2bd8db3b-9841-46dc-9bdc-f57369a2258e','子駿運使八咏堂 柏軒','文同','宋','宋诗','song-poetry','','[]','沈沈敞幽軒，聳聳列寒柏。',72,'全唐诗/poet.song.25000.json','["沈沈敞幽軒，聳聳列寒柏。", "清音納窗戶，爽氣逼枕席。", "主人重端勁，坐若對佳客。", "時復下撫摩，破蘚交履迹。", "此意乃如是，來者當愛惜。", "大厦須良材，相期早千尺。"]'),
('bab91f86-a3ea-4dd8-a066-255ffb8489a1','子駿運使八咏堂 竹軒','文同','宋','宋诗','song-poetry','','[]','此景絕可愛，叢筠挺修竿。',72,'全唐诗/poet.song.25000.json','["此景絕可愛，叢筠挺修竿。", "侵簾復映幌，翠影何檀欒。", "霜威忌晚秀，雨氣矜晴寒。", "每向極靜時，幽禽發清彈。", "自無車馬塵，飛來泊琅玕。", "宜遣老鈴下，日日申平安。"]'),
('4c4554ff-83bd-4b54-8b2c-c2b05262fbf5','子駿運使八咏堂 巽堂','文同','宋','宋诗','song-poetry','','[]','華堂聳嚴臺，地勢側隨水。',96,'全唐诗/poet.song.25000.json','["華堂聳嚴臺，地勢側隨水。", "高臨巽宮上，其取名以是。", "峨峨寶峰頂，日影正辰巳。", "繚棧入雲林，詰屈如篆字。", "輕霏互虧蔽，亂樾紛間厠。", "賓來獲清歡，吏散生野思。", "靜見萬物本，一一齊於此。", "體道以行權，端居得深旨。"]'),
('ad1d4a9e-bde9-4c14-bb73-d3b82e28609d','子駿運使八咏堂 山齋','文同','宋','宋诗','song-poetry','','[]','職事凡少休，餘復不經眼。',72,'全唐诗/poet.song.25000.json','["職事凡少休，餘復不經眼。", "幽齋設橫榻，盡日對層巘。", "遥懷寄浩蕩，靜想縈𡾰嵼。", "松雨潤書匳，竹風吹酒盞。", "榮名付傲兀，勝事入清簡。", "雖有舊林泉，何須嗟去晚。"]'),
('805a5809-a448-4bbf-b926-31d189061ff1','子駿運使八咏堂 閑燕亭','文同','宋','宋诗','song-poetry','','[]','靜宇占幽深，是中何所有。',72,'全唐诗/poet.song.25000.json','["靜宇占幽深，是中何所有。", "軒窗極清潔，硯席羅左右。", "公餘每休此，俗客曾不受。", "六尺局脚床，解带就橫肘。", "掃除閑景物，健筆當大帚。", "敢問公許年，得詩凡幾首。"]'),
('c2927407-5b3a-46f6-a7f7-2bafdc44ac1a','子駿運使八咏堂 會景亭','文同','宋','宋诗','song-poetry','','[]','誰茲敞高亭，磴道繞千蹋。',72,'全唐诗/poet.song.25000.json','["誰茲敞高亭，磴道繞千蹋。", "江山接平遠，百里俱會合。", "人間最佳景，窗戶供遠納。", "烟雲互蔽虧，蟲鳥相應答。", "吟箋摘奇勝，畫筆寫紛雜。", "安得日從公，短屐手自蠟。"]'),
('36fcfaec-84a5-45fa-ba7d-a2e61fb07384','呈李堅甫中舍','文同','宋','宋诗','song-poetry','','[]','往年曾憶過長安，短紙書名詣門下。',256,'全唐诗/poet.song.25000.json','["往年曾憶過長安，短紙書名詣門下。", "君時延我坐終日，灑掃東軒留看畫。", "橫圖巨軸不知數，但見匣中時一把。", "甲猶未竟乙復作，門類著番開滿架。", "使人嘆羨不能已，只恨有門歸隔夜。", "歸來兀坐想精絕，念此榮觀若爲謝。", "就中寒林兩大幅，此物世間誰敢價。", "倏然一別十五載，常向人前盛誇詫。", "因君奉使臨敝邑，見先問此餘不暇。", "君能爲我再講說，座上不容人俗話。", "如君所蓄更誰有，有亦未能無笑駡。", "况君累世盡清職，摹本敢來前弄詐。", "君今還省正擢用，異日須求作鄰舍。", "峨巾曳屨日相謁，更欲重煩開幾帊。", "待尋前輩用心處，款曲應須頻假借。", "每厨閱訖當便還，不敢奉欺言羽化。"]'),
('6fc53cce-465b-4896-9b5f-734bd9e6ac42','采芡','文同','宋','宋诗','song-poetry','','[]','芡盤團團開碧輪，城東壕中如疊鱗。',128,'全唐诗/poet.song.25000.json','["芡盤團團開碧輪，城東壕中如疊鱗。", "漢南父老舊不識，日日岸上多少人。", "駢頭鬅𩃭露秋熟，綠刺紅鍼割寒玉。", "提籠當筵破紫苞，老蚌一開珠一掬。", "吹臺北下凝祥池，圃田東邊僕射陂。", "如今兩處盡堙沒，異日此地名應馳。", "物貴新成味尤美，可惜飄零還入水。", "料得明年轉更多，一匝清波流萬子。"]'),
('dbf14bfb-0372-4dfa-9a58-b8e20e5c7de1','峰鐵峽','文同','宋','宋诗','song-poetry','','[]','東風吹空力何短，三月隴山全未暖。',67,'全唐诗/poet.song.25000.json','["東風吹空力何短，三月隴山全未暖。", "文法姦酋引騎兵，飛隨銀鶻弓刀滿。", "霜矛雪甲寒如水，候卒何由知首尾。", "君不見峰鐵峽頭雲色死，一過蕭然五十里。"]'),
('344e9b97-3116-4fd8-bf89-2ecdb7549f59','周思道如詔亭','文同','宋','宋诗','song-poetry','','[]','繁上先生教子時，義方題榜貼亭楣。',64,'全唐诗/poet.song.25000.json','["繁上先生教子時，義方題榜貼亭楣。", "當年此地開師席，今日其言入制詞。", "鄉里共傳爲盛事，鬼神相助使前知。", "後人若續成都記，第一詳書不可遺。"]'),
('13cc8b9b-478b-4c00-afbf-83388cdb95ef','陵井喻氏歲寒山居','文同','宋','宋诗','song-poetry','','[]','蕨平處士居山日，手種青松一萬根。',64,'全唐诗/poet.song.25000.json','["蕨平處士居山日，手種青松一萬根。", "歲月漸深枝盡偃，雪霜雖厚葉仍繁。", "本營勝概逃軒冕，更結清風遺子孫。", "寄語後人須愛護，莫教空有令名存。"]'),
('a5562b79-bda4-413a-8876-ae7c8e1f3747','提刑司勳示及瞑禽圖作詩詠之','文同','宋','宋诗','song-poetry','','[]','朱華盛發穿疏竹，寒枿齊枯遍野磯。',64,'全唐诗/poet.song.25000.json','["朱華盛發穿疏竹，寒枿齊枯遍野磯。", "大雪蔽天方亂下，衆禽爭地各相依。", "非公好事誰能得，此畫如今自已稀。", "試待晴明挂軒壁，定開群眼一時飛。"]'),
('a972ce94-4c1b-494c-a220-13a3a89be766','北齋雨後','文同','宋','宋诗','song-poetry','','[]','小庭幽圃絕清佳，愛此常教放吏衙。',64,'全唐诗/poet.song.25000.json','["小庭幽圃絕清佳，愛此常教放吏衙。", "雨後雙禽來占竹，秋深一蝶下尋花。", "喚人掃壁開吳畫，留客臨軒試越茶。", "野興漸多公事少，宛如當日在山家。"]'),
('67bcc1f8-a718-4430-a34e-5a6d2a0dea6d','北城樓上','文同','宋','宋诗','song-poetry','','[]','滿目望不極，城樓當最高。',48,'全唐诗/poet.song.25000.json','["滿目望不極，城樓當最高。", "地形連楚闊，山勢入秦豪。", "平外斜通駱，深中遠認褒。", "圖經何壯觀，故事有蕭曹。"]'),
('a0fb188c-5361-45a7-befc-8e7ddd05fd83','晴登北城','文同','宋','宋诗','song-poetry','','[]','積雨已逾月，久妨於此行。',48,'全唐诗/poet.song.25000.json','["積雨已逾月，久妨於此行。", "雲山勞夢想，風日幸晴明。", "常愛往來處，盡皆苔蘚生。", "一壕新草木，强半不知名。"]'),
('31e41a27-1900-4305-91d6-d4f4016fc775','寒食書事感懷','文同','宋','宋诗','song-poetry','','[]','寥寥官舍靜於僧，雖有園亭亦倦登。',64,'全唐诗/poet.song.25000.json','["寥寥官舍靜於僧，雖有園亭亦倦登。", "桃杏花陰流似水，圖書滋味冷如冰。", "坐觀棨戟慚無狀，歸掃松楸恨未能。", "得報君恩便休去，虞卿前日本擔簦。"]'),
('7332b165-0344-4ce8-a012-0fc7889905b4','送李堅甫中舍奉使還闕','文同','宋','宋诗','song-poetry','','[]','曾歌出塞愁，又遣使西州。',48,'全唐诗/poet.song.25000.json','["曾歌出塞愁，又遣使西州。", "去國星辰動，還家歲月流。", "褒斜新路晚，鄠杜故園秋。", "歸對延和殿，從容問講求。"]'),
('99b59fbc-7016-46f3-a85b-2377ed9cfaaa','漢中城樓  其一','文同','宋','宋诗','song-poetry','','[]','解带緩幽憂，登城復上樓。',48,'全唐诗/poet.song.25000.json','["解带緩幽憂，登城復上樓。", "斷烟橫沔水，孤鶩入洋州。", "浩蕩成遥望，凄凉起暮愁。", "山中自有桂，何事此淹留。"]'),
('41252cdf-fc4c-4f48-af0b-e11fd03c8ad0','漢中城樓  其二','文同','宋','宋诗','song-poetry','','[]','蘚徑踏層斑，高林古木間。',48,'全唐诗/poet.song.25000.json','["蘚徑踏層斑，高林古木間。", "雁隨平楚遠，雲共太虛閑。", "晚靄昏斜谷，晴陽露斗山。", "將身就清曠，名路爾何顔。"]'),
('861f6439-24bd-45e1-9025-03b80f7b8619','凝雲榭晚興','文同','宋','宋诗','song-poetry','','[]','晚策倚危榭，群峰天際橫。',48,'全唐诗/poet.song.25000.json','["晚策倚危榭，群峰天際橫。", "雲陰下斜谷，雨勢落褒城。", "遠渡孤烟起，前村夕照明。", "遥懷寄新月，又見一棱生。"]'),
('f703e469-a9b1-41ce-819b-8abc00cba58c','山堂偶書','文同','宋','宋诗','song-poetry','','[]','幾日無公事，山堂興頗清。',48,'全唐诗/poet.song.25000.json','["幾日無公事，山堂興頗清。", "和詩防積壓，丸藥趁晴明。", "斸石新棱出，澆蔬晚甲生。", "此皆忙外得，低首笑塵纓。"]'),
('ac6718b1-b997-4314-b87b-2332ad88dec3','清閣','文同','宋','宋诗','song-poetry','','[]','治庭區紜紛，齋閣簡應接。',48,'全唐诗/poet.song.25000.json','["治庭區紜紛，齋閣簡應接。", "身閑憙枕簟，慮靜厭圖牒。", "孤芳媚深叢，幽哢出密葉。", "物理茲領會，真境知可躡。"]'),
('591dc00b-be52-4633-a7c7-28828f9f11da','靜庵','文同','宋','宋诗','song-poetry','','[]','問此初誰築，經營羨爾能。',48,'全唐诗/poet.song.25000.json','["問此初誰築，經營羨爾能。", "依深還巨木，就蔭覆高藤。", "坐與境同寂，來無人可憎。", "一床黄卧具，茂灌本如僧。"]'),
('16633a85-6993-498c-91a1-6d0377ad6124','忘憂堂','文同','宋','宋诗','song-poetry','','[]','磴道循城近，垣牆占地幽。',48,'全唐诗/poet.song.25000.json','["磴道循城近，垣牆占地幽。", "軒窗誰指畫，硯席我優游。", "不許簿書到，恐爲圖史羞。", "此心元自適，何處欲忘憂。"]'),
('71cc576f-5a5e-4c79-b7d6-fada7baa36f9','夏日官舍','文同','宋','宋诗','song-poetry','','[]','省事公多暇，虛心景更長。',48,'全唐诗/poet.song.25000.json','["省事公多暇，虛心景更長。", "捨書無可樂，就枕不能忘。", "短葛沾肌薄，寒泉沃肺凉。", "何當逢靖節，相與話羲皇。"]'),
('b8a25d13-566a-4cbf-98ac-a42187a04012','寄成都趙資政','文同','宋','宋诗','song-poetry','','[]','纔承寵詔聯公鼎，便謁除書別帝閽。',64,'全唐诗/poet.song.25000.json','["纔承寵詔聯公鼎，便謁除書別帝閽。", "萬口一詞歌盛德，四年三度福遐藩。", "已爲魁壘無雙士，更入摩訶不二門。", "應笑臨邛病痟客，最先參見在江原。"]'),
('6c1e72e0-8453-4f9e-9ea5-ad6ca79b6057','晴步西園','文同','宋','宋诗','song-poetry','','[]','急雨正新霽，林端明晚霞。',48,'全唐诗/poet.song.25000.json','["急雨正新霽，林端明晚霞。", "松亭臨曠絕，竹徑入欹斜。", "花落留深草，泉生上淺沙。", "稚圭貧亦樂，一部奏池蛙。"]'),
('efa7f198-bbac-4aa5-b3d7-fbc32937e938','金影軒','文同','宋','宋诗','song-poetry','','[]','開軒俯清溪，正在修篁內。',48,'全唐诗/poet.song.25000.json','["開軒俯清溪，正在修篁內。", "霜筠抱冰節，爽氣常四會。", "主人厭俗客，日與此君對。", "月上寒影來，滿襟摇瑣碎。"]'),
('a3a5778c-901c-4d17-ae5b-f7e756f44d73','忽憶故園修竹因作此詩','文同','宋','宋诗','song-poetry','','[]','故園修竹遶東溪，占水侵沙一萬枝。',32,'全唐诗/poet.song.25000.json','["故園修竹遶東溪，占水侵沙一萬枝。", "我走宦途休未得，此君應是怪歸遲。"]'),
('4b47de0a-7bf7-4bde-9e81-37881bb5486b','寄景孺提刑時按武興','文同','宋','宋诗','song-poetry','','[]','夾欄虛棧武興西，使騎翩翩晚夕馳。',32,'全唐诗/poet.song.25000.json','["夾欄虛棧武興西，使騎翩翩晚夕馳。", "想過飛仙須下馬，此中佳景入吟詩。"]'),
('95ed2429-8ec8-467b-bb48-31f3b7188608','子駿遊沙溪洞','文同','宋','宋诗','song-poetry','','[]','聞有沙溪洞，公將柅使輪。',48,'全唐诗/poet.song.25000.json','["聞有沙溪洞，公將柅使輪。", "還如探禹穴，應見避秦人。", "石繖形容古，琳房氣象春。", "若逢丹輦客，問取虎文巾。"]'),
('bc5a92d4-eee3-4de0-9776-da12923343ed','送郭榮叔秀才應武舉','文同','宋','宋诗','song-poetry','','[]','愛君才辯吐如傾，圓直橫斜善講兵。',32,'全唐诗/poet.song.25000.json','["愛君才辯吐如傾，圓直橫斜善講兵。", "休弄向時閑筆硯，破蠻征虜是功名。"]'),
('d3898cb8-2c93-4572-a590-8e7934f9586c','乞畫雁寄涇州毌使君','文同','宋','宋诗','song-poetry','','[]','寒影亂翻秦嶺月，晚行高處隴山雲。',32,'全唐诗/poet.song.25000.json','["寒影亂翻秦嶺月，晚行高處隴山雲。", "回中有客能傳雁，異日從公乞一群。"]'),
('b497e248-61b0-463e-98e7-4cde0fb1d608','興元府園亭雜咏 甚美堂','文同','宋','宋诗','song-poetry','','[]','潭潭棟宇盛，窅窅軒窗闢。',36,'全唐诗/poet.song.25000.json','["潭潭棟宇盛，窅窅軒窗闢。", "高深與地稱，可大張宴席。", "府事如少休，茲焉會佳客。"]'),
('263fdaac-2baa-4414-a3c7-293b14391574','興元府園亭雜咏 武陵軒','文同','宋','宋诗','song-poetry','','[]','水從前岩來，轉入後溪去。',36,'全唐诗/poet.song.25000.json','["水從前岩來，轉入後溪去。", "中間載酒下，各到客前住。", "醉後皆怳然，再來無覓處。"]'),
('b7abda18-72dd-44cc-be2f-0616ba9355fe','興元府園亭雜咏 綠景亭','文同','宋','宋诗','song-poetry','','[]','竹間有幽亭，所宜惟暑飲。',36,'全唐诗/poet.song.25000.json','["竹間有幽亭，所宜惟暑飲。", "層陰隔炎日，四坐障綠錦。", "過午不可留，單絺覺微凜。"]'),
('f223174e-450f-4730-b196-438f17d493ea','興元府園亭雜咏 激湍亭','文同','宋','宋诗','song-poetry','','[]','高輪轉深淵，下瀉石蟾口。',36,'全唐诗/poet.song.25000.json','["高輪轉深淵，下瀉石蟾口。", "臨之設軒檻，清絕更無有。", "愛此山中來，應須坐良久。"]'),
('e6acc77b-e9b4-4e57-ab18-027a55b2c540','興元府園亭雜咏 凝雲榭','文同','宋','宋诗','song-poetry','','[]','朝雲南山吐，暮雲北山翕。',36,'全唐诗/poet.song.25000.json','["朝雲南山吐，暮雲北山翕。", "來往高榭中，留者頗堆積。", "坐客如久之，去須襟袖濕。"]'),
('275234f8-9f14-48f9-b6ba-94c51e131d5c','興元府園亭雜咏 照筠壇','文同','宋','宋诗','song-poetry','','[]','積土削爲壇，險然在深竹。',36,'全唐诗/poet.song.25000.json','["積土削爲壇，險然在深竹。", "中惟一詩石，獨坐擁寒玉。", "勿謂人少知，此境不容俗。"]'),
('c862b3f4-ad81-4d31-8a56-e6e757547407','興元府園亭雜咏 桂石堂','文同','宋','宋诗','song-poetry','','[]','嘗聞陽朔山，萬尺從地起。',36,'全唐诗/poet.song.25000.json','["嘗聞陽朔山，萬尺從地起。", "孤峰立庭下，此石無乃似。", "愛爾常獨來，一日須三四。"]'),
('9608cda7-5a42-4742-830f-925719175eac','興元府園亭雜咏 四照亭','文同','宋','宋诗','song-poetry','','[]','巒嶺附梁山，汀洲隨漢水。',36,'全唐诗/poet.song.25000.json','["巒嶺附梁山，汀洲隨漢水。", "秋容上屏障，左右二百里。", "此景誰能論，殘霞獨憑几。"]'),
('e353a436-3a3e-4798-b7da-539255165191','興元府園亭雜咏 垂蘿徑','文同','宋','宋诗','song-poetry','','[]','長蘿託高株，晻曖蔽烟霧。',36,'全唐诗/poet.song.25000.json','["長蘿託高株，晻曖蔽烟霧。", "垂蔓已百尺，更引欲何處。", "願少放餘條，恐傷君所附。"]'),
('077ecbf2-5bc6-46e4-b455-e773b6dd9378','興元府園亭雜咏 盤雲塢','文同','宋','宋诗','song-poetry','','[]','幾曲上層城，盤盤次文石。',36,'全唐诗/poet.song.25000.json','["幾曲上層城，盤盤次文石。", "愛之有佳趣，不倦紆晚策。", "禽蟲應見疑，日遇此狂客。"]'),
('7ec63d7d-1a25-4f69-a1e2-392a8c0cdea7','興元府園亭雜咏 北軒','文同','宋','宋诗','song-poetry','','[]','天上之貴神，所居皆在北。',36,'全唐诗/poet.song.25000.json','["天上之貴神，所居皆在北。", "有軒正相望，慢恐取陰劾。", "余常過則趨，不敢茲少息。"]'),
('7a7619a6-0ec1-4306-91cb-7d8c13ec23d7','興元府園亭雜咏 棋軒','文同','宋','宋诗','song-poetry','','[]','北城云最高，上復有喬木。',36,'全唐诗/poet.song.25000.json','["北城云最高，上復有喬木。", "垂蘿密如帳，中乃營小屋。", "時引方外人，百憂銷一局。"]'),
('a9d2bce5-edae-4df9-96d1-4cf0f8c95b92','興元府園亭雜咏 山堂','文同','宋','宋诗','song-poetry','','[]','何以山名堂，層石作崖巘。',36,'全唐诗/poet.song.25000.json','["何以山名堂，層石作崖巘。", "余本岩穴士，每往不欲返。", "公吏呈俗書，還來愧冠冕。"]'),
('340b4a00-9e61-479d-a77c-9b73d9645d85','興元府園亭雜咏 靜庵','文同','宋','宋诗','song-poetry','','[]','知動以爲幻，既知即非靜。',36,'全唐诗/poet.song.25000.json','["知動以爲幻，既知即非靜。", "名庵以靜者，無乃自起爭。", "爲語庵中人，勿以靜爲病。"]'),
('30d2b43a-5d82-4fed-8a9e-aef3774a02c7','將赴洋州書東谷舊隠','文同','宋','宋诗','song-poetry','','[]','晚客無一來，獨步入東谷。',288,'全唐诗/poet.song.25000.json','["晚客無一來，獨步入東谷。", "園林已成就，此景頗不俗。", "落落岩畔松，修修澗邊竹。", "爽氣逼襟袖，清如新出浴。", "寒泉激亂石，磊磊漱瓊玉。", "荒溪漬餘潤，滿地苔蘚綠。", "珍禽靜相倚，毛羽華且縟。", "高下相和鳴，不去若馴伏。", "幽花雜紅紫，點滴亂盈目。", "坐久微風來，時聞散餘馥。", "往年讀書處，宛爾舊茅屋。", "雖然小破壞，修整可數木。", "開門拂軒窗，無限起蝙蝠。", "縱橫列蟲網，不免自掃撲。", "壁間細書字，多是親寫錄。", "當時苦謀身，如此用意毒。", "于今三十年，才抵羊脾熟。", "一從入仕路，行步每踖踧。", "所畏惟簡書，其甘者藜菽。", "中間何大幸，致身在天祿。", "無狀陪俊游，俯首常自恧。", "連章乞外補，得郡悉鄉曲。", "雖名二千石，敢自辭碌碌。", "朝廷設新法，布作天下福。"]'),
('39bd919e-3860-4cab-b8d9-0e080f90ae4e','崔覲詩','文同','宋','宋诗','song-poetry','','[]','崔覲者高士，梁州城固人。',264,'全唐诗/poet.song.25000.json','["崔覲者高士，梁州城固人。", "讀書不求官，但與耕稼親。", "夫婦既已老，左右無子孫。", "一日召奴婢，盡以田宅均。", "俾之各爲業，不用來相聞。", "遂去隠南山，雜迹麋鹿群。", "約曰或過汝，所給爲我陳。", "有時携其妻，來至諸人門。", "乃與具酒食，嘯詠相歡欣。", "山南鄭餘慶，辟之爲參軍。", "見趣使就職，漫不知吏文。", "已復許謝事，但謂長者云。", "補闕王直方，本覲之比鄰。", "文宗時上書，召見蒙咨詢。", "薦覲有高行，用可追至淳。", "詔授起居郎，褒斜走蒲輪。", "辭疾不肯至，高風概秋旻。", "我昨過其縣，裴回想芳塵。", "訪問諸故老，寂無祠與墳。", "斯人久不競，薄夫何由敦。", "此縣漢唐時，諸公揚清芬。", "刻詩子堅廟，來者期不泯。"]'),
('fa7f0166-c01e-4800-a4d2-6936f68b74c3','寄題閬州開元寺澤師竹軒','文同','宋','宋诗','song-poetry','','[]','澤師種竹三十年，竹成滿院生綠烟。',192,'全唐诗/poet.song.25000.json','["澤師種竹三十年，竹成滿院生綠烟。", "蒼龍子孫太繁盛，分領眷屬來渭川。", "藏風蓄雨蔭殿壁，不敢輒近寒森然。", "香飛常入佛座上，葉落不到經窗前。", "芟除掃掠凈如洗，欄外不許行狂鞭。", "澤師瘦健如老鶴，壞衲幾尺披左肩。", "手持數珠讀梵筴，狀貌兀若塑與鎸。", "朝旋暮繞在其下，不肯出院求齋錢。", "古人亦有愛竹者，豈得似師心意專。", "我亦平生苦如此，兼解略把筆墨傳。", "逢師正謂同所好，但恨尚有區中緣。", "何時相對月明下，坐徹清影談幽禪。"]'),
('220468e8-0dda-40ff-92cf-ceaa8b031b2f','寄題密州蘇學士快哉亭太史云此城之西北送客處也','文同','宋','宋诗','song-poetry','','[]','出城送客客未來，主人到此先徘徊。',96,'全唐诗/poet.song.25000.json','["出城送客客未來，主人到此先徘徊。", "地臨濰水極清曠，每爲送客雙眼開。", "客來既坐歌管作，紅袖勸酒無停杯。", "主人自醒客已醉，門外落日驪駒催。", "揖客上馬退岸幘，未忍便擁千騎回。", "滿襟高興屬軒檻，野闊風長真快哉。"]'),
('246c5a31-933b-4e92-be24-bac6d7ee9b4b','獨遊','文同','宋','宋诗','song-poetry','','[]','孤亭入陰森，竹徑北松塢。',96,'全唐诗/poet.song.25000.json','["孤亭入陰森，竹徑北松塢。", "高林動清吹，猶滴前夕雨。", "解衣此危坐，左右一不許。", "性本不奈雜，况復茲寡侶。", "孤懷託寥曠，世慮絕參伍。", "幽花爲誰笑，獨鳥只自語。", "身閑得天全，一息了萬古。", "忽往而忽來，其誰知踽踽。"]'),
('6f5df619-be47-4b82-aef2-72823d0f6eaf','夏日湖亭試筆','文同','宋','宋诗','song-poetry','','[]','亭臺清凉水竹凈，愛此來避蚊與蠅。',64,'全唐诗/poet.song.25000.json','["亭臺清凉水竹凈，愛此來避蚊與蠅。", "蓮花窺人類楚女，野鳥彈舌如胡僧。", "旋來開卷坐松蔭，却把釣竿沿石棱。", "二年何幸爾足樂，慚報上恩無所能。"]'),
('f84993f8-8523-47e9-95b9-1128e6f6af99','楊山人草堂','文同','宋','宋诗','song-poetry','','[]','九隴山人文父後，心閑身健兩誰如。',64,'全唐诗/poet.song.25000.json','["九隴山人文父後，心閑身健兩誰如。", "玉函經外傳奇訣，畫戟門前創隠居。", "入鼎靈丹黄似橘，隔牆凡境臭如帤。", "何時再到高柟下，倚遍清陰聽道書。"]'),
('8346918b-d8b4-435f-802c-72d0ba8e2e6d','詠鳬','文同','宋','宋诗','song-poetry','','[]','雙雙紋羽弄清漪，全得天真似爾稀。',64,'全唐诗/poet.song.25000.json','["雙雙紋羽弄清漪，全得天真似爾稀。", "萬頃滄波供口腹，一梁寒日曬毛衣。", "雨歸別島嘔唲語，風度前灘翕呷飛。", "好向中流最深處，等閑休要上漁磯。"]'),
('525da6f2-bb1f-4e12-985b-6d531dd1559b','弄珠亭春望','文同','宋','宋诗','song-poetry','','[]','岸柳舞毿毿，春醲物象酣。',48,'全唐诗/poet.song.25000.json','["岸柳舞毿毿，春醲物象酣。", "烟雲分極浦，舟楫聚回潭。", "上水魚千萬，眠沙雁兩三。", "遥懷無可奈，長是寄城南。"]'),
('72e64b1e-703f-4054-8d15-a68df7f02e56','新晴望北山','文同','宋','宋诗','song-poetry','','[]','西風吹北山，晚日曬新雨。',48,'全唐诗/poet.song.25000.json','["西風吹北山，晚日曬新雨。", "嵐光發岩岫，草木紛可數。", "翠壁倚萬丈，白雲橫一縷。", "待訪餐霞人，斯游欲誰與。"]'),
('a18db17e-5e10-4c12-b8a5-92fc6d2c52a7','城南江館','文同','宋','宋诗','song-poetry','','[]','漢江之北涯，軒宇頗高爽。',48,'全唐诗/poet.song.25000.json','["漢江之北涯，軒宇頗高爽。", "西南正空闊，時此託遐想。", "誰家有竹石，更可悅新賞。", "待學袁愍孫，乘興欲直往。"]'),
('efaee8e0-b4b5-4170-8701-8c6659210e5d','屬疾梧軒','文同','宋','宋诗','song-poetry','','[]','高梧覆新葉，滿院發華滋。',48,'全唐诗/poet.song.25000.json','["高梧覆新葉，滿院發華滋。", "白日一何永，清陰閑自移。", "暖蟲垂到地，晴鳥語多時。", "病肘倚枯几，泊然忘所思。"]'),
('0bce7167-9ef1-4247-97b0-447684a82314','北園避熱','文同','宋','宋诗','song-poetry','','[]','繚繞度回塘，紆餘轉短牆。',48,'全唐诗/poet.song.25000.json','["繚繞度回塘，紆餘轉短牆。", "引筇聊散誕，入竹得清凉。", "正午禽蟲凈，初晴果木香。", "移床就高處，更欲解衣裳。"]'),
('073ae57d-e54f-49c4-8689-cd0da0f44e92','施公潭','文同','宋','宋诗','song-poetry','','[]','盤巖復轉溪，磴道入雲微。',72,'全唐诗/poet.song.25000.json','["盤巖復轉溪，磴道入雲微。", "斷巘雙屏立，垂泉一劍飛。", "浮空交彩翠，濺遠亂珠璣。", "啼穴饑鼯出，翹灘宿鷺歸。", "寒光清徹骨，晚氣潤沾衣。", "東谷牛羊下，摇鞭去夕暉。"]'),
('3e53ab81-ea71-4374-b4fb-f88b4e6a98ed','罷郡','文同','宋','宋诗','song-poetry','','[]','自問爾何事，端然信方策。',48,'全唐诗/poet.song.25000.json','["自問爾何事，端然信方策。", "本是鉏犁人，强爲簪組客。", "何嘗補萬分，徒自勞七尺。", "還如裴昭明，罷郡歸無宅。"]'),
('c6ba1c48-f2bc-4482-83dd-bb732c7c99a6','送文鑄師游襄陽鹿門','文同','宋','宋诗','song-poetry','','[]','師今鹿門去，正此冒炎曦。',48,'全唐诗/poet.song.25000.json','["師今鹿門去，正此冒炎曦。", "野店乞晨饌，亂山吟古詩。", "問程行幾日，覽景立多時。", "我有懷賢意，憑看墮淚碑。"]'),
('f8184c0b-9980-4cf4-b621-76ab0c4da24a','夏日南園','文同','宋','宋诗','song-poetry','','[]','陰陰喬木下，翠影若雲浮。',48,'全唐诗/poet.song.25000.json','["陰陰喬木下，翠影若雲浮。", "滿地紫桑椹，數枝黄栗留。", "迎風湖上去，避日竹間遊。", "定作今宵雨，繞牆啼曉鳩。"]'),
('aa948f39-406f-43d2-9140-9ddc1b94e135','北樓晚晴望秦嶺','文同','宋','宋诗','song-poetry','','[]','秦嶺巉巉列萬峰，晚嵐渾欲滴晴空。',32,'全唐诗/poet.song.25000.json','["秦嶺巉巉列萬峰，晚嵐渾欲滴晴空。", "如何學得崔重易，吟嘯終南明月中。"]'),
('1e7f5db2-4aff-422d-bac8-7eca5a0aeedf','柳枝','文同','宋','宋诗','song-poetry','','[]','牆宇周回院落深，日光風色凈陰陰。',32,'全唐诗/poet.song.25000.json','["牆宇周回院落深，日光風色凈陰陰。", "柔條一似孫荆玉，帖地反腰銜寶簪。"]'),
('d2c274a7-4a19-41da-b7ea-74559a9afe5e','送王存之','文同','宋','宋诗','song-poetry','','[]','野水冰生薄似綿，短亭梅發大於錢。',32,'全唐诗/poet.song.25000.json','["野水冰生薄似綿，短亭梅發大於錢。", "想君歸到江陽日，欲話今時已去年。"]'),
('98392a3a-7116-4cf9-8212-55ed4b0d8fb0','放言','文同','宋','宋诗','song-poetry','','[]','裨海之外既爾知，自問何苦安喧卑。',32,'全唐诗/poet.song.25000.json','["裨海之外既爾知，自問何苦安喧卑。", "胡不往見蒙轂士，看卷龜殻食蛤蜊。"]'),
('48199b38-cbe4-438a-92de-04caf25efbde','寄褒城宰','文同','宋','宋诗','song-poetry','','[]','灧灧清波瀉石門，茂林高巘夾烟昏。',32,'全唐诗/poet.song.25000.json','["灧灧清波瀉石門，茂林高巘夾烟昏。", "何當畫舫載明月，共醉江心白玉盆。"]'),
('920e42c2-63f3-4fcc-b277-bf1cfb9aff41','篔簹 贈竹','文同','宋','宋诗','song-poetry','','[]','我昔初來見爾時，禿稍攣葉病褵褷。',32,'全唐诗/poet.song.25000.json','["我昔初來見爾時，禿稍攣葉病褵褷。", "遮根護笋今成立，好在清風十萬枝。"]'),
('4f6c3538-09c7-4107-8c2f-c89eb8031b7b','篔簹 竹答','文同','宋','宋诗','song-poetry','','[]','我實仙陂百世孫，二年生長感君恩。',32,'全唐诗/poet.song.25000.json','["我實仙陂百世孫，二年生長感君恩。", "近聞官滿將歸去，更望臨時莫洗園。"]'),
('3fb3a841-82fb-4590-88d1-b892a4dbee2d','守居園池雜題 湖橋','文同','宋','宋诗','song-poetry','','[]','飛橋架橫湖，偃若長虹卧。',24,'全唐诗/poet.song.25000.json','["飛橋架橫湖，偃若長虹卧。", "自問一日中，往來凡幾過。"]'),
('5b451d84-621d-4cf3-a4f7-9afa3330f75d','守居園池雜題 橫湖','文同','宋','宋诗','song-poetry','','[]','長湖直東西，漾漾承守寢。',24,'全唐诗/poet.song.25000.json','["長湖直東西，漾漾承守寢。", "一望見荷花，天機織雲錦。"]'),
('74f37348-d6e8-464c-a7c9-0fc55351e02f','守居園池雜題 書軒','文同','宋','宋诗','song-poetry','','[]','清泉繞庭除，綠篠映軒檻。',24,'全唐诗/poet.song.25000.json','["清泉繞庭除，綠篠映軒檻。", "坐此何可爲，惟宜弄鉛槧。"]'),
('a1ed476d-f8e7-48b5-85af-d5c64120b0ed','守居園池雜題 冰池','文同','宋','宋诗','song-poetry','','[]','日暮池已冰，翩翩下鳬鶩。',24,'全唐诗/poet.song.25000.json','["日暮池已冰，翩翩下鳬鶩。", "不怕池中寒，便於冰上宿。"]'),
('b368fa7c-3385-4544-a80b-6126280351f6','守居園池雜題 竹塢','文同','宋','宋诗','song-poetry','','[]','文石間蒼苔，相引入深塢。',24,'全唐诗/poet.song.25000.json','["文石間蒼苔，相引入深塢。", "莫撼青琅玕，無時露如雨。"]'),
('98104169-60cf-40ba-b5c2-d5044b488c52','守居園池雜題 菡萏軒','文同','宋','宋诗','song-poetry','','[]','朝陽媚秋漪，菡萏隔深竹。',24,'全唐诗/poet.song.25000.json','["朝陽媚秋漪，菡萏隔深竹。", "誰開翠錦障，無限點銀燭。"]'),
('e3ef6ea5-ca8f-4d37-acce-25f3f7932d7a','守居園池雜題 荼蘼洞','文同','宋','宋诗','song-poetry','','[]','柔條綴繁英，擁架若深洞。',24,'全唐诗/poet.song.25000.json','["柔條綴繁英，擁架若深洞。", "是處欲清香，憑風爲持送。"]'),
('8ff50b4c-5d57-4a39-922e-d4600e00fd99','守居園池雜題 篔簹谷','文同','宋','宋诗','song-poetry','','[]','千輿翠羽蓋，萬錡綠沈槍。',24,'全唐诗/poet.song.25000.json','["千輿翠羽蓋，萬錡綠沈槍。", "定有葛陂種，不知何處藏。"]'),
('f515cbc0-06ab-490f-a6d3-38a93963c477','守居園池雜題 金橙徑','文同','宋','宋诗','song-poetry','','[]','金橙實佳果，不爲土人重。',24,'全唐诗/poet.song.25000.json','["金橙實佳果，不爲土人重。", "上苑聞未多，誰能爲移種。"]'),
('39c7676a-fa9d-48f1-8733-f9a08aa0cbd4','守居園池雜題 荻浦','文同','宋','宋诗','song-poetry','','[]','枯荻饒霜風，暮寒聲索索。',24,'全唐诗/poet.song.25000.json','["枯荻饒霜風，暮寒聲索索。", "無限有微禽，捉之宿如客。"]'),
('a259ef75-8917-4994-96cf-d3a5233ef611','守居園池雜題 蓼嶼','文同','宋','宋诗','song-poetry','','[]','孤嶼紅蓼深，清波照寒影。',24,'全唐诗/poet.song.25000.json','["孤嶼紅蓼深，清波照寒影。", "時有雙鷺鷥，飛來作佳景。"]'),
('4cb33597-5451-43a1-9a79-05ddbc226cd3','守居園池雜題 望雲樓','文同','宋','宋诗','song-poetry','','[]','巴山樓之東，秦嶺樓之北。',24,'全唐诗/poet.song.25000.json','["巴山樓之東，秦嶺樓之北。", "樓上捲簾時，滿樓雲一色。"]'),
('7c7ce11f-235a-4ee4-8647-a084e68d5608','紹興親享明堂二十六首 徹豆用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','工祝告休，笙鏞云闋。',40,'全唐诗/poet.song.250000.json','["工祝告休，笙鏞云闋。", "酒茅既除，牲俎斯徹。", "幽明罔恫，中外咸悅。", "禮成伊何，天地同節。"]'),
('2d23a99d-4345-49cf-960e-ca44408a8af0','紹興親享明堂二十六首 送神用《誠安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕宗祀，煌煌禮文。',40,'全唐诗/poet.song.250000.json','["奕奕宗祀，煌煌禮文。", "高靈下墮，精意升聞。", "熙事既畢，忽乘青雲。", "敢拜明貺，永清世氛。"]'),
('c9159613-bb56-4da6-8279-bd687adb3dea','紹興親享明堂二十六首 望燎用《儀安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','載酌載獻，以純以精。',40,'全唐诗/poet.song.250000.json','["載酌載獻，以純以精。", "歌傳夜誦，物備秋成。", "報本斯極，聽卑則明。", "願儲景貺，福我羣生。"]'),
('c0a612c0-cbfd-419e-8a04-a22fa891f948','紹興親享明堂二十六首 望瘞用《儀安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮協豐融，誠交彷彿。',40,'全唐诗/poet.song.250000.json','["禮協豐融，誠交彷彿。", "辟公受膰，宗祀臨瘞。", "貽我來牟，以興嗣歲。", "山川出雲，天地同氣。"]'),
('9d80d128-e481-411f-bdcc-79e4f17e7793','紹興親享明堂二十六首 還大次用《憩安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','應天以實，已事而竣。',40,'全唐诗/poet.song.250000.json','["應天以實，已事而竣。", "氈案朝帝，竹宮拜神。", "靈光下燭，協氣斯陳。", "福祿時萬，基圖日新。"]'),
('71a4fd44-099e-478d-96dd-81f9f0e10333','紹興淳熙分命館職定撰十七首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕上直房心，時惟明堂。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕上直房心，時惟明堂。", "配天享親，宗祀有常。", "盛德在金，日吉辰良。", "享我克誠，來格來康。"]'),
('d17a6dce-a6e7-45a0-b8da-d61aa9352e76','紹興淳熙分命館職定撰十七首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕合宮盛禮，金商令時。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕合宮盛禮，金商令時。", "備成熙事，蒐揚上儀。", "駿奔在庭，精意肅祗。", "來享嘉薦，神靈燕娭。"]'),
('83316fbb-febd-462d-ad13-3abcd8036396','紹興淳熙分命館職定撰十七首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕休德孔昭，靈承上帝。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕休德孔昭，靈承上帝。", "孝極尊親，嚴配于位。", "嘉薦芬芳，禮無不備。", "神其格思，享茲誠至。"]'),
('b9393b48-e4d8-4664-b161-cd505186bdd6','紹興淳熙分命館職定撰十七首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕霜露既降，孝思奉先。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕霜露既降，孝思奉先。", "陟降上帝，禮隆九筵。", "有馨黍稷，有肥牲牷。", "神來燕娭，想像肅然。"]'),
('6bac894b-45a5-4395-951c-ecd48b04433a','紹興淳熙分命館職定撰十七首 盥洗用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮經之重，祭典爲宗。',40,'全唐诗/poet.song.250000.json','["禮經之重，祭典爲宗。", "上公攝事，進退彌恭。", "庶品豐潔，令儀肅雍。", "百祥萃止，惟吉之從。"]'),
('92d97fe9-b847-45d5-ac40-2bbbb69f798f','紹興淳熙分命館職定撰十七首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇祖配帝，歲祀明堂。',40,'全唐诗/poet.song.250000.json','["皇祖配帝，歲祀明堂。", "冕服陟降，玉佩瑲瑲。", "疾徐有節，進止克莊。", "維時右享，日靖四方。"]'),
('c0344cc1-9602-4760-8b86-dd429937e001','紹興淳熙分命館職定撰十七首 上帝位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大享季秋，百執揚厲。',40,'全唐诗/poet.song.250000.json','["大享季秋，百執揚厲。", "明明太宗，赫赫上帝。", "祗薦忱誠，式嚴圭幣。", "祚我明德，錫茲來裔。"]'),
('41f5f20b-7784-40e8-9123-f40b581c2418','紹興淳熙分命館職定撰十七首 太宗位奠幣用《宗安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆皇祖，丕昭聖功。',40,'全唐诗/poet.song.250000.json','["穆穆皇祖，丕昭聖功。", "聲律身度，樂備禮隆。", "祗薦量幣，祀于合宮。", "玉帛萬國，驩心載同。"]'),
('a3ae2be0-61c5-4d14-8517-57a1f1b4100c','紹興淳熙分命館職定撰十七首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','備物昭陳，工祝告具。',40,'全唐诗/poet.song.250000.json','["備物昭陳，工祝告具。", "維羊維牛，孔碩孔庶。", "有嘉維馨，加食宜飫。", "斂時五福，永膺豐胙。"]'),
('da460e11-ea30-43af-ab01-43353d899627','紹興淳熙分命館職定撰十七首 上帝位酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','燁彼房心，明明有融。',40,'全唐诗/poet.song.250000.json','["燁彼房心，明明有融。", "維聖享帝，禮行合宮。", "祀事時止，粢盛潔豐。", "昭受申命，萬福攸同。"]'),
('2fa8ec49-5a01-45c4-b804-741e8001239d','紹興淳熙分命館職定撰十七首 太宗位酌獻用《德安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','受命溥將，勳高百王。',40,'全唐诗/poet.song.250000.json','["受命溥將，勳高百王。", "寰宇大定，聖治平康。", "有嚴陟配，宗祀明堂。", "神保是格，申錫無疆。"]'),
('e0cc553f-4eaa-4d8a-b98c-69bdf96a9fb7','紹興淳熙分命館職定撰十七首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','溫厚嚴凝，於皇上帝。',40,'全唐诗/poet.song.250000.json','["溫厚嚴凝，於皇上帝。", "文德武功，列聖並配。", "舞綴象成，肅雍進退。", "秉翟踆踆，總干蹈厲。"]'),
('0d4c78b5-7b7f-41d6-b7ad-1d634ea4b32c','紹興淳熙分命館職定撰十七首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','總章靈承，維國之常。',40,'全唐诗/poet.song.250000.json','["總章靈承，維國之常。", "禮樂宣鬯，降升齊莊。", "竭誠盡志，薦茲累觴。", "於昭在上，申錫無疆。"]'),
('538d039d-0c92-4efc-9aff-16eded0e74be','紹興淳熙分命館職定撰十七首 徹豆用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇上帝，肅然來臨。',40,'全唐诗/poet.song.250000.json','["於皇上帝，肅然來臨。", "恭薦芳俎，以達高明。", "烹飪既事，享于克誠。", "以介景福，惟德之馨。"]'),
('13eae9fa-5cc0-46f7-8fce-e540b0ee60c4','紹興淳熙分命館職定撰十七首 送神用《景安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝在合宮，鑒觀盛禮。',40,'全唐诗/poet.song.250000.json','["帝在合宮，鑒觀盛禮。", "黍稷惟馨，神心則喜。", "禮備樂成，亦既歸止。", "億萬斯年，以貺多祉。"]'),
('8e7a611b-7575-4259-9bd9-0b2e6e366345','紹興淳熙分命館職定撰十七首 高宗位奠幣用《宗安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫高廟，于堯有光。',40,'全唐诗/poet.song.250000.json','["赫赫高廟，于堯有光。", "覆被萬祀，冠冕百王。", "有量斯幣，蠲潔是將。", "在帝左右，維時降康。"]'),
('701d08ba-a8f5-40ec-98f8-325cfaee67ae','紹興淳熙分命館職定撰十七首 酌獻用《德安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','炎運中興，蒼生載寧。',40,'全唐诗/poet.song.250000.json','["炎運中興，蒼生載寧。", "九秩燕豫，三紀豐凝。", "精祀上帝，陟配威靈。", "錫羨胙祉，萬世承承。"]'),
('9dbc7d4c-eb6c-43c4-a917-1a4033e3ec26','景德祀皇地祇三首 降神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至哉厚德，陟配天長。',40,'全唐诗/poet.song.250000.json','["至哉厚德，陟配天長。", "沈潜剛克，廣大無疆。", "資生萬物，神化含章。", "同和八變，神靈效祥。"]'),
('93d3851e-6435-4fb4-9f9b-7eb5f5c6c026','景德祀皇地祇三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於昭祀典，致享坤儀。',40,'全唐诗/poet.song.250000.json','["於昭祀典，致享坤儀。", "備物咸秩，柔祇格思。", "功宣敏樹，日益鴻禧。", "持載品彙，率土攸宜。"]'),
('e0f0798f-d045-4575-a7e9-a197f372db83','景德祀皇地祇三首 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','妙用無方，倏來忽逝。',20,'全唐诗/poet.song.250000.json','["妙用無方，倏來忽逝。", "蠲潔寅恭，式終禋瘞。"]'),
('aaba819b-32d5-4e8d-9a9b-9351ddb74b9d','景祐夏至祀皇地祇二首 太祖奠幣用《恭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫矣淳耀，俶載帝基。',40,'全唐诗/poet.song.250000.json','["赫矣淳耀，俶載帝基。", "一戎以定，萬國來儀。", "寅恭潔祀，博厚皇祇。", "威靈攸在，福祿如茨。"]'),
('4cbb811b-3948-4500-b7cf-efd82658a7ee','景祐夏至祀皇地祇二首 酌獻用《英安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','丕命惟皇，萬物咸臯。',40,'全唐诗/poet.song.250000.json','["丕命惟皇，萬物咸臯。", "卜年邁周，崇功冠禹。", "有燁炎精，大昌聖祚。", "酌鬯祈年，永錫繁祜。"]'),
('ddf5b0fc-f8ea-4f6d-af80-63ee5a713f29','熙寧祀皇地祇十二首 迎神用《導安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昭靈積厚，混混坤輿。',40,'全唐诗/poet.song.250000.json','["昭靈積厚，混混坤輿。", "配天作極，陰慘陽舒。", "齊明薦享，百福其儲。", "庶幾來止，風馬雲車。"]'),
('6198fa5d-30b0-487f-a560-98564685e1ed','熙寧祀皇地祇十二首 升降用《靖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有來穆穆，臨此方丘。',40,'全唐诗/poet.song.250000.json','["有來穆穆，臨此方丘。", "其行風動，其止霆收。", "躬事匪懈，豐盛潔羞。", "百昌咸殖，允矣神休。"]'),
('036fac85-afd9-4445-a571-d54d9c445e26','熙寧祀皇地祇十二首 奠幣用《釐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','純誠昭融，芳美嘉薦。',40,'全唐诗/poet.song.250000.json','["純誠昭融，芳美嘉薦。", "肅將二精，以享以奠。", "休光四充，靈祇來燕。", "其祥伊何，永世錫羨。"]'),
('1b11da0f-84dd-40f0-89fb-75325e5bb792','熙寧祀皇地祇十二首 太祖用《肇安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇烈祖，維帝所興。',40,'全唐诗/poet.song.250000.json','["於皇烈祖，維帝所興。", "光輝宗祀，如日之升。", "告靈作配，孝享烝烝。", "錫茲祉福，百世其承。"]'),
('a37add97-f9b4-4eb8-a5b4-fb3c49965cc5','熙寧祀皇地祇十二首 司徒奉俎用《承安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我修祀事，於何致誠。',40,'全唐诗/poet.song.250000.json','["我修祀事，於何致誠。", "罔敢怠佚，視茲碩牲。", "納烹薦俎，侑以和聲。", "格哉休應，世濟皇明。"]'),
('780f0de9-0c73-4504-969b-d418ba7a0266','熙寧祀皇地祇十二首 酌獻用《和安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗嗟富媼，博厚含弘。',40,'全唐诗/poet.song.250000.json','["猗嗟富媼，博厚含弘。", "發榮敷秀，動植茲豐。", "爰酌茲酒，肸蠁交通。", "衆祥萃止，垂祜無窮。"]'),
('bfc4437f-0653-4d86-87fe-8bd372136319','熙寧祀皇地祇十二首 太祖用《佑安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','光大含弘，坤元之力。',40,'全唐诗/poet.song.250000.json','["光大含弘，坤元之力。", "海宇咸寧，烈祖之德。", "作配方壇，不僭不忒。", "子孫其承，毋替厥則。"]'),
('2ad59617-a7d6-4741-8262-c04c08e5293d','熙寧祀皇地祇十二首 飲福用《禔安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','載登壇阼，載酌尊彝。',40,'全唐诗/poet.song.250000.json','["載登壇阼，載酌尊彝。", "牲酒嘉旨，福祿純熙。", "其福維何，萬物咸宜。", "其祿維何，永承神禧。"]'),
('9ea26e71-7442-4e75-a404-d76cf186c822','熙寧祀皇地祇十二首 退文舞、迎武舞用《威安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雍雍肅肅，建我采旄。',40,'全唐诗/poet.song.250000.json','["雍雍肅肅，建我采旄。", "舞以玉戚，不吳不敖。", "其將其肆，脾臄嘉肴。", "何以侑樂，鍾鼓管簫。"]'),
('035bdad4-e093-4f7e-9489-0ccdb1c254a6','熙寧祀皇地祇十二首 亞、終獻用《儀安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','折俎在籩，胾羹在豆。',40,'全唐诗/poet.song.250000.json','["折俎在籩，胾羹在豆。", "何以酌之，酒醴是侑。", "何以錫之，貽爾眉壽。", "何以格之，永爾康阜。"]'),
('d2377cc6-0945-4a43-bb4f-2ccb08fd6595','熙寧祀皇地祇十二首 徹豆用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','曳我黼黻，履舄接武。',40,'全唐诗/poet.song.250000.json','["曳我黼黻，履舄接武。", "鏘我珩璜，降升圉圉。", "其將肆兮，既曰不侮。", "其終徹兮，恭欽惟主。"]'),
('5444f12f-47b5-41e6-9b79-ce555a6c930b','熙寧祀皇地祇十二首 送神用《阜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神兮來下，享此苾芬。',40,'全唐诗/poet.song.250000.json','["神兮來下，享此苾芬。", "酌獻雍雍，執事孔勤。", "神之還矣，忽乘飛雲。", "遺我祺祥，物象忻忻。"]'),
('d945fb26-83b8-457c-9e00-8c1dd3993032','常祀皇地祇五首 迎神用《寧安》。八變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤元之德，光大無疆。',40,'全唐诗/poet.song.250000.json','["坤元之德，光大無疆。", "一氣交感，百物阜昌。", "吉蠲致享，精明是將。", "介茲景福，鼎祚靈長。"]'),
('777f2673-5127-41a9-a3e3-059f08543ba8','常祀皇地祇五首 升降用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮經之重，祭典爲宗。',40,'全唐诗/poet.song.250000.json','["禮經之重，祭典爲宗。", "上公攝事，登降彌恭。", "庶品豐潔，令儀肅雍。", "百祥萃止，維吉之從。"]'),
('9d04bc24-43f0-4a5b-a53a-ed54bcc23c8f','常祀皇地祇五首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮崇禋祀，神鑒孔明。',40,'全唐诗/poet.song.250000.json','["禮崇禋祀，神鑒孔明。", "牲牷博腯，以炰以烹。", "馨香蠲潔，品物惟精。", "錫以純嘏，享茲至誠。"]'),
('685fb7cc-f3a0-47fe-84de-6b6045c9451c','常祀皇地祇五首 退文舞、迎武舞用《威安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','進旅退旅，載揚干揚。',40,'全唐诗/poet.song.250000.json','["進旅退旅，載揚干揚。", "不愆于儀，容服有章。", "式綏式侑，神保是聽。", "鼓之舞之，神永安寧。"]'),
('3b7a5791-bfc2-4a56-91c7-103161fe05d0','常祀皇地祇五首 送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','物備百嘉，樂周八變。',40,'全唐诗/poet.song.250000.json','["物備百嘉，樂周八變。", "克誠是享，明德斯薦。", "神鑒孔昭，蕃禧錫羨。", "回馭飄然，邈不可見。"]'),
('21983ba2-cf4c-4817-a6f9-b4f92bf88d36','紹興祀皇地祇十五首 迎神用《寧安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔函鍾爲宮〕至哉厚德，物生是資。',46,'全唐诗/poet.song.250000.json','["〔函鍾爲宮〕至哉厚德，物生是資。", "直方維則，翕闢攸宜。", "於昭祀典，致享坤儀。", "禮罔不答，神之格思。"]'),
('fb626f5c-88cc-4bc2-a712-72734ca3042d','紹興祀皇地祇十五首 迎神用《寧安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲角〕蕆事方丘，舊典時式。',46,'全唐诗/poet.song.250000.json','["〔太簇爲角〕蕆事方丘，舊典時式。", "至誠感神，馨非黍稷。", "肸蠁來臨，鑒茲明德。", "永錫坤珍，時萬時億。"]'),
('25377325-6df9-4cd2-a838-f4faa6941bf4','紹興祀皇地祇十五首 迎神用《寧安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲徵〕至哉坤元，乃順承天。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲徵〕至哉坤元，乃順承天。", "厚德載物，含洪八埏。", "日北多暑，祀儀吉蠲。", "式昭毋事，敢告恭虔。"]'),
('b75a0f41-110b-464e-93c7-2121f4553f30','紹興祀皇地祇十五首 迎神用《寧安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔南呂爲羽〕蕆事方丘，情文孔時。',46,'全唐诗/poet.song.250000.json','["〔南呂爲羽〕蕆事方丘，情文孔時。", "名山大澤，侑祭無遺。", "牲陳黝犢，樂備咸池。", "柔祇皆出，介我繁禧。"]'),
('569844f0-13a6-4667-8def-a4151695ab35','紹興祀皇地祇十五首 盥洗用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆盛禮，肅肅在宮。',40,'全唐诗/poet.song.250000.json','["於穆盛禮，肅肅在宮。", "蕆事有初，直于東榮。", "滌濯是謹，惟寅惟清。", "祗薦柔嘉，享茲克誠。"]'),
('28b8a687-401e-4c0e-a7ea-6de9b078a779','紹興祀皇地祇十五首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','景風應時，聿嚴毖祀。',40,'全唐诗/poet.song.250000.json','["景風應時，聿嚴毖祀。", "用事方丘，鏘鏘濟濟。", "登降有節，三獻成禮。", "神其格思，錫我繁祉。"]'),
('3f29cf47-c9a4-4947-9358-a48d2e94c4b6','紹興祀皇地祇十五首 正位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤元博厚，對越天明。',40,'全唐诗/poet.song.250000.json','["坤元博厚，對越天明。", "展事方澤，亶惟顧歆。", "嘉玉量幣，祗薦純精。", "錫我繁祉，燕及函生。"]'),
('ec682d08-f737-4eaf-921a-702fd722ce97','紹興祀皇地祇十五首 太祖位用《定安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','毖祀泰折，柔祇是承。',40,'全唐诗/poet.song.250000.json','["毖祀泰折，柔祇是承。", "於赫藝祖，道格三靈。", "式嚴配侑，厚德惟寧。", "爰昭薦幣，享于克誠。"]'),
('9c0c8206-58aa-4809-a3a3-67d91abffec6','紹興祀皇地祇十五首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','丕答靈貺，蕆事方丘。',40,'全唐诗/poet.song.250000.json','["丕答靈貺，蕆事方丘。", "豆登在列，鼎俎斯儔。", "牲牷告具，寅畏彌周。", "柔祇昭格，飈至雲流。"]'),
('ae7f2a59-51f8-4afa-a103-5b80c099eda5','紹興祀皇地祇十五首 正位酌獻用《光安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祗事坤元，飭躬敢憚。',40,'全唐诗/poet.song.250000.json','["祗事坤元，飭躬敢憚。", "爰潔粢盛，載嚴圭瓚。", "清明內融，嘉旨外粲。", "介我繁釐，時億時萬。"]'),
('f92680ec-a364-49c0-a180-30db36276d32','紹興祀皇地祇十五首 太祖位酌獻用《英安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇矣藝祖，九圍是式。',40,'全唐诗/poet.song.250000.json','["皇矣藝祖，九圍是式。", "至哉柔祇，萬彙允殖。", "保茲嘉邦，介我黍稷。", "酌鬯告虔，作配無極。"]'),
('dec2a545-ec1e-446a-9759-1ef0564b4791','紹興祀皇地祇十五首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆媼神，媲德彼天。',40,'全唐诗/poet.song.250000.json','["於穆媼神，媲德彼天。", "我修毖祀，以莫不虔。", "肆陳時夏，干羽相宣。", "靈其來游，降福綿綿。"]'),
('c00952a0-97c3-43d5-a74d-d3d98baa5df8','紹興祀皇地祇十五首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮有祈報，國惟典常。',40,'全唐诗/poet.song.250000.json','["禮有祈報，國惟典常。", "籩豆豐潔，降升齊莊。", "備物致志，式薦累觴。", "昭格來享，自天降康。"]'),
('8e3d96e3-486a-4f5f-9c83-134b878d04fe','紹興祀皇地祇十五首 徹豆用《娛安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','承天效法，其道貴誠。',40,'全唐诗/poet.song.250000.json','["承天效法，其道貴誠。", "牲羞黄犢，薦德之馨。", "芳俎告畢，禮備樂盈。", "既靜既安，庶物霑生。"]'),
('433ab9a8-a732-4146-bec5-b774a1f22130','紹興祀皇地祇十五首 送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至厚至深，其動也剛。',40,'全唐诗/poet.song.250000.json','["至厚至深，其動也剛。", "精誠默通，或出其藏。", "神之言歸，化斯有光。", "相我炎圖，萬世無疆。"]'),
('8ef751cf-f7c4-4fff-a701-7b35660440a5','宋初祀神州地祇三首 降神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','膴膴郊原，茫茫宇縣。',40,'全唐诗/poet.song.250000.json','["膴膴郊原，茫茫宇縣。", "畫野分疆，禹功疏奠。", "靈祇是臻，豆籩祗薦。", "幽贊皇圖，視之不見。"]'),
('7305a6f0-19e9-4378-a21e-878d414dad58','宋初祀神州地祇三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肸蠁儲靈，肅恭用幣。',40,'全唐诗/poet.song.250000.json','["肸蠁儲靈，肅恭用幣。", "鏘洋導和，洪休允契。", "嘉氣雲蒸，浹于華裔。", "式薦坤珍，聿符明世。"]'),
('f32d8554-2919-4128-aea8-3d6c02816f23','宋初祀神州地祇三首 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','獻奠云畢，純嘏祁祁。',20,'全唐诗/poet.song.250000.json','["獻奠云畢，純嘏祁祁。", "威靈藏用，邈矣何之。"]'),
('9a0d6cbb-b871-4017-b9d4-73619bac1494','景祐孟冬祭神州地祇二首 太宗位奠幣用《化安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','削平僞邦，嗣興鴻業。',40,'全唐诗/poet.song.250000.json','["削平僞邦，嗣興鴻業。", "禮樂交修，仁德該洽。", "柔祇薦享，量幣攸攝。", "侑坐延靈，神休允答。"]'),
('be850b2c-08b9-4d09-9685-32f32102beb0','景祐孟冬祭神州地祇二首 酌獻用《韶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有煒彌文，克隆宏構。',40,'全唐诗/poet.song.250000.json','["有煒彌文，克隆宏構。", "貽此燕謀，具膺多祐。", "嶰律吹莩，彝尊奠酒。", "佐乃沈潜，永祈豐楙。"]'),
('61e1f7e1-8900-417b-b08c-c0805e5b16a2','元符祭神州地祇二首 迎神用《寧安》。八變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','膴膴浚邦，皇天是宅。',40,'全唐诗/poet.song.250000.json','["膴膴浚邦，皇天是宅。", "必有幽贊，聰明正直。", "布列籩豆，考擊金石。", "中外謐寧，繄神之力。"]'),
('b24b0c56-23a0-41ae-99cc-980b08c1c523','元符祭神州地祇二首 送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','都邑浩穰，民物富盛。',40,'全唐诗/poet.song.250000.json','["都邑浩穰，民物富盛。", "主以靈祇，昭乃丕應。", "玉帛牲牷，鼓鍾筦磬。", "祗薦攸歆，歸于至靜。"]'),
('2f164638-6f18-45bf-a884-925cd0a281f5','紹興祀神州地祇十六首 迎神用《寧安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔函鍾爲宮〕芒芒下土，恢恢方儀。',46,'全唐诗/poet.song.250000.json','["〔函鍾爲宮〕芒芒下土，恢恢方儀。", "富媼統攝，潜運八維。", "爰稱元祀，告備吉時。", "揭茲虔恭，僾其格思。"]'),
('919f7361-e8dd-44ef-8c8e-2b0faffcc46c','紹興祀神州地祇十六首 迎神用《寧安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲角〕洪惟坤元，道著品物。',46,'全唐诗/poet.song.250000.json','["〔太簇爲角〕洪惟坤元，道著品物。", "上配紫旻，厚載其德。", "良月肇蕆，祭器布列。", "必先皇祇，以迓景福。"]'),
('da5fd6a2-4fb3-413b-af49-2624cbae0672','紹興祀神州地祇十六首 迎神用《寧安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲徵〕坱圠無垠，磅礴罔測。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲徵〕坱圠無垠，磅礴罔測。", "山盈川沖，自生自殖。", "其報惟何，率禮靡忒。", "億萬斯年，功被無極。"]'),
('6b321654-dac6-49b7-b0fc-21ecce7bf199','紹興祀神州地祇十六首 迎神用《寧安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔南呂爲羽〕翕闢以時，協氣陶蒸。',46,'全唐诗/poet.song.250000.json','["〔南呂爲羽〕翕闢以時，協氣陶蒸。", "播之金石，鏘厥和聲。", "冥冥眑眑，孔享純誠。", "是聽是娭，邦基永寧。"]'),
('ec9e762a-64ad-44df-bd34-31abed342a34','紹興祀神州地祇十六首 盥洗用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','晨煬致煙，浡然四施。',40,'全唐诗/poet.song.250000.json','["晨煬致煙，浡然四施。", "飄飄風馬，彷彿來斯。", "祀事維清，沃之盥之。", "載涓載肅，罔有愧辭。"]'),
('392c78d1-32ab-4030-b761-ef2153010fef','紹興祀神州地祇十六首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','崇崇其壇，屹矣層級。',40,'全唐诗/poet.song.250000.json','["崇崇其壇，屹矣層級。", "佩約步趨，降登中節。", "左瞻右睨，祥風藹集。", "斿旆羽紛，昭鑒翊翊。"]'),
('df9da428-4bd6-4acf-b013-2b5f6804c179','紹興祀神州地祇十六首 神州地祇位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','璇璣諧序，籍斂薦嘉。',40,'全唐诗/poet.song.250000.json','["璇璣諧序，籍斂薦嘉。", "昭答柔祇，迭奏雅歌。", "幣琮以侑，儀腆氣和。", "靈其溥臨，容與燕嘉。"]'),
('22c988ab-c82e-43a7-9c2b-d98244c9839c','紹興祀神州地祇十六首 太宗位奠幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆令聞，溥博有容。',40,'全唐诗/poet.song.250000.json','["穆穆令聞，溥博有容。", "澤被萬宇，靡不率從。", "恭陳量幣，明薦其衷。", "禮亦宜之，享德攸同。"]'),
('1d4a3e9f-c84c-4926-b8f3-e480f09fe889','紹興祀神州地祇十六首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅嘉承，唯德其物。',40,'全唐诗/poet.song.250000.json','["肅肅嘉承，唯德其物。", "工祝以告，繄民之力。", "神哉廣生，孔蕃且碩。", "奠于嘉壇，吐之則弗。"]'),
('623e9228-4f67-46de-8646-32079e5882e9','紹興祀神州地祇十六首 神州地祇位酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恭承明祀，嘉薦令芳。',40,'全唐诗/poet.song.250000.json','["恭承明祀，嘉薦令芳。", "亦有桂酒，誠慤是將。", "瑟瓚以酌，效懽厥觴。", "庶乎燕享，永懷不忘。"]'),
('49c82099-361d-4ff1-a583-b2a331afbb9b','紹興祀神州地祇十六首 太宗位酌獻用《化安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宗德含洪，方祇可儗。',40,'全唐诗/poet.song.250000.json','["宗德含洪，方祇可儗。", "闢土開疆，八埏同軌。", "是用作配，有永無紀。", "祼獻以享，茂格蕃祉。"]'),
('0196fde3-5cfb-4a30-b031-ab0c5934fe80','紹興祀神州地祇十六首 文舞退、武舞進用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕綴兆，咸池孔彰。',40,'全唐诗/poet.song.250000.json','["奕奕綴兆，咸池孔彰。", "丕闡文德，靡忘發揚。", "進退有節，乃容之常。", "樂備爾奏，燁燁榮光。"]'),
('141627da-9101-4e5b-93f6-965c0740ec10','紹興祀神州地祇十六首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','縮酌以祼，既旨且多。',40,'全唐诗/poet.song.250000.json','["縮酌以祼，既旨且多。", "三獻有序，情文愈加。", "黄祇臨享，錫以休嘉。", "廣茲靈祲，覃及邇遐。"]'),
('0169478c-331d-4590-88b4-ffcd801f70cc','紹興祀神州地祇十六首 徹豆用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','展牲告全，迺登于俎。',40,'全唐诗/poet.song.250000.json','["展牲告全，迺登于俎。", "竣事而徹，侑以樂語。", "奉釐宣室，祚我神主。", "斂敷庶民，並受其祜。"]'),
('13967be8-a70a-461f-8299-77fbe71d7bcc','紹興祀神州地祇十六首 送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雲馭洋洋，既歆既顧。',40,'全唐诗/poet.song.250000.json','["雲馭洋洋，既歆既顧。", "悠然聿歸，曷求厥路。", "欽想頌堂，跛立以慕。", "賚我肸蠁，莫不懌豫。"]'),
('adfe4bc1-1512-4cb3-803e-330132c46b14','紹興祀神州地祇十六首 望瘞用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神罔怨恫，燕其有喜。',40,'全唐诗/poet.song.250000.json','["神罔怨恫，燕其有喜。", "蕆事告成，爰修瘞禮。", "樂闋儀備，休氣四起。", "尚謹不愆，念終如始。"]'),
('06974bc6-8473-46a6-b642-4900ed911dae','景德朝日三首 降神用《高安》。六變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','陽德之母，羲御寅賓。',40,'全唐诗/poet.song.250000.json','["陽德之母，羲御寅賓。", "得天久照，首茲三辰。", "正辭備物，肅肅振振。", "淪精降監，克享明禋。"]'),
('b65c0393-a7bd-4192-9c4d-edac4b7499be','景德朝日三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','醴齊良潔，有牲斯純。',40,'全唐诗/poet.song.250000.json','["醴齊良潔，有牲斯純。", "大采玄冕，乃昭其文。", "王宮定位，粢盛苾芬。", "民事以敘，盛德升聞。"]'),
('25c1f721-0085-4ee7-bf5f-67f5fa7584ef','景德朝日三首 送神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','縣象著明，照臨下土。',20,'全唐诗/poet.song.250000.json','["縣象著明，照臨下土。", "降福穰穰，德施周普。"]'),
('4582a90e-a1c3-4b60-9b69-bcedc9f71e32','夕月三首 降神用《高安》。六變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','凝陰稟粹，照臨八埏。',40,'全唐诗/poet.song.250000.json','["凝陰稟粹，照臨八埏。", "麗天垂象，繼日代明。", "一氣資始，四時運行。", "靈祇昭格，備物薦誠。"]'),
('6b36b118-10f0-4b0a-abe7-e580850ee7f1','夕月三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夕耀乘秋，功存宇縣。',40,'全唐诗/poet.song.250000.json','["夕耀乘秋，功存宇縣。", "金奏在縣，以時致薦。", "祀事孔寅，明靈降眷。", "潔粢豐盛，倉箱流衍。"]'),
('42c6b0f6-2f1f-4bc4-864a-4f4436ab8e46','夕月三首 送神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夙陳籩豆，潔誠致祈。',20,'全唐诗/poet.song.250000.json','["夙陳籩豆，潔誠致祈。", "垂休保佑，景祚巍巍。"]'),
('f66469a2-2906-41dd-83db-b0a87ddfff10','大觀秋分夕月四首 降神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至陰之精，虧而復盈。',40,'全唐诗/poet.song.250000.json','["至陰之精，虧而復盈。", "輪高僊桂，階應祥蓂。", "玉兔影孤，金莖露溢。", "其駕星車，顧于茲夕。"]'),
('622788f6-dc5f-4294-bcbf-ce0e57347049','大觀秋分夕月四首 奠玉幣。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉鈎初彎，冰盤乍圓。',40,'全唐诗/poet.song.250000.json','["玉鈎初彎，冰盤乍圓。", "扇掩秋後，烏飛枝邊。", "精凝蟾蜍，輝光嬋娟。", "歆于明祀，弭芳節焉。"]'),
('b2a4d84d-d83b-4281-8c47-b46abefc07bc','大觀秋分夕月四首 酌獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','名稽漢儀，歌參唐宗。',40,'全唐诗/poet.song.250000.json','["名稽漢儀，歌參唐宗。", "往于卿少，乘秋氣中。", "周天而行，如姊之崇。", "可飛霞佩，下瑠璃宮。"]'),
('3b4fbf51-bbd5-4bc8-b315-06f0d09847d6','大觀秋分夕月四首 送神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四扉大開，五雲車立。',40,'全唐诗/poet.song.250000.json','["四扉大開，五雲車立。", "霓裾娣從，風翿童執。", "摇曳胥來，鏘洋爰集。", "歆我嚴禋，西面以揖。"]'),
('51a13aea-c2ce-4ef4-b8d9-8bac6084936d','紹興朝日十首 降神用《高安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕玄鳥既至，序屬春分。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕玄鳥既至，序屬春分。", "朝于太陽，厥典備存。", "載嚴大采，示民有尊。", "揚光下燭，煜爚東門。"]'),
('5473c4e6-26f6-4642-9610-3685fab04dce','紹興朝日十首 降神用《高安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕升暉麗天，陽德之母。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕升暉麗天，陽德之母。", "率無頗偏，兼燭下土。", "恭事崇壇，禮樂具舉。", "頓御六龍，裴回容與。"]'),
('7f76e894-9085-472e-9271-4363e9ce797d','紹興朝日十首 降神用《高安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕周祀及闇，漢制中營。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕周祀及闇，漢制中營。", "肸蠁是屆，禮神以兄。", "我潔斯璧，我肥斯牲。", "神兮燕享，鑒觀孔明。"]'),
('29f348c3-6483-441c-bb43-7de7bd1086ed','紹興朝日十首 降神用《高安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕屹爾王宮，泛臨翊翊。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕屹爾王宮，泛臨翊翊。", "惠此萬方，豈惟五色。", "以修陽政，以習地德。", "雲景杳冥，施祥無極。"]'),
('7322b361-a713-4a53-87ff-43b4d6f247c5','紹興朝日十首 初獻升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天宇四霽，嘉壇聿崇。',40,'全唐诗/poet.song.250000.json','["天宇四霽，嘉壇聿崇。", "肅祗嚴祀，登降有容。", "仰瞻曜靈，位居其中。", "既安既妥，沛哉豐融。"]'),
('739a6773-db63-4536-8d60-44f5951bca18','紹興朝日十首 奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','物之備矣，以交於神。',40,'全唐诗/poet.song.250000.json','["物之備矣，以交於神。", "時惟炎精，不忘顧歆。", "經緯之文，璆琳之質。", "燦然相輝，其儀秩秩。"]'),
('132e0b9a-cfc9-4429-91f3-2c3ac645d7e0','紹興朝日十首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','扶桑朝暾，和氣肸飭。',40,'全唐诗/poet.song.250000.json','["扶桑朝暾，和氣肸飭。", "奉此牲牢，爲俎孔碩。", "芬馨進聞，介我黍稷。", "所將以誠，茲用享德。"]'),
('fb6eb723-a0a4-471c-9b67-98a32436a0e6','紹興朝日十首 酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','匏爵斯陳，百味旨酒。',40,'全唐诗/poet.song.250000.json','["匏爵斯陳，百味旨酒。", "勺以獻之，再拜稽首。", "鍾鼓在列，靈方安留。", "眷然加薦，惟時之休。"]'),
('f43d0a36-4b95-4fcd-b1ae-3a5bbc43b887','紹興朝日十首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮罄沃盥，誠意肅將。',40,'全唐诗/poet.song.250000.json','["禮罄沃盥，誠意肅將。", "包茅是縮，冀畢重觴。", "煥矣情文，既具醉止。", "熙事備成，靈其有喜。"]'),
('14b44e19-f532-4bfb-995c-2aea7351d2a2','紹興朝日十首 送神用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羲和駕兮，其容杲杲。',40,'全唐诗/poet.song.250000.json','["羲和駕兮，其容杲杲。", "將安之兮，言歸黄道。", "光赫萬物，無古無今。", "人君之表，咸仰照臨。"]'),
('3c0c78aa-3215-43ff-bceb-9e1f3dad6ee7','夕月十首 降神用《高安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕金行告遒，玉律分秋。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕金行告遒，玉律分秋。", "禮蕆西郊，毖祀聿修。", "精意潜達，永孚于休。", "神之聽之，爰格飈斿。"]'),
('8e424e40-1444-428a-87df-75b4f52b7577','夕月十首 降神用《高安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕時維秋仲，夜寂天清。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕時維秋仲，夜寂天清。", "實嚴姊事，用答陰靈。", "壇壝斯設，黍稷惟馨。", "雲車來下，庶歆厥誠。"]'),
('54c59b7b-d7ec-4e85-baa4-957edf037ff5','夕月十首 降神用《高安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕遡日著明，麗天作配。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕遡日著明，麗天作配。", "潔誠以祠，禮行肅拜。", "光凝冕服，氣肅環珮。", "庶幾昭格，祗而不懈。"]'),
('accc7680-9410-4acf-947d-e266ae162792','夕月十首 降神用《高安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕穆穆流輝，太陰之精。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕穆穆流輝，太陰之精。", "盈虧靡忒，寒暑以均。", "克禋克祀，揆日涓辰。", "牲碩酒旨，來燕來寧。"]'),
('ad2b91b3-cdf4-47f4-adf1-1b778fff34bc','夕月十首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗歟崇基，右平左墄。',40,'全唐诗/poet.song.250000.json','["猗歟崇基，右平左墄。", "祗率典常，屆茲秋夕。", "陟降惟寅，威儀抑抑。", "神其鑒觀，穰簡是集。"]'),
('f5f71781-0fb9-4045-a0af-f18ab3d17653','夕月十首 奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','少采陳儀，實曰坎祭。',40,'全唐诗/poet.song.250000.json','["少采陳儀，實曰坎祭。", "禮備樂舉，嚴恭將事。", "于以奠之，嘉玉量幣。", "神兮昭受，陰騭萬彙。"]'),
('ba0f1c23-e0c0-4862-b8c8-b66869a431c9','夕月十首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穀旦其差，有牲在滌。',40,'全唐诗/poet.song.250000.json','["穀旦其差，有牲在滌。", "工祝致告，爲俎孔碩。", "肸蠁是期，祚我明德。", "備茲孝欽，式和民則。"]'),
('fe7f4e66-c983-41a2-a29b-499efd85d34a','夕月十首 酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','白藏在序，享惟其時。',40,'全唐诗/poet.song.250000.json','["白藏在序，享惟其時。", "躬即明壇，禮惟載祗。", "斟以瑶爵，神靈燕娭。", "歆馨顧德，錫我蕃釐。"]'),
('01165c61-4f75-4711-8604-e2dd3b4051df','夕月十首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅雍嚴祀，聖治昭彰。',40,'全唐诗/poet.song.250000.json','["肅雍嚴祀，聖治昭彰。", "清酒既載，或肆或將。", "禮匝三獻，終然允臧。", "神具醉止，其樂且康。"]'),
('3e99a6c6-c193-4204-ab3f-8a59bcf03155','夕月十首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','歌奏云闋，式禮莫愆。',40,'全唐诗/poet.song.250000.json','["歌奏云闋，式禮莫愆。", "以我齊明，罄其吉蠲。", "神保聿歸，降康自天。", "蘿圖永固，億萬斯年。"]'),
('48796322-5864-42a8-9b55-fb93fcefca06','熙寧以後祀高禖六首 降神用《高安》。六變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','容臺講禮，禖宮立祠。',40,'全唐诗/poet.song.250000.json','["容臺講禮，禖宮立祠。", "司分屆後，带韣陳儀。", "嘉祥萃止，靈馭來思。", "皇支蕃衍，永固邦基。"]'),
('5eec0031-b90f-4f6d-94bf-ddd828437b02','熙寧以後祀高禖六首 升降用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','郊禖之應，肇自生商。',40,'全唐诗/poet.song.250000.json','["郊禖之應，肇自生商。", "誕膺寶命，濬發其祥。", "天材蕃衍，德稱君王。", "本支萬世，與天無疆。"]'),
('73df567c-4eba-4668-b481-cf8e2c07da31','熙寧以後祀高禖六首 奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昔帝高辛，先禖肇祀。',40,'全唐诗/poet.song.250000.json','["昔帝高辛，先禖肇祀。", "爰揆仲陽，式祈嘉祉。", "陳之犧牲，授以弓矢。", "敷祐皇宗，施于孫子。"]'),
('ae519dda-1554-42ca-8f8d-1fb0458eed25','熙寧以後祀高禖六首 酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昭薦精衷，靈承端命。',40,'全唐诗/poet.song.250000.json','["昭薦精衷，靈承端命。", "青帝顧懷，神禖儲慶。", "祚以蕃昌，協于熙盛。", "螽斯衆多，流于雅詠。"]'),
('71f3fb59-aec8-4e3b-8d9e-b73e9e240867','熙寧以後祀高禖六首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫高禖，萬世所祀。',40,'全唐诗/poet.song.250000.json','["赫赫高禖，萬世所祀。", "其德不回，錫茲福祉。", "蕃衍椒聊，和平芣苢。", "傳類降康，世濟其美。"]'),
('b257bd85-0de1-42ca-b64a-7536b943f0ef','熙寧以後祀高禖六首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮奠蠲衷，祭儀竣事。',20,'全唐诗/poet.song.250000.json','["禮奠蠲衷，祭儀竣事。", "丕擁靈休，蕃衍皇嗣。"]'),
('9a1d63f9-0aae-41a6-a53d-38ea67c22173','紹興祀高禖十首 降神用《高安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕聿分春氣，施生在時。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕聿分春氣，施生在時。", "禖宮肇啟，精意以祠。", "禮儀告備，神其格思。", "厥靈有赫，錫我繁釐。"]'),
('2a163f93-b4c7-4d9f-93a2-f9d097dd9314','紹興祀高禖十首 降神用《高安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕眷此尊祀，實惟仲春。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕眷此尊祀，實惟仲春。", "青圭束帛，克祀克禋。", "庶蒙嘉惠，嗣續詵詵。", "神之降鑒，雲車來臻。"]'),
('fa2bd0e4-b942-4d69-8744-2c36110b74b1','紹興祀高禖十首 降神用《高安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕猗歟禖宮，祀典所貴。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕猗歟禖宮，祀典所貴。", "粵自艱難，禮或弗備。", "以迄于今，始建壇壝。", "願戒雲車，歆此誠意。"]'),
('7191e0e6-50b7-4297-b37c-a16a17cac132','紹興祀高禖十首 降神用《高安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕春氣肇分，萬類滋榮。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕春氣肇分，萬類滋榮。", "惟此祀事，皆象發生。", "求神以類，式昭至誠。", "庶幾來格，子孫繩繩。"]'),
('5b9ac19d-09f6-4ba1-a9ea-0be2dbbf462d','紹興祀高禖十首 升壇用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有奕禖宮，在國之南。',40,'全唐诗/poet.song.250000.json','["有奕禖宮，在國之南。", "壇壝既設，威儀孔嚴。", "登祀濟濟，神兮顧瞻。", "佑我皇祚，宜百斯男。"]'),
('0b698476-4a39-4d9f-9536-788232dda357','紹興祀高禖十首 奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','青律載陽，有鳦頡頏。',40,'全唐诗/poet.song.250000.json','["青律載陽，有鳦頡頏。", "祈我繁祉，立子生商。", "三牲既薦，玉帛是將。", "克禋克祀，有嘉其祥。"]'),
('39051369-c61d-4483-8cc1-8509321db8ab','紹興祀高禖十首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祗祓禖壇，潔蠲羊豕。',40,'全唐诗/poet.song.250000.json','["祗祓禖壇，潔蠲羊豕。", "博碩肥腯，爰具牲醴。", "執事駿奔，肅將俎几。", "神其顧歆，永錫多子。"]'),
('b967d844-9b6c-40bd-b525-a6a72287f8f3','紹興祀高禖十首 青帝位酌獻用《祐安》。伏羲、高辛酌獻并同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瑞鳦至止，祀事孔時。',40,'全唐诗/poet.song.250000.json','["瑞鳦至止，祀事孔時。", "酌以清酒，祼獻載祗。", "神具醉止，介我蕃禧。", "乃占吉夢，維熊維羆。"]'),
('d6ba2a2b-8848-4885-90e9-dfc10620c79c','紹興祀高禖十首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','中春涓吉，蕆事禖祠。',40,'全唐诗/poet.song.250000.json','["中春涓吉，蕆事禖祠。", "禮備樂作，籩豆孔時。", "貳觴畢舉，薦獻無違。", "庶幾神惠，祥啟熊羆。"]'),
('6846a124-8792-4a7c-b79a-471ca1632574','紹興祀高禖十首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉薦令芳，有嚴禋祀。',40,'全唐诗/poet.song.250000.json','["嘉薦令芳，有嚴禋祀。", "神來燕娭，亦既醉止。", "風馭言還，栗然歘起。", "以祓以除，錫我蕃祉。"]'),
('b4d83846-8c22-46a1-8e89-c27796798963','景德祀九宮貴神三首 降神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','倬彼垂象，照臨下土。',40,'全唐诗/poet.song.250000.json','["倬彼垂象，照臨下土。", "躔次運行，功德周普。", "九宮既位，惟德是輔。", "神之至上，皇皇斯臯。"]'),
('77f9ebe3-5c28-4116-9e81-fb9e182540f6','景德祀九宮貴神三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈禋既肅，明神既秩。',40,'全唐诗/poet.song.250000.json','["靈禋既肅，明神既秩。", "在國之東，協日之吉。", "升歌有儀，六變中律。", "懷和萬靈，降茲陰騭。"]'),
('bd7aa427-3752-45bc-9b20-bde5af29c3c2','景德祀九宮貴神三首 送神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祗薦有常，惟神無方。',20,'全唐诗/poet.song.250000.json','["祗薦有常，惟神無方。", "回飈整馭，垂休降祥。"]'),
('eeac94b5-fdc5-4f68-a66a-47d7f093d6c3','元祐祀九宮貴神二首 降神用《景安》。六變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上天貴神，九宮設位。',40,'全唐诗/poet.song.250000.json','["上天貴神，九宮設位。", "功德及物，乃秩明祀。", "望拜紫壇，赫然靈氣。", "奠玉薦幣，歆之無愧。"]'),
('e7fca8be-73c2-4d3c-8317-9fe0ec28cf20','元祐祀九宮貴神二首 送神用《景安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天之貴神，推移九宮。',40,'全唐诗/poet.song.250000.json','["天之貴神，推移九宮。", "厥位靡常，降康則同。", "來集于壇，顧歆恪恭。", "歌以送之，飈靜旋穹。"]'),
('834e6690-39ab-4e20-b26c-2267a3f73ca8','紹興祀九宮貴神十首 降神用《景安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕紫闕幽宏，惟神靈尊。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕紫闕幽宏，惟神靈尊。", "輔成泰元，贊役乃坤。", "曰雨曰暘，緼豫調紛。", "享薦隕光，蒙祉如屯。"]'),
('0845feec-38f2-4ad7-b51f-f52d91692992','紹興祀九宮貴神十首 降神用《景安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕載陽衍德，農祥孔昭。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕載陽衍德，農祥孔昭。", "賚茲元嘏，穰穰黍苗。", "象輿眇冥，金奏遠姚。", "無閼厥靈，丹衷匪恌。"]'),
('c92b0804-245a-460c-832a-32c6fac6f2ef','紹興祀九宮貴神十首 降神用《景安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕於赫九宮，天神之貴。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕於赫九宮，天神之貴。", "煌煌彪列，下土是蒞。", "幽贊高穹，陰騭萬類。", "肅若舊典，有嚴祗事。"]'),
('928ffb45-7215-4604-b07c-9b012abfbb68','紹興祀九宮貴神十首 降神用《景安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕練時吉良，聿崇明祀。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕練時吉良，聿崇明祀。", "粢盛潔豐，牲碩酒旨。", "肅唱和聲，來燕來止。", "嘉承天休，賚及含齒。"]'),
('0f870473-ca39-43b1-bf2d-baee77128828','紹興祀九宮貴神十首 初獻升壇用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於昭毖祀，周旋有容。',40,'全唐诗/poet.song.250000.json','["於昭毖祀，周旋有容。", "歷階將事，趨進鞠躬。", "改步如初，沒階彌恭。", "左墄右平，陟降雍雍。"]'),
('256c8737-4e9e-4ed2-94df-74e88589e3df','紹興祀九宮貴神十首 太一位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌九宮，照臨下土。',40,'全唐诗/poet.song.250000.json','["煌煌九宮，照臨下土。", "陰騭庶類，功施周普。", "恪修祀典，禮備樂舉。", "嘉玉量幣，馨非稷黍。"]'),
('996e1673-030d-4e85-a6dc-84c4dd3c0c53','紹興祀九宮貴神十首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈鑒匪遠，誠心肅祗。',40,'全唐诗/poet.song.250000.json','["靈鑒匪遠，誠心肅祗。", "是烝是享，俎實孔時。", "禮行樂奏，肸蠁是期。", "雲車風馬，神其燕娭。"]'),
('874a9f77-9a81-415d-b603-3290a3d31dd2','紹興祀九宮貴神十首 太一位酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟天丕冒，彪列九神。',40,'全唐诗/poet.song.250000.json','["惟天丕冒，彪列九神。", "財成元化，陰騭下民。", "有酒斯旨，登薦苾芬。", "昭哉降鑒，茀祿來臻。"]'),
('6ac61803-da54-43be-a3a7-168d72f9d6f3','紹興祀九宮貴神十首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','均調大化，陰騭下民。',40,'全唐诗/poet.song.250000.json','["均調大化，陰騭下民。", "駿功有赫，誕舉明禋。", "嘉觴中貳，執事惟寅。", "清明鬯矣，福祿攸臻。"]'),
('2da951ff-c852-45cc-88e6-d2decc8fa74a','紹興祀九宮貴神十首 送神用《景安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','薦獻有序，降登無違。',40,'全唐诗/poet.song.250000.json','["薦獻有序，降登無違。", "禮樂備舉，昭格燕娭。", "雲車縹緲，神曰還歸。", "報以景貺，翊我昌期。"]'),
('17f80388-f8b5-4b03-8e3c-d18f6bf7fe66','建隆以來祀享太廟十六首 迎神用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅清廟，奉祠來詣。',40,'全唐诗/poet.song.250000.json','["肅肅清廟，奉祠來詣。", "格思之靈，如在之祭。", "克謹威儀，載嚴容衛。", "降福孔皆，以克永世。"]'),
('ffeef1e1-01e1-48ab-b1e2-046628e58a31','建隆以來祀享太廟十六首 皇帝行用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','工祝升階，賓尸在位。',40,'全唐诗/poet.song.250000.json','["工祝升階，賓尸在位。", "祗達孝思，允修毖祀。", "顯相有儀，克恭乃事。", "儼恪其容，通此精意。"]'),
('3b5f1347-894b-41f0-911c-010ac917f972','建隆以來祀享太廟十六首 奠瓚用《瑞木》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','木符啟瑞，著象成文。',40,'全唐诗/poet.song.250000.json','["木符啟瑞，著象成文。", "於昭大號，協應明君。", "靈命有屬，鴻禧洞分。", "歌以升薦，休嘉洽聞。"]'),
('2a083680-fe57-43e8-853a-f3ec0d255799','建隆以來祀享太廟十六首 又用《馴象》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉彼馴象，來歸帝鄉。',40,'全唐诗/poet.song.250000.json','["嘉彼馴象，來歸帝鄉。", "南州毓質，中區效祥。", "仁格巨獸，德柔遐荒。", "有感斯應，神化無方。"]'),
('f66873dc-b511-4160-b827-1dce6e194098','建隆以來祀享太廟十六首 又用《玉烏》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','素烏爰止，淳精允臧。',40,'全唐诗/poet.song.250000.json','["素烏爰止，淳精允臧。", "名符瑞牒，色應金方。", "潔白容與，翹英奮揚。", "孝思攸感，皇德逾張。"]'),
('2d8488fa-ed0a-4de7-ae37-cfc1aa931432','建隆以來祀享太廟十六首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維犧維牲，以炰以烹。',40,'全唐诗/poet.song.250000.json','["維犧維牲，以炰以烹。", "植其鞉鼓，潔彼鉶羹。", "孔碩茲俎，於穆厥聲。", "肅雍顯相，福祿來成。"]'),
('35886155-ef4f-4a80-b9ea-25ac39a32378','建隆以來祀享太廟十六首 酌獻僖祖室用《大善》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','湯湯洪河，經啟長源。',40,'全唐诗/poet.song.250000.json','["湯湯洪河，經啟長源。", "鬰鬰嘉木，挺生本根。", "大哉崇基，出乎慶門。", "發祥垂裕，永世貽孫。"]'),
('f15987b3-7816-4887-8ad7-da940a2c0385','建隆以來祀享太廟十六首 順祖室用《大寧》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','元鍾九千，生於仲呂。',40,'全唐诗/poet.song.250000.json','["元鍾九千，生於仲呂。", "崇臺九層，起於累土。", "赫日之升，明夷爲主。", "孝孫作帝，式由祖武。"]'),
('8f76f30b-911d-4885-8c15-d3dd2ae61afb','建隆以來祀享太廟十六首 翼祖室用《大順》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明我祖，積德攸宜。',40,'全唐诗/poet.song.250000.json','["明明我祖，積德攸宜。", "肇繼瓜瓞，將隆本支。", "爰資慶緒，式昭帝基。", "於穆清廟，永洽重熙。"]'),
('efd8bcbe-85da-4522-afeb-88ceddbd355f','建隆以來祀享太廟十六首 宣祖室用《大慶》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','艱難積行，綿長鍾慶。',40,'全唐诗/poet.song.250000.json','["艱難積行，綿長鍾慶。", "同人之時，得主乃定。", "既敘宗祧，乃修舞詠。", "經武開先，永昭丕命。"]'),
('9d9a1e46-8652-45c3-8139-d9d58c175bca','建隆以來祀享太廟十六首 太祖室用《大定》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗歟太祖，受命于天。',40,'全唐诗/poet.song.250000.json','["猗歟太祖，受命于天。", "化行區宇，功溢簡編。", "武威震耀，文德昭宣。", "開基垂統，億萬斯年。"]'),
('ec079433-ec52-41b5-9bd0-ef301409cf7b','建隆以來祀享太廟十六首 太宗室用《大盛》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫皇運，明明太宗。',40,'全唐诗/poet.song.250000.json','["赫赫皇運，明明太宗。", "四隩咸暨，一變時雍。", "睿文炳煥，聖德溫恭。", "千齡萬祀，永播笙鏞。"]'),
('56d03012-9755-461d-9c83-dae88cb514ed','建隆以來祀享太廟十六首 飲福用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉粟旨酒，博腯牲牷。',40,'全唐诗/poet.song.250000.json','["嘉粟旨酒，博腯牲牷。", "神鑒孔昭，享茲吉蠲。", "夙夜毖祀，孝以奉先。", "永錫純嘏，功格于天。"]'),
('5ee9dea7-8954-4925-a94a-156fb1dcf274','建隆以來祀享太廟十六首 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','已象文治，乃觀武成。',20,'全唐诗/poet.song.250000.json','["已象文治，乃觀武成。", "進退可度，威儀克明。"]'),
('ebe34d76-2ae9-41f2-8a9b-f5b2070b8f1a','建隆以來祀享太廟十六首 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','常武徂征，詩人所稱。',20,'全唐诗/poet.song.250000.json','["常武徂征，詩人所稱。", "總干山立，厥象伊凝。"]'),
('4f1379a7-ae2f-49c4-977f-98f28d65ad63','建隆以來祀享太廟十六首 徹豆用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肥腯之牲，既析既薦。',40,'全唐诗/poet.song.250000.json','["肥腯之牲，既析既薦。", "鬰鬯之酒，已酌已獻。", "祝辭亦陳，和奏斯徧。", "享禮具舉，徹其有踐。"]'),
('1b92a5b4-89fb-447d-812f-a259c8c88dcd','攝事十三首 降神用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅清廟，昭事祖禰。',40,'全唐诗/poet.song.250000.json','["肅肅清廟，昭事祖禰。", "粢盛苾芬，四海來祭。", "皇靈格思，令容有睟。", "降福孔皆，以克永世。"]'),
('193840ed-f04e-4fa5-9ac6-69313127157c','攝事十三首 太尉行用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祼鬯溥將，賓尸在位。',40,'全唐诗/poet.song.250000.json','["祼鬯溥將，賓尸在位。", "帝德升聞，孝思光被。", "公卿庶正，傅御師氏。", "至誠感神，福祿來暨。"]'),
('e78d1b99-692e-4f94-ae4e-7016b20884c7','攝事十三首 奠瓚用《瑞安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','淳清育物，瑞木成文。',40,'全唐诗/poet.song.250000.json','["淳清育物，瑞木成文。", "元氣陶冶，非煙鬰氛。", "玄貺昭格，至和所熏。", "登歌祼獻，肸蠁如聞。"]'),
('dd957c46-f4b9-4dce-b534-c93765dabbe2','攝事十三首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','麗碑割牲，以炰以烹。',40,'全唐诗/poet.song.250000.json','["麗碑割牲，以炰以烹。", "博碩肥腯，薦羞神明。", "祖考來格，享于克誠。", "如聞謦欬，式燕以寧。"]'),
('f8024cd1-e064-4897-a8e6-1b157d7d3361','攝事十三首 酌獻僖祖室用《大善》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅藝祖，肇基鴻源。',40,'全唐诗/poet.song.250000.json','["肅肅藝祖，肇基鴻源。", "權輿光大，燕翼貽孫。", "載祀惟永，慶流後昆。", "威靈在天，顧我思存。"]'),
('8d739313-b31d-457a-ab84-279edac5e7a4','攝事十三首 順祖室用《大寧》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思文聖祖，長發其祥。',40,'全唐诗/poet.song.250000.json','["思文聖祖，長發其祥。", "錫羨蕃衍，德厚流光。", "眷命自天，卜世聿昌。", "祗肅孝享，降福無疆。"]'),
('9eabba7f-ea96-4ef7-a253-ca7c8da4fa57','攝事十三首 翼祖室用《大順》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明我祖，積德累仁。',40,'全唐诗/poet.song.250000.json','["明明我祖，積德累仁。", "居晦匿曜，邁種惟勤。", "帝圖天錫，輝光日新。", "寢廟繹繹，昭事同寅。"]'),
('140b7977-2ba1-4b7e-a886-292b24eb082a','攝事十三首 宣祖室用《大慶》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','洸洸我祖，時惟鷹揚。',40,'全唐诗/poet.song.250000.json','["洸洸我祖，時惟鷹揚。", "潜德弗耀，發源靈長。", "肆類配天，永思不忘。", "來顧來享，百福是將。"]'),
('8f458955-aeee-43f5-a0dd-a9748ea01ebe','攝事十三首 太祖室用《大定》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫太祖，受命于天。',40,'全唐诗/poet.song.250000.json','["赫赫太祖，受命于天。", "赤符啟運，威加八埏。", "神武戡難，功無間然。", "翼翼丕承，億萬斯年。"]'),
('8780f242-d28c-496d-98d0-9ad5a0cc4f87','攝事十三首 太宗室用《大盛》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆太宗，與天合德。',40,'全唐诗/poet.song.250000.json','["穆穆太宗，與天合德。", "昧旦丕顯，乾乾翼翼。", "敷佑下民，時帝之力。", "永懷聖神，孝思罔極。"]'),
('cf1b9a70-7ce4-4387-adba-b8f8a30b5566','攝事十三首 真宗室用《大明》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌真宗，善繼善承。',40,'全唐诗/poet.song.250000.json','["煌煌真宗，善繼善承。", "經武耀德，臻于治平。", "對祀禮樂，丕昭鴻名。", "陟配文廟，皇圖永寧。"]'),
('20c36589-e277-4fbd-8da7-0879c47ea443','攝事十三首 徹豆用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鼎俎既陳，豆籩既設。',40,'全唐诗/poet.song.250000.json','["鼎俎既陳，豆籩既設。", "金石在庭，工師就列。", "備物有嚴，著誠致潔。", "孝惟時思，禮以雍徹。"]'),
('24848cc5-c40d-4b1b-a415-953e8760db08','攝事十三首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之來兮風肅然，神之去兮升九天。',32,'全唐诗/poet.song.250000.json','["神之來兮風肅然，神之去兮升九天。", "排凌兢兮還恍惚，羽旄紛兮蕭燔煙。"]'),
('b1157797-5685-4315-92bc-043c4bc64bea','真宗御製二首 奠瓚用《萬國朝天》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鴻源濬發，睿圖誕彰。',200,'全唐诗/poet.song.250000.json','["鴻源濬發，睿圖誕彰。", "高明錫羨，累洽延祥。", "巍巍藝祖，溥率賓王。", "煌煌文考，區宇大康。", "珍符昭顯，寶曆綿長。", "物性茂遂，民俗阜昌。", "甫田多稼，禾黍穰穰。", "含生嘉育，鳥獸蹌蹌。", "八紘統域，九服要荒。", "沐浴惠澤，祗畏典常。", "隔谷分壤，望斗辨方。", "並襲冠带，來奉圭璋。", "峨峨雙闕，濟濟明堂。", "諸侯執帛，天后當陽。", "何以辨等，衮衣繡裳。", "何以褒德，輅車乘黄。", "聲明煥赫，雅頌汪洋。", "啟茲丕緒，祐我無疆。", "大統斯集，大樂斯揚。", "俯隆宗祏，仰繼穹蒼。"]'),
('36b8eb35-0542-4684-bd2c-c2ccde05358f','真宗御製二首 亞獻、終獻用《平晉樂》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','五代衰替，六合携離。',200,'全唐诗/poet.song.250000.json','["五代衰替，六合携離。", "封疆竊據，兵甲競馳。", "天顧黎獻，塗炭可悲。", "帝啟靈命，濬哲應期。", "皇祖丕變，金鉞俄麾。", "率土執贄，獷俗來儀。", "瞻彼大鹵，竊此餘基。", "獨迷文告，莫畏天威。", "神宗繼統，璿圖有輝。", "尚安蠢爾，罔懷格思。", "六飛夙駕，萬旅奉辭。", "徯來發詠，不陣行師。", "雲旗先路，壺漿塞岐。", "天臨日照，宸慮通微。", "前歌後舞，人心悅隨。", "要領自得，智力何施。", "風移僭冒，政治淳熙。", "書文混一，盛德咸宜。", "干戈倒載，振振言歸。", "誕昭七德，永定九圍。"]'),
('f45cce3b-7836-4e7d-b1ab-5c8ed5bae85e','真宗告饗六首 告受天書用《瑞安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寶命自天，鴻禧錫祚。',40,'全唐诗/poet.song.250000.json','["寶命自天，鴻禧錫祚。", "昭晰綠文，氤氳黄素。", "玄感薦彰，靈休誕布。", "寅奉珍符，聿懷永慕。"]'),
('ee1fdec0-2da2-461d-985c-de7bfca0a9d3','真宗告饗六首 太祖、太宗加上尊謚用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','報貺陟封，聿昭典禮。',40,'全唐诗/poet.song.250000.json','["報貺陟封，聿昭典禮。", "讓德穹厚，歸功祖禰。", "丕顯尊稱，盡善盡美。", "寅威孝思，以介蕃祉。"]'),
('31d2d826-58ee-4deb-a673-96c830b21585','真宗告饗六首 東封畢躬謝酌獻用《封安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕清廟，錫羨詒謀。',40,'全唐诗/poet.song.250000.json','["奕奕清廟，錫羨詒謀。", "升中神嶽，顯允皇猷。", "歸格藝祖，昭報靈休。", "奉先追遠，盛德益修。"]'),
('68d6e888-6393-40e3-8c1a-1bd7691bbfee','真宗告饗六首 祀汾陰畢躬謝酌獻用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於昭列聖，休德清明。',40,'全唐诗/poet.song.250000.json','["於昭列聖，休德清明。", "威靈如在，享于克誠。", "報功厚載，馨薦惟精。", "歸格飲至，禮備樂成。"]'),
('6f7aed8d-7bec-4b9c-ae0c-6ee0e563dc52','真宗告饗六首 聖祖降親告用《瑞安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於赫聖祖，景靈在天。',40,'全唐诗/poet.song.250000.json','["於赫聖祖，景靈在天。", "神遊來暨，睟容穆然。", "誨言昭示，帝胄開先。", "齊明欽若，延鴻億年。"]'),
('91370388-d2d4-4575-aa61-ba61dc1b0e83','真宗告饗六首 六室加謚用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','欽崇太霄，肅奉徽冊。',40,'全唐诗/poet.song.250000.json','["欽崇太霄，肅奉徽冊。", "大禮克誠，鴻猷有赫。", "令芳爰薦，明靈斯格。", "照謝垂祥，永懷何極。"]'),
('ff5825f3-09e3-47de-b5a7-7d4a870bf89f','景祐親享太廟二首 迎神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','追養奉先，納孝練主。',40,'全唐诗/poet.song.250000.json','["追養奉先，納孝練主。", "金奏鳳鳴，關雎樂舞。", "奠鬯恭神，肥腯展俎。", "積慶聰明，降景寰宇。"]'),
('c576e631-17b6-473b-8221-60ecafdeca55','景祐親享太廟二首 酌獻真宗室用《大明》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆真皇，宅心道粹。',40,'全唐诗/poet.song.250000.json','["於穆真皇，宅心道粹。", "和戎偃革，煥乎文治。", "操瑞拜圖，封天祀地。", "盛德爲宗，烝嘗萬世。"]'),
('3d1fd96c-9932-4e6b-80ef-3bdc974f11ae','至和祫享三首 迎神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','濡露降霜，永懷孝思。',40,'全唐诗/poet.song.250000.json','["濡露降霜，永懷孝思。", "祫食諦敘，再閏之期。", "歌德詠功，八音播之。", "歆神惟始，靈其格茲。"]'),
('52b4d7f8-7ebb-41a9-9677-72da440a5ea7','至和祫享三首 奠瓚用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昭穆親祖，自室徂堂。',40,'全唐诗/poet.song.250000.json','["昭穆親祖，自室徂堂。", "禮備樂成，肅然祼將。", "瑟瓚黄流，條鬯芬芳。", "氣達淵泉，神孚來享。"]'),
('d8de17b7-2bd3-41c7-a63c-9edc410c760a','至和祫享三首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四祖基慶，三后在天。',40,'全唐诗/poet.song.250000.json','["四祖基慶，三后在天。", "薦侑備成，靈娭其旋。", "孝孫應嘏，受福永年。", "送之懷之，明發惻然。"]'),
('d1f09e2d-c3b7-4bcd-8e44-5ae3839be35c','嘉祐祫享二首 迎神用《懷安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','躬茲孝享，禮備樂成。',40,'全唐诗/poet.song.250000.json','["躬茲孝享，禮備樂成。", "神登于俎，祝導于祊。", "展牲肥腯，奏格和平。", "靈其昭格，肅僾凝情。"]'),
('bbcec1a5-6a0c-408d-9003-70b77e2589ad','嘉祐祫享二首 送神用《懷安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈神歸止，光景肅然。',40,'全唐诗/poet.song.250000.json','["靈神歸止，光景肅然。", "福祥裕世，明威在天。", "孝孫有慶，駿烈推先。", "佑茲基緒，彌萬斯年。"]'),
('01ca75fe-8908-4ec7-a145-ddcd7d1ce737','熙寧以後享廟五首 酌獻英宗室用《大英》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','在宋五世，天子嗣昌。',40,'全唐诗/poet.song.250000.json','["在宋五世，天子嗣昌。", "躬發英斷，若乾之剛。", "聲容沄沄，被于八荒。", "垂千萬年，永烈有光。"]'),
('84e86ec1-ad72-48c2-a44a-9cffac2ddb6b','熙寧以後享廟五首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鍾鼓惟旅，籩豆孔時。',40,'全唐诗/poet.song.250000.json','["鍾鼓惟旅，籩豆孔時。", "衎我祖宗，既右享之。", "神亟來止，孝孫之喜。", "神保聿歸，孝孫之思。"]'),
('305a289d-2735-40a1-a907-aacf437789f5','熙寧以後享廟五首 禘祫孟享、臘享宗正卿升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','進退有容，服章有儀。',20,'全唐诗/poet.song.250000.json','["進退有容，服章有儀。", "匪亟匪遲，降登孔時。"]'),
('eee94700-007e-4426-89ec-f5ad1d62582d','熙寧以後享廟五首 祫享仁宗用《大和》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆仁廟，聖澤滂流。',40,'全唐诗/poet.song.250000.json','["於穆仁廟，聖澤滂流。", "華夷用乂，動植蒙休。", "徽名冠古，奕世垂謀。", "帝躬祼獻，盛典昭修。"]'),
('d58a7232-422f-4b8d-ab60-44cf331be725','熙寧以後享廟五首 英宗用《大康》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫英皇，總提邦紀。',40,'全唐诗/poet.song.250000.json','["赫赫英皇，總提邦紀。", "濬發神功，恢張聖理。", "仙馭雖遥，鴻徽不弭。", "永言孝思，竭誠躬祀。"]'),
('e94d0a1f-587d-4d18-89fa-558889a1f2f0','常祀五享三首 迎神用《興安》。九變。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕清廟，昭穆定位。',40,'全唐诗/poet.song.250000.json','["奕奕清廟，昭穆定位。", "霜露增感，粢盛潔祭。", "神靈來格，福祉攸暨。", "追孝奉先，本支百世。"]'),
('629cd2c1-0c42-4908-917c-95e86bde0e69','常祀五享三首 太尉奠瓚用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有秩時祀，匪怠匪瀆。',40,'全唐诗/poet.song.250000.json','["有秩時祀，匪怠匪瀆。", "有來宗工，載祗載肅。", "厥作祼將，流黄瓚玉。", "是享是宜，永綏多福。"]'),
('16833356-31b1-4d9d-a7db-895af4807954','常祀五享三首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇祖皇考，配帝配天。',40,'全唐诗/poet.song.250000.json','["皇祖皇考，配帝配天。", "駿奔顯相，神保言旋。", "祝以孝告，嘏以慈宣。", "去來永慕，宗事惟虔。"]'),
('4b67af05-048c-4286-8769-844f4bd6d9eb','紹興以後時享二十五首 迎神用《興安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲宮〕奉先嚴祀，率禮大經。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲宮〕奉先嚴祀，率禮大經。", "時思致享，肅薦芳馨。", "竭誠備物，樂奏和聲。", "真馭來止，熙事克成。"]'),
('270ea310-6f14-4d3d-ac7f-05a01b9ba405','紹興以後時享二十五首 迎神用《興安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔大呂爲角〕聖靈在天，九關崇深。',46,'全唐诗/poet.song.250000.json','["〔大呂爲角〕聖靈在天，九關崇深。", "風馬雲車，紛其顧臨。", "擁祥儲休，昭答孝心。", "孝孫受祉，萬福是膺。"]'),
('8bea6bc5-8bda-496c-b653-90914146214c','紹興以後時享二十五首 迎神用《興安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕嘉承和平，秩祀爲先。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕嘉承和平，秩祀爲先。", "乃練休辰，祝史告虔。", "內心齊明，祀具吉蠲。", "交際恍惚，如在後前。"]'),
('89262a5f-177c-4af1-811d-23119c144c1d','紹興以後時享二十五首 迎神用《興安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔應鍾爲羽〕道信於神，神靈燕娭。',46,'全唐诗/poet.song.250000.json','["〔應鍾爲羽〕道信於神，神靈燕娭。", "酒有嘉德，物惟其時。", "緩節安歌，樂奏具宜。", "欣欣樂康，福祿綏之。"]'),
('476ad640-0c75-4100-bbde-1684554bc180','紹興以後時享二十五首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','王假有廟，子孫保光。',40,'全唐诗/poet.song.250000.json','["王假有廟，子孫保光。", "奉牲以告，玉俎膏香。", "專精厲意，神其迪嘗。", "休承靈意，申錫無疆。"]'),
('9bc24e36-4a1d-4699-8e64-1fd975e75d27','紹興以後時享二十五首 初獻盥洗用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恪恭祀典，涓選休成。',40,'全唐诗/poet.song.250000.json','["恪恭祀典，涓選休成。", "設洗致潔，直于東榮。", "嘉觴祗薦，明德惟馨。", "祖考來格，享茲孝誠。"]'),
('8c34804e-eb5d-4acc-92ab-1d9f7f151dec','紹興以後時享二十五首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','冠佩雍容，時惟上公。',40,'全唐诗/poet.song.250000.json','["冠佩雍容，時惟上公。", "享于清廟，陟降彌恭。", "籩豆靜嘉，粢盛潔豐。", "孝孫有慶，萬福來同。"]'),
('2bc8bf9f-bf05-4013-83bc-5e28b72b4c9c','紹興以後時享二十五首 僖祖室酌獻用《基命》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆文獻，自天發祥。',40,'全唐诗/poet.song.250000.json','["於穆文獻，自天發祥。", "肇基明命，錫羨無疆。", "子孫千億，宗社靈長。", "神之格思，如在洋洋。"]'),
('8e122fb0-f4bc-4514-9d0d-53a321a4a032','紹興以後時享二十五首 宣祖室酌獻用《天元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天啟炎曆，集我大命。',40,'全唐诗/poet.song.250000.json','["天啟炎曆，集我大命。", "長發其祥，篤生上聖。", "夷亂芟荒，乾坤以定。", "時祀聿修，孝孫有慶。"]'),
('c0f81a88-4788-4231-93f0-5bb97fe7a662','紹興以後時享二十五首 太祖室酌獻用《皇武》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫藝祖，受天明命。',40,'全唐诗/poet.song.250000.json','["赫赫藝祖，受天明命。", "威加八紘，德垂累聖。", "祀事孔明，有嚴笙磬。", "對越在天，延休錫慶。"]'),
('40dea5fb-73b7-4c0c-9c2e-2db46ec411fc','紹興以後時享二十五首 太宗室酌獻用《大定》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明在上，時維太宗。',40,'全唐诗/poet.song.250000.json','["明明在上，時維太宗。", "允武允文，丕基紹隆。", "於肅清廟，昭報是豐。", "皇靈格思，福祿來同。"]'),
('606e3f43-13a8-4209-8de5-8a25d0a6e551','紹興以後時享二十五首 真宗室酌獻用《熙文》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆真皇，維烈有光。',40,'全唐诗/poet.song.250000.json','["於穆真皇，維烈有光。", "丕承二后，奄奠萬方。", "威加戎狄，道格穹蒼。", "歆時禋祀，降福無疆。"]'),
('4a9e2c67-4b83-466a-83af-666273bd41fd','紹興以後時享二十五首 仁宗室酌獻用《美成》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至哉帝德，乃聖乃神。',40,'全唐诗/poet.song.250000.json','["至哉帝德，乃聖乃神。", "恭己南面，天下歸仁。", "歷年長久，垂裕後人。", "祀修舊典，寶命維新。"]'),
('2f6e2060-15ae-415d-85c3-f51ba98139ee','紹興以後時享二十五首 英宗室酌獻用《治隆》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','炎基克鞏，赫赫英宗。',40,'全唐诗/poet.song.250000.json','["炎基克鞏，赫赫英宗。", "紹休前烈，仁化彌隆。", "篤生聖子，堯湯比蹤。", "烝嘗萬世，福祿來崇。"]'),
('2614be71-7839-4b79-9c1d-08c5d5ac1a90','紹興以後時享二十五首 神宗室酌獻用《大明》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於昭神祖，運撫明昌。',40,'全唐诗/poet.song.250000.json','["於昭神祖，運撫明昌。", "肇新百度，克配三王。", "遐荒底績，聖武維揚。", "永言執競，上帝是皇。"]'),
('b2ad176f-dc0d-40ee-baa3-845bb90cd863','紹興以後時享二十五首 哲宗室酌獻用《重光》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇濬哲，遹駿有聲。',40,'全唐诗/poet.song.250000.json','["於皇濬哲，遹駿有聲。", "率時昭考，丕顯儀刑。", "功光大業，道協三靈。", "永綏厥後，來燕來寧。"]'),
('00751a83-e978-4a89-a80b-ebfe51fa08bc','紹興以後時享二十五首 徽宗室酌獻用《承元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天錫神聖，徽柔懿恭。',40,'全唐诗/poet.song.250000.json','["天錫神聖，徽柔懿恭。", "垂衣拱手，遵制揚功。", "配天立極，體道居中。", "佑我烈考，萬福攸同。"]'),
('530e6e1b-4ec3-4a62-b81a-b60bb67434e7','紹興以後時享二十五首 欽宗室酌獻用《端慶》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇欽宗，道備德宏。',40,'全唐诗/poet.song.250000.json','["於皇欽宗，道備德宏。", "允恭允儉，克類克明。", "孝遵前烈，仁翊函生。", "歆茲肆祀，永燕宗祊。"]'),
('81243477-d1a1-4879-8d17-c72847d9c5fc','紹興以後時享二十五首 高宗室用《大德》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇時宋，自天保定。',40,'全唐诗/poet.song.250000.json','["於皇時宋，自天保定。", "高宗受之，再僕景命。", "紹開中興，翼善傳聖。", "何千萬年，永綏厥慶。"]'),
('a3cdceaf-85fb-4142-97f3-39c7d43277cb','紹興以後時享二十五首 孝宗室用《大倫》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖人之德，無加於孝。',40,'全唐诗/poet.song.250000.json','["聖人之德，無加於孝。", "思皇孝宗，履行立教。", "始終純誠，非曰笑貌。", "於萬斯年，是則是傚。"]'),
('0d253660-4120-4201-b12f-88d68299e83d','紹興以後時享二十五首 光宗室用《大和》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維宋洽熙，帝繼于理。',40,'全唐诗/poet.song.250000.json','["維宋洽熙，帝繼于理。", "萬姓厚生，三辰順軌。", "對時天休，以燕翼子。", "肅唱和聲，神其有喜。"]'),
('94aa0824-159f-4488-b98e-19db6142f61a','紹興以後時享二十五首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅清廟，於顯維德。',40,'全唐诗/poet.song.250000.json','["肅肅清廟，於顯維德。", "我祀孔時，我奏有翼。", "秉翟載駿，有來干戚。", "神之燕娭，休祥允格。"]'),
('a4ccd0c2-714b-4787-a12e-f1504d7ebee0','紹興以後時享二十五首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','觀德宗祏，奕世烈光。',40,'全唐诗/poet.song.250000.json','["觀德宗祏，奕世烈光。", "有嚴祀典，粵循舊章。", "樂諧九變，獻舉重觴。", "燕娭如在，戩穀穰穰。"]'),
('40ffa979-471b-4e4f-aa14-02d319e09ae7','紹興以後時享二十五首 徹豆用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮備樂成，物稱誠竭。',40,'全唐诗/poet.song.250000.json','["禮備樂成，物稱誠竭。", "相維辟公，神人以說。", "歌雍一章，諸宰斯徹。", "天子萬年，無競維烈。"]'),
('980540f3-3aa1-4832-8f54-4a4a789ad1ea','紹興以後時享二十五首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','霜露既降，時思展禋。',40,'全唐诗/poet.song.250000.json','["霜露既降，時思展禋。", "在天之御，睠然顧歆。", "樂成禮備，言歸靡停。", "既安既樂，福祿來成。"]'),
('e4007d52-d421-40cf-8a7d-0605c37e5293','祫享八首 迎神用《興安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾宮〕時維孟冬，霜露既零。',45,'全唐诗/poet.song.250000.json','["〔黄鍾宮〕時維孟冬，霜露既零。", "合食盛禮，以時以行。", "孝心翼翼，惟神來寧。", "肅倡斯舉，神具是聽。"]'),
('777f586d-f683-4f07-ba59-2af537476061','祫享八首 迎神用《興安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔大呂角〕於穆孝思，嘉薦維時。',45,'全唐诗/poet.song.250000.json','["〔大呂角〕於穆孝思，嘉薦維時。", "誠通茲格，咸來燕娭。", "神之聽之，申錫蕃釐。", "於萬斯年，永保丕基。"]'),
('bf949151-6c38-4577-8cba-515c7fba8917','祫享八首 迎神用《興安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇徵〕於昭孝治，通乎神明。',45,'全唐诗/poet.song.250000.json','["〔太簇徵〕於昭孝治，通乎神明。", "寒暑不忒，熙事備成。", "牲牷孔碩，黍稷惟馨。", "以享以祀，來燕來寧。"]'),
('16ad6b8c-9689-4775-b49e-790437f8b9ce','祫享八首 迎神用《興安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔應鍾羽〕苾芬孝祀，薦灌肅雍。',45,'全唐诗/poet.song.250000.json','["〔應鍾羽〕苾芬孝祀，薦灌肅雍。", "致力於神，明信咸通。", "靈之妥留，惠我龐鴻。", "廣被萬宇，福祿攸同。"]'),
('ecdad201-4967-45a4-b4d0-9e67e7474ae4','祫享八首 初獻、順祖酌獻用《大寧》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於赫皇祖，濬發其祥。',40,'全唐诗/poet.song.250000.json','["於赫皇祖，濬發其祥。", "德盛流遠，奕世彌昌。", "孝孫有慶，嘉薦令芳。", "神保是享，錫羨無疆。"]'),
('3c5028be-5050-4907-85b1-33dd182c2327','祫享八首 翼祖酌獻用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上天眷命，佑我丕基。',40,'全唐诗/poet.song.250000.json','["上天眷命，佑我丕基。", "翼翼皇祖，不耀其輝。", "積厚流長，福祿攸宜。", "祀事孔時，曾孫篤之。"]'),
('88aef6a4-1635-438f-85c0-6f3b025aae19','祫享八首 光宗室酌獻用《大承》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇光宗，握符御極。',40,'全唐诗/poet.song.250000.json','["於皇光宗，握符御極。", "昭哉嗣服，惟仁與德。", "勤施於民，靡有暇逸。", "萬年之思，永奠宗祏。"]'),
('1dd3a3b1-7592-4f23-a188-88b2ee61387f','祫享八首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','合祭大事，因時發天。',40,'全唐诗/poet.song.250000.json','["合祭大事，因時發天。", "翼翼孝思，三獻禮虔。", "神兮樂康，飈馭言旋。", "永福後人，於千萬年。"]'),
('c02eeaa7-29fa-4f3f-acc0-9daba4280727','上仁宗英宗徽號一首 入門升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆仁祖，寵綏萬方。',40,'全唐诗/poet.song.250000.json','["於穆仁祖，寵綏萬方。", "執競英考，迄用成康。", "圖徽寶冊，有烈其光。", "庶幾億載，與天無疆。"]'),
('ad1e51a4-b150-46d5-9c65-e3a4261d1e4d','上英宗尊號一首 入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','在宋五世，天子神明。',40,'全唐诗/poet.song.250000.json','["在宋五世，天子神明。", "羣公奉冊，迺揚鴻名。", "金書煌煌，遹昭厥成。", "思皇多祜，與天同聲。"]'),
('8b755fad-1373-42ff-bfae-36bb0285d12c','增上神宗徽號一首 升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於惟禰廟，乃聖乃神。',40,'全唐诗/poet.song.250000.json','["於惟禰廟，乃聖乃神。", "秉文之士，作起惟新。", "建宮稽古，一視同仁。", "庶幾備號，以享天人。"]'),
('e11096ea-8f45-4b42-99c1-e2922ecbcc48','紹興十四年奉上徽宗冊寶三首 冊寶入門用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於鑠徽考，如天莫名。',40,'全唐诗/poet.song.250000.json','["於鑠徽考，如天莫名。", "迨茲丕揚，擬純粹精。", "溫玉鏤文，來至于祊。", "有嚴奕奕，禮備樂成。"]'),
('b3772c34-2f64-40ba-b425-44633f44868e','紹興十四年奉上徽宗冊寶三首 冊寶升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金字煌煌，瑶光燦燦。',40,'全唐诗/poet.song.250000.json','["金字煌煌，瑶光燦燦。", "羣工奉之，登此寶殿。", "對越祖宗，式遵成憲。", "威靈在天，來止來燕。"]'),
('84db3086-32ff-43a9-845c-3095446b0ecc','紹興十四年奉上徽宗冊寶三首 上徽號用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟精惟一，乃聖乃神。',40,'全唐诗/poet.song.250000.json','["惟精惟一，乃聖乃神。", "鴻名克揚，茂實斯賓。", "如禹之功，如堯之仁。", "孝思永慕，用詔無垠。"]'),
('d11379d0-c5b4-4c65-9bad-53cb74e23dc7','淳熙十五年上高宗徽號三首 冊寶入門用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆高皇，功德兼隆。',40,'全唐诗/poet.song.250000.json','["於穆高皇，功德兼隆。", "稱天以誄，初謚未崇。", "載稽禮典，揚徽垂鴻。", "涓日之良，登進廟宮。"]'),
('96867789-0f8a-408f-9a74-00ce16815673','淳熙十五年上高宗徽號三首 冊寶升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有瑑斯寶，有編斯冊。',40,'全唐诗/poet.song.250000.json','["有瑑斯寶，有編斯冊。", "導以麾仗，奏以金石。", "祲威盛容，煌煌赫赫。", "巨工奉之，高靈來格。"]'),
('57d89ac3-3df2-4371-9250-d9cc91de059f','淳熙十五年上高宗徽號三首 上徽號用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','中興之烈，高掩商宗。',40,'全唐诗/poet.song.250000.json','["中興之烈，高掩商宗。", "揖遜之美，放勳比隆。", "字十有六，擬諸形容。", "威靈在天，裕後無窮。"]'),
('e5802cf3-8e39-47ed-85f1-b3dca3c3dfda','慶元三年奉上孝宗徽號三首 冊寶入門用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','巍巍孝廟，聖德天通。',40,'全唐诗/poet.song.250000.json','["巍巍孝廟，聖德天通。", "同符藝祖，克紹高宗。", "有儀有冊，載推載崇。", "鏤玉繩金，登奉祏宮。"]'),
('f2463aa8-2103-44fd-9a48-864d87e2159b','慶元三年奉上孝宗徽號三首 冊寶升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','文金晶熒，冊玉輝潤。',40,'全唐诗/poet.song.250000.json','["文金晶熒，冊玉輝潤。", "統紹乎堯，德全于舜。", "勤崇推高，子孝孫順。", "冠德百王，萬年垂訓。"]'),
('bdd4869b-e7ca-43f5-9bb8-e8b37914bf07','慶元三年奉上孝宗徽號三首 上徽號用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金石充庭，珩璜在列。',40,'全唐诗/poet.song.250000.json','["金石充庭，珩璜在列。", "繪畫乾坤，形容日月。", "巍巍功德，顯顯謨烈。", "垂億萬年，鴻徽昭揭。"]'),
('68f00825-d972-4c6d-9836-8a5311f83323','高宗郊祀前朝享太廟三十首 皇帝入門用《乾安》。後還前殿並同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇我后，祗戒專精。',40,'全唐诗/poet.song.250000.json','["於皇我后，祗戒專精。", "假于有廟，祖考是承。", "趨進惟肅，僾思惟誠。", "神之聽之，來燕來寧。"]'),
('8ea12ee0-89b0-4645-89fe-473e9350f2f7','高宗郊祀前朝享太廟三十首 皇帝升殿用《乾安》。詣室、降殿並同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇皇大宮，丕顯於穆。',40,'全唐诗/poet.song.250000.json','["皇皇大宮，丕顯於穆。", "休德昭清，元氣回復。", "芝葉蔓茂，桂華馮翼。", "孝孫假斯，受茲介福。"]'),
('c6ca5d70-21d2-4005-b198-2e3b87edb173','高宗郊祀前朝享太廟三十首 盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維皇齊精，鬷假于廟。',40,'全唐诗/poet.song.250000.json','["維皇齊精，鬷假于廟。", "觀盥之初，惟以潔告。", "衎承祖宗，恤祀昭孝。", "誠心有孚，介福斯報。"]'),
('e6103f87-b22f-4af1-afc5-ac896b13f4de','高宗郊祀前朝享太廟三十首 迎神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秬鬯既將，黄鍾具奏。',40,'全唐诗/poet.song.250000.json','["秬鬯既將，黄鍾具奏。", "肅我祖考，祗栗以俟。", "於皇列聖，在帝左右。", "監觀于茲，雲車來下。"]'),
('ef70877b-32e3-4763-8598-9d063c24a91a','高宗郊祀前朝享太廟三十首 尚書奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有碩其牲，登于大房。',40,'全唐诗/poet.song.250000.json','["有碩其牲，登于大房。", "肅展以享，庶幾迪嘗。", "匪腯是告，我民其康。", "保艾爾後，垂休無疆。"]'),
('fc6d097b-2dc1-4e51-a187-ec0828b6d581','高宗郊祀前朝享太廟三十首 皇帝再盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盥至于再，潔誠愈孚。',40,'全唐诗/poet.song.250000.json','["盥至于再，潔誠愈孚。", "帝用祗薦，靈咸嘉虞。", "騰歌臚歡，會于軒朱。", "觀厥顒若，受福之符。"]'),
('130a7265-8761-40ba-9b01-55ad73b1a768','高宗郊祀前朝享太廟三十首 僖祖室酌獻用《基命》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思文僖祖，基德之元。',40,'全唐诗/poet.song.250000.json','["思文僖祖，基德之元。", "皇武大之，受命于天。", "積厚流光，不已其傳。", "曾孫篤之，於萬斯年。"]'),
('b93c7193-eb16-4394-a95d-b7d3a2e03697','高宗郊祀前朝享太廟三十首 翼祖室酌獻用《大順》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天命有開，維仁是依。',40,'全唐诗/poet.song.250000.json','["天命有開，維仁是依。", "迺睠冀邦，于以顧之。", "其顧伊何，發祥肇基。", "施于孫子，虔奉孝思。"]'),
('7be0324c-a52f-4796-8f42-36f441c3d64c','高宗郊祀前朝享太廟三十首 宣祖室用《天元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昭哉皇祖，源深流長。',40,'全唐诗/poet.song.250000.json','["昭哉皇祖，源深流長。", "雕戈圭瓚，休有烈光。", "天祐潜德，繼世其昌。", "永懷積累，嘉薦令芳。"]'),
('bc90abd3-d395-46ae-abae-3f21c13466bc','高宗郊祀前朝享太廟三十首 太祖室用《皇武》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','爲民請命，皇祖赫臨。',40,'全唐诗/poet.song.250000.json','["爲民請命，皇祖赫臨。", "天地並貺，億萬同心。", "造邦以德，介福宜深。", "挹彼惟旨，真游居歆。"]'),
('ea7ef37b-e067-4591-a732-8bedbec099d9','高宗郊祀前朝享太廟三十首 太宗室用《大定》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇矣太宗，嗣服平成。',40,'全唐诗/poet.song.250000.json','["皇矣太宗，嗣服平成。", "益奮神旅，再征不庭。", "文武秉德，仁孝克明。", "以聖傳聖，對越紫清。"]'),
('8edfa02e-d677-4f81-9107-f9144d1495a8','高宗郊祀前朝享太廟三十首 真宗室用《熙文》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思文真宗，體道之崇。',40,'全唐诗/poet.song.250000.json','["思文真宗，體道之崇。", "憺威赫靈，遵制揚功。", "真符鼎來，告成登封。", "盛德百世，於昭無窮。"]'),
('d1ea159a-ce2f-40ee-a5a8-936064270ce7','高宗郊祀前朝享太廟三十首 仁宗室用《美成》。徽宗御製。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','仁德如天，徧覆無偏。',40,'全唐诗/poet.song.250000.json','["仁德如天，徧覆無偏。", "功濟九有，恩涵八埏。", "齊民受康，朝野晏然。", "擊壤歌謠，四十二年。"]'),
('c1d61649-328b-4343-bdbc-0d235df8becc','高宗郊祀前朝享太廟三十首 英宗室用《治隆》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆英宗，持盈守成。',40,'全唐诗/poet.song.250000.json','["穆穆英宗，持盈守成。", "世德作求，是纘是承。", "齊家睦族，偃武恢文。", "於薦清酤，酌之欣欣。"]'),
('803e6a6f-d10d-4bbd-a712-8e64fec49dae','高宗郊祀前朝享太廟三十首 神宗室用《大明》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','烝哉維后，繼明體神。',40,'全唐诗/poet.song.250000.json','["烝哉維后，繼明體神。", "稽古行道，文物一新。", "潤色鴻業，垂裕後人。", "靈斿沛然，來燕來寧。"]'),
('b989a351-d348-4554-b702-2ed90beb3d00','高宗郊祀前朝享太廟三十首 哲宗室用《重光》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明哲煌煌，照臨無疆。',40,'全唐诗/poet.song.250000.json','["明哲煌煌，照臨無疆。", "紹述先志，寔宣重光。", "詒謀燕翼，率由舊章。", "苾芬孝祀，降福穰穰。"]'),
('71049a4e-09bf-4c71-81e4-3159cd902555','高宗郊祀前朝享太廟三十首 徽宗室用《承元》。御製。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇烈考，道化聖神。',40,'全唐诗/poet.song.250000.json','["於皇烈考，道化聖神。", "堯聰舜孝，文恬武忻。", "命子出震，遺駿上賓。", "罔極之哀，有古莫倫。"]'),
('e83acdf5-d756-4e39-bfd6-9e8ab57de467','高宗郊祀前朝享太廟三十首 降殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明德惟馨，進止回復。',40,'全唐诗/poet.song.250000.json','["明德惟馨，進止回復。", "裼襲安恭，嚴若惟谷。", "誠意昭融，羣工袂屬。", "成此祲容，生乎齊肅。"]'),
('9b2fc848-4916-4ffb-958a-acc300b84fb9','高宗郊祀前朝享太廟三十首 入小次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇我后，祗戒專精。',40,'全唐诗/poet.song.250000.json','["於皇我后，祗戒專精。", "躬製聲詩，文思聰明。", "雍容戾止，玉立端誠。", "神聽如在，福祿來寧。"]'),
('1639a6a1-8da8-4b8f-ba34-58367fc139dd','高宗郊祀前朝享太廟三十首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','八音諧律，綴兆充庭。',40,'全唐诗/poet.song.250000.json','["八音諧律，綴兆充庭。", "進旅退旅，肅恭和平。", "盛薦祖宗，靈監昭升。", "象功崇德，遹觀厥成。"]'),
('c118e1e0-e4c6-4fcc-bd6a-55b8c4128d12','高宗郊祀前朝享太廟三十首 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','威神在天，享于克誠。',40,'全唐诗/poet.song.250000.json','["威神在天，享于克誠。", "申以貳觴，式昭德馨。", "籩豆孔嘉，樂舞具陳。", "庶幾是聽，福祿來成。"]'),
('84145a65-97a4-4bac-82fb-a74aec7b9a1e','高宗郊祀前朝享太廟三十首 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','疏冪三舉，誠意一純。',40,'全唐诗/poet.song.250000.json','["疏冪三舉，誠意一純。", "孰陪予祀，公族振振。", "神具醉止，燕娭窈冥。", "於萬斯年，綏我思成。"]'),
('bc47cfe5-6e59-4eb7-9d88-20e2fc37bd01','高宗郊祀前朝享太廟三十首 皇帝出小次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夙戒告備，禮節俯成。',40,'全唐诗/poet.song.250000.json','["夙戒告備，禮節俯成。", "妥侑惟乾，氛氳夜澄。", "有嚴有翼，列聖靈承。", "於穆清閟，肅肅無聲。"]'),
('8ee2ed1c-9142-4cb1-940c-1d4a46c64fbd','高宗郊祀前朝享太廟三十首 皇帝再升位詣飲福位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維皇親享，至再至三。',40,'全唐诗/poet.song.250000.json','["維皇親享，至再至三。", "禮備樂奏，層陛森嚴。", "粢盛芳潔，酒醴旨甘。", "雲車風馬，從衛觀瞻。"]'),
('3c23b354-0d70-4dfc-96eb-0b6dccdbd708','高宗郊祀前朝享太廟三十首 飲福用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫明明，維祖維宗。',40,'全唐诗/poet.song.250000.json','["赫赫明明，維祖維宗。", "鑒于文孫，維德之同。", "日靖四方，亦同其功。", "億萬斯年，以承家邦。"]'),
('8a229dc0-c4ed-4828-a43e-578048dbd799','高宗郊祀前朝享太廟三十首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝既臨享，步武鳴鸞。',40,'全唐诗/poet.song.250000.json','["帝既臨享，步武鳴鸞。", "陟降規矩，顒昂周旋。", "登歌一再，典禮莫愆。", "神之聽之，祉福綿綿。"]'),
('6c90282e-7de0-4d9b-add4-ee4cb899d2c9','高宗郊祀前朝享太廟三十首 尚書徹豆用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','熙事既成，嘉籩告徹。',40,'全唐诗/poet.song.250000.json','["熙事既成，嘉籩告徹。", "洋洋來臨，藹藹布列。", "配帝其功，在天對越。", "允集叢釐，萬邦和悅。"]'),
('1d39a63e-35be-4fe7-94a4-08204ca23547','高宗郊祀前朝享太廟三十首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之來游，風馬雲車。',40,'全唐诗/poet.song.250000.json','["神之來游，風馬雲車。", "淹留彷彿，顧瞻欷歔。", "神之還歸，鈞天帝居。", "監觀于下，何福不除。"]'),
('c04650ff-1da5-4efa-af27-9e26231b13ae','高宗郊祀前朝享太廟三十首 降殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇上天，欽哉成命。',40,'全唐诗/poet.song.250000.json','["於皇上天，欽哉成命。", "集于沖人，丕承列聖。", "爰熙紫壇，于廟告慶。", "肸蠁潜通，休祥荐應。"]'),
('3fde60b4-c376-429c-bed5-1c3daee4b931','高宗郊祀前朝享太廟三十首 還大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盛德豐功，一祖六宗。',40,'全唐诗/poet.song.250000.json','["盛德豐功，一祖六宗。", "欽翼燕詒，禋享是崇。", "厲意齊精，假廟惟恭。", "率禮周旋，福祿來同。"]'),
('94ee003f-72d7-4d55-b4c1-cbad740d717a','寧宗朝享三十五首 皇帝入門用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','王假有廟，四極駿奔。',40,'全唐诗/poet.song.250000.json','["王假有廟，四極駿奔。", "鼎俎宵嚴，簴簨雲屯。", "積厚流廣，德隆慶蕃。", "是則是繩，保我子孫。"]'),
('aef3e6e9-d832-487c-afb2-c6ce8a014246','寧宗朝享三十五首 升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆清宮，奕奕孔碩。',40,'全唐诗/poet.song.250000.json','["於穆清宮，奕奕孔碩。", "芝莖蔓秀，桂華馮翼。", "八簋登列，六瑚賁室。", "皇代擁慶，啟佑千億。"]'),
('73583ef2-e210-441a-956b-f95e405041d9','寧宗朝享三十五首 盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天一以清，地一以寧。',40,'全唐诗/poet.song.250000.json','["天一以清，地一以寧。", "維皇精專，承神明靈。", "娥御墮津，瀆祇揚溟。", "盥事允嚴，先祖是聽。"]'),
('6b5dd159-ab3e-4346-8d80-16d087d1acba','寧宗朝享三十五首 詣室用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','丹楹雲深，芳勺宵奠。',40,'全唐诗/poet.song.250000.json','["丹楹雲深，芳勺宵奠。", "樂華淳鬯，禮文炳絢。", "有容有儀，載肅載見。", "維時緝熙，世世以燕。"]'),
('35467b3c-3d3f-424e-9037-844569c3fb0e','寧宗朝享三十五首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','旅楹有閑，人神允叶。',40,'全唐诗/poet.song.250000.json','["旅楹有閑，人神允叶。", "福以德昭，饗以誠接。", "六樂宣揚，百禮煒燁。", "對越在天，流祚萬葉。"]'),
('5da1d25e-0af9-4622-87ba-f3270b4a7361','寧宗朝享三十五首 迎神用《興安》。九變。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲宮〕咸英備樂，簋席列斝。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲宮〕咸英備樂，簋席列斝。", "詩歌安世，聲叶皇雅。", "翠旗羽蓋，雲車風馬。", "神其來兮，以燕以下。"]'),
('8011064f-6727-45b2-9b5b-5c30083a205e','寧宗朝享三十五首 迎神用《興安》。九變。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔大呂爲角〕勾陳旦闢，閶闔夜分。',46,'全唐诗/poet.song.250000.json','["〔大呂爲角〕勾陳旦闢，閶闔夜分。", "軫風挾月，車駟凌雲。", "瑞景晻靄，神光耀熅。", "神其來兮，以留以忻。"]'),
('9e165199-0f6e-4681-b44b-bce0cdcceff1','寧宗朝享三十五首 迎神用《興安》。九變。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕穆穆紫幄，璜璜清宮。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕穆穆紫幄，璜璜清宮。", "旱麓流詠，鳧鷖叶工。", "道閎詒燕，業綿垂鴻。", "神其來兮，以康以崇。"]'),
('fcb73125-5ea0-4b94-bb0f-8164de30d22c','寧宗朝享三十五首 迎神用《興安》。九變。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔應鍾爲羽〕文以謨顯，武以烈承。',46,'全唐诗/poet.song.250000.json','["〔應鍾爲羽〕文以謨顯，武以烈承。", "聖訓之保，祖武之繩。", "有肅孝假，式嚴衎烝。", "神其來兮，以宜以寧。"]'),
('50ade0df-0fcf-4e72-8bd9-919737915ef0','寧宗朝享三十五首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','簋豆薦牲，鉶籩實饋。',40,'全唐诗/poet.song.250000.json','["簋豆薦牲，鉶籩實饋。", "其俎孔庶，吉蠲爲饎。", "惟德達馨，以忱以貴。", "神既佑享，祉貺來暨。"]'),
('3ded73a3-6401-4dc2-a9a3-3fcb54efd5ca','寧宗朝享三十五首 再詣盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','精粹象天，明清鑒月。',40,'全唐诗/poet.song.250000.json','["精粹象天，明清鑒月。", "再御茲盥，益致其潔。", "齊容顒若，誠意洞徹。", "百禮允洽，率禮不越。"]'),
('39f0ff12-cadd-4c9c-87f9-c4f7c3eeb6c1','寧宗朝享三十五首 真宗室用《熙文》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天地熙泰，躋時昇平。',40,'全唐诗/poet.song.250000.json','["天地熙泰，躋時昇平。", "闡符建壇，聲容文明。", "君臣賡載，夷夏肅清。", "本支百世，持盈守成。"]'),
('020b07d3-64a9-48e9-ad05-afcec524d7e7','寧宗朝享三十五首 仁宗室用《美成》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','在宋四世，天子聖神。',40,'全唐诗/poet.song.250000.json','["在宋四世，天子聖神。", "用賢致治，約己裕民。", "海內富庶，裔夷肅賓。", "四十二年，堯舜之仁。"]'),
('15a28ca9-f29d-4ebb-ab0e-3638a1253ded','寧宗朝享三十五首 英宗室用《治隆》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明英后，仁孝儉恭。',40,'全唐诗/poet.song.250000.json','["明明英后，仁孝儉恭。", "丕顯丕承，增光祖宗。", "繼志述事，遵制揚功。", "萬邦作孚，盛德形容。"]'),
('35d0aa6c-f04b-4821-b25f-01793b26e2dc','寧宗朝享三十五首 神宗室用《大明》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','厲精基治，大哉乾剛。',40,'全唐诗/poet.song.250000.json','["厲精基治，大哉乾剛。", "信賞必罰，內修外攘。", "禮樂法理，號令文章。", "作新之功，度越百王。"]'),
('d76c6c92-c3d6-4489-a936-a40ae0d86ec7','寧宗朝享三十五首 哲宗室用《重光》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇我宋，世有哲明。',40,'全唐诗/poet.song.250000.json','["於皇我宋，世有哲明。", "元祐用人，遹駿有聲。", "紹述先志，思監于成。", "受天之祜，王配于京。"]'),
('44b821c6-2bf8-4072-b677-44a92917ca1d','寧宗朝享三十五首 徽宗室用《承元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝撫熙運，晏粲協期。',40,'全唐诗/poet.song.250000.json','["帝撫熙運，晏粲協期。", "禮明樂備，文恬武嬉。", "道光授受，謀深燕詒。", "駿命不易，子孫保之。"]'),
('fb0ed518-cda5-4f19-a960-ad25ea91869a','寧宗朝享三十五首 欽宗室用《端慶》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','顯顯令主，輝光日新。',40,'全唐诗/poet.song.250000.json','["顯顯令主，輝光日新。", "奉親以孝，綏下以仁。", "兢兢業業，誕保庶民。", "於穆不已，之德之純。"]'),
('2322bed7-97fa-4c3b-86c6-217d2e23f75e','寧宗朝享三十五首 高宗室用《大德》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昊天有命，中興復古。',40,'全唐诗/poet.song.250000.json','["昊天有命，中興復古。", "治定功成，修文偃武。", "德隆商宗，業閎漢祖。", "付託得人，系堯之緒。"]'),
('47158940-9194-4ba4-a91f-7e65c9a0358c','寧宗朝享三十五首 孝宗室用《大倫》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','藝祖有孫，聰睿神武。',40,'全唐诗/poet.song.250000.json','["藝祖有孫，聰睿神武。", "紹興受禪，歸尊于父。", "行道襲爵，百度修舉。", "聖德曰孝，光于千古。"]'),
('780ad680-2302-4a9b-8b62-2d8c9591fbf4','寧宗朝享三十五首 光宗室用《大和》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維宋洽熙，帝繼于理。',40,'全唐诗/poet.song.250000.json','["維宋洽熙，帝繼于理。", "萬姓厚生，三辰順軌。", "對時天休，以燕翼子。", "肅唱和聲，神其有喜。"]'),
('2fc0014b-7fdb-4d05-9b6f-10335ffc848a','寧宗朝享三十五首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','在周之庭，設業設簴。',40,'全唐诗/poet.song.250000.json','["在周之庭，設業設簴。", "酒醴惟醹，爾殽伊脯。", "帝觴畢勺，天步旋舉。", "丕顯丕承，念茲皇祖。"]'),
('39c76cc0-9767-459e-b61a-93082d7fe31f','寧宗朝享三十五首 降殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','黼幄蟬蜎，飈斿寧燕。',40,'全唐诗/poet.song.250000.json','["黼幄蟬蜎，飈斿寧燕。", "尊彝獻祼，瑚簋陳薦。", "眎儀天旋，淳音韶變。", "遹求厥寧，福祿流羨。"]'),
('5acb954d-4bbd-4886-8b8d-3e7154c133e4','寧宗朝享三十五首 入小次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇容肅祗，天步舒遲。',40,'全唐诗/poet.song.250000.json','["皇容肅祗，天步舒遲。", "對越惟恭，敬事不遺。", "陟降蒞止，永言孝思。", "上帝臨女，日監于茲。"]'),
('95084851-41c7-4688-8c21-6f81753f2db1','寧宗朝享三十五首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明庭承神，鞉磬柷敔。',40,'全唐诗/poet.song.250000.json','["明庭承神，鞉磬柷敔。", "玉梢飾歌，佾綴維旅。", "既肖厥文，復象乃武。", "祖德宗功，惟帝時舉。"]'),
('0d2fef0b-2df4-494e-bce9-6b04b7d327b6','寧宗朝享三十五首 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','尊斝星陳，罍冪雲舒。',40,'全唐诗/poet.song.250000.json','["尊斝星陳，罍冪雲舒。", "來貳鸞觴，玉佩瓊琚。", "相予嚴祀，秉德有初。", "對揚王休，何福不除。"]'),
('eb1ab555-4e84-4eeb-8ace-3e141b9e541e','寧宗朝享三十五首 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秉德翼翼，顯相肅雝。',40,'全唐诗/poet.song.250000.json','["秉德翼翼，顯相肅雝。", "疏冪三舉，誠意益恭。", "光燭黼繡，和流笙鏞。", "子孫衆多，福祿來從。"]'),
('05bdfcdb-0a63-429a-ab88-da6107f94ef9','寧宗朝享三十五首 出小次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','廟楹邃嚴，夜景藻清。',40,'全唐诗/poet.song.250000.json','["廟楹邃嚴，夜景藻清。", "文物炳彪，禮儀熙成。", "帷宮載敞，珮珩有聲。", "帝復對越，將受厥明。"]'),
('7e6a77f4-8561-4686-a232-3ccb130d6ff9','寧宗朝享三十五首 再升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明維后，詒厥孫謀。',40,'全唐诗/poet.song.250000.json','["明明維后，詒厥孫謀。", "系隆我漢，陳錫哉周。", "以孝以饗，世德作求。", "介以繁祉，萬邦咸休。"]'),
('1c17b42f-18d9-45bc-820f-5e453e38a117','寧宗朝享三十五首 飲福用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉瓚黄流，有飶其香。',40,'全唐诗/poet.song.250000.json','["玉瓚黄流，有飶其香。", "來假來享，降福穰穰。", "我應受之，湯孫之將。", "有百斯男，福祿無疆。"]'),
('e8e1acac-da67-440f-b808-165d8e27fed7','寧宗朝享三十五首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖圖廣大，宗祊光輝。',40,'全唐诗/poet.song.250000.json','["聖圖廣大，宗祊光輝。", "假于有廟，帝命不違。", "僾若有慕，夙夜畏威。", "嘉樂君子，福祿祁祁。"]'),
('f267035c-aa07-4a8e-8542-11328449c9b3','寧宗朝享三十五首 徹豆用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','升饌有章，卒食攸序。',40,'全唐诗/poet.song.250000.json','["升饌有章，卒食攸序。", "庭鏘金奏，凱收鉶筥。", "其獻惟成，其餕維旅。", "禮洽慶流，皇祖之祜。"]'),
('eaf17665-d14e-4cd8-85cf-7f0881c3e3af','寧宗朝享三十五首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','珠幄熉黄，神既燕娭。',40,'全唐诗/poet.song.250000.json','["珠幄熉黄，神既燕娭。", "監觀于下，福祿來宜。", "雲車風馬，神保聿歸。", "啟佑我後，福祿來爲。"]'),
('32fab2ee-dde0-451b-96fc-c497d7b2177f','寧宗朝享三十五首 降殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖有謨訓，詒謀燕翼。',40,'全唐诗/poet.song.250000.json','["聖有謨訓，詒謀燕翼。", "奉天酌祖，萬世維則。", "維皇孝熙，乾乾夕惕。", "禮既式旋，惟福之錫。"]'),
('9d3a4321-0683-4721-9f92-3e0587d1c4d6','寧宗朝享三十五首 還大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','王假有廟，對越在天。',40,'全唐诗/poet.song.250000.json','["王假有廟，對越在天。", "帷宮旋御，率禮不愆。", "泰畤展祠，雲陽奉瑄。", "齊居精明，益用告虔。"]'),
('d2e384e5-e14e-4d73-b89d-218e86b299bc','理宗朝享三首 皇帝升降用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇祖宗，清廟奕奕。',40,'全唐诗/poet.song.250000.json','["於皇祖宗，清廟奕奕。", "威靈在天，不顯惟德。", "垂裕鴻延，詒謀燕翼。", "孝孫格斯，受祉罔極。"]'),
('e0379195-d62f-43bd-ac97-95c047e92a1a','理宗朝享三首 迎神用《興安》。九奏。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秬鬯既將，黄鍾具奏。',40,'全唐诗/poet.song.250000.json','["秬鬯既將，黄鍾具奏。", "瞻望真游，僾若有慕。", "於皇列聖，在帝左右。", "雲車具來，以妥以侑。"]'),
('61361d32-136d-4c77-b5c7-dcf8f2b77907','理宗朝享三首 寧宗室用《大安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝德之休，恭儉淵懿。',40,'全唐诗/poet.song.250000.json','["帝德之休，恭儉淵懿。", "三十一年，謹終如始。", "升祔在宮，祖功並美。", "民懷有仁，何千萬世。"]'),
('34eaa09b-7703-47df-b86b-c67b28bfbf63','高宗祀明堂前朝享太廟二十一首 皇帝入門用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇我后，祗戒專精。',40,'全唐诗/poet.song.250000.json','["於皇我后，祗戒專精。", "齊肅有容，祖考是承。", "造次匪懈，孝思純誠。", "神聽有格，福祿來寧。"]'),
('3ce75497-6ec6-4f89-a423-f46b9a27f626','高宗祀明堂前朝享太廟二十一首 升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅哉清宮，熉珠照幄。',40,'全唐诗/poet.song.250000.json','["肅哉清宮，熉珠照幄。", "神之來思，八音振作。", "赤舄龍章，奉玉惟恪。", "匪今斯今，先民時若。"]'),
('172f63b4-0d07-46ec-ba10-3bc18e4b10d8','高宗祀明堂前朝享太廟二十一首 盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇維后，觀盥之初。',40,'全唐诗/poet.song.250000.json','["於皇維后，觀盥之初。", "精意昭著，既順既愉。", "圭鬯承祀，卿士咸趨。", "目視心化，四方其孚。"]'),
('e9aef426-b86a-48b3-8d97-961f8dabed22','高宗祀明堂前朝享太廟二十一首 迎神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','涓選休成，祖考是享。',40,'全唐诗/poet.song.250000.json','["涓選休成，祖考是享。", "夙夜專精，求諸惚恍。", "洋洋在上，惟神之仰。", "鬯矣清明，應之如響。"]'),
('0eeb0d96-79cd-4f47-b5b7-8a453e3da07b','高宗祀明堂前朝享太廟二十一首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','來相于庭，鳴鋗鏘鏘。',40,'全唐诗/poet.song.250000.json','["來相于庭，鳴鋗鏘鏘。", "奉牲而告，登彼雕房。", "非牲之備，民庶是康。", "神依民聽，上帝斯皇。"]'),
('3c725a45-a8bc-4292-bfaf-d319483490a1','高宗祀明堂前朝享太廟二十一首 僖祖室酌獻用《基命》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','何慶之長，實兆于商。',40,'全唐诗/poet.song.250000.json','["何慶之長，實兆于商。", "由商太戊，子孫其昌。", "皇基成命，宋道用光。", "詒厥孫謀，膺受四方。"]'),
('55bd3a72-ecaf-40fd-a7f5-9cbf79bfa892','高宗祀明堂前朝享太廟二十一首 翼祖室用《大順》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上帝監觀，維仁是依。',40,'全唐诗/poet.song.250000.json','["上帝監觀，維仁是依。", "繼世修德，皇心顧之。", "其顧伊何，在彼冀方。", "施于子孫，降福穰穰。"]'),
('a3d6b3b3-4b2a-470f-9f2c-fe78e0db1bc4','高宗祀明堂前朝享太廟二十一首 宣祖室酌獻用《天元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昭哉皇祖，駿發其祥。',40,'全唐诗/poet.song.250000.json','["昭哉皇祖，駿發其祥。", "雕戈圭瓚，盛烈載揚。", "天錫寶符，俾熾而昌。", "神聖應期，赫然垂光。"]'),
('69512256-352f-478a-b875-cb2ea9cf5693','高宗祀明堂前朝享太廟二十一首 太祖室用《皇武》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗歟皇祖，下民攸歸。',40,'全唐诗/poet.song.250000.json','["猗歟皇祖，下民攸歸。", "膺帝之命，龍翔太微。", "戎車雷動，天地清夷。", "峨峨奉璋，萬世無違。"]'),
('97ae848c-879f-46e6-af3c-61687e446018','高宗祀明堂前朝享太廟二十一首 太宗室用《大定》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌神武，再御戎軒。',40,'全唐诗/poet.song.250000.json','["煌煌神武，再御戎軒。", "時惠南土，旋定太原。", "車書混同，聲教布宣。", "維天佑之，億萬斯年。"]'),
('50b47fef-ed00-42c2-b104-022eb402d145','高宗祀明堂前朝享太廟二十一首 真宗室用《熙文》。仁宗室曲同郊祀，送神亦同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇真宗，體道之崇。',40,'全唐诗/poet.song.250000.json','["於皇真宗，體道之崇。", "游心物外，應迹寰中。", "四方既同，化民以躬。", "清浄無爲，盛德之容。"]'),
('f5744ae8-0cf2-43d5-ab5e-046c9d2beadb','高宗祀明堂前朝享太廟二十一首 英宗室用《治隆》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','噫我大君，嗣世修文。',40,'全唐诗/poet.song.250000.json','["噫我大君，嗣世修文。", "維文維武，諟繼虞勳。", "天錫丕祚，施于後昆。", "於薦清酤，酌之欣欣。"]'),
('829221b2-97ec-456d-a54e-56e8f3c64b4c','高宗祀明堂前朝享太廟二十一首 神宗室用《大明》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','烝哉維后，繼明體神。',40,'全唐诗/poet.song.250000.json','["烝哉維后，繼明體神。", "憲章文武，宜民宜人。", "經世之道，功格于天。", "子孫嚴祀，無窮之傳。"]'),
('ef04f886-567c-4271-a87f-95c1e79d5dbe','高宗祀明堂前朝享太廟二十一首 哲宗室用《重光》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明哲煌煌，照臨無疆。',40,'全唐诗/poet.song.250000.json','["明哲煌煌，照臨無疆。", "丕承先志，嘉靖多方。", "朝廷尊榮，民庶樂康。", "珍符來應，錫茲重光。"]'),
('f66560d6-70d3-4f47-86ed-07da2eaf51a7','高宗祀明堂前朝享太廟二十一首 徽宗室用《承元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖考巍巍，光紹丕基。',40,'全唐诗/poet.song.250000.json','["聖考巍巍，光紹丕基。", "禮隆樂備，時維純熙。", "天仁兼覆，皇化無爲。", "功成弗處，心潜希夷。"]'),
('71e40868-98c0-4a44-ba3b-89e3bf36cdea','高宗祀明堂前朝享太廟二十一首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','作樂合祖，筍簴在庭。',40,'全唐诗/poet.song.250000.json','["作樂合祖，筍簴在庭。", "衆奏具舉，肅雝和鳴。", "神靈來格，庶幾是聽。", "皦繹以終，永觀厥成。"]'),
('8b037a84-f809-4d1a-a10d-e843a423086c','高宗祀明堂前朝享太廟二十一首 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','威神在天，來格于誠。',40,'全唐诗/poet.song.250000.json','["威神在天，來格于誠。", "既載清酤，有聞無聲。", "相予熙事，時頼宗英。", "肅肅雝雝，允協思成。"]'),
('677a603a-b10d-4e9f-bc38-b4a06d112a89','高宗祀明堂前朝享太廟二十一首 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','疏冪三舉，誠意一純。',40,'全唐诗/poet.song.250000.json','["疏冪三舉，誠意一純。", "孰陪予祀，公族振振。", "明靈來娭，樂舞具陳。", "奉神所佑，昭孝息民。"]'),
('40014352-bddd-452b-89a6-766b1436f66d','高宗祀明堂前朝享太廟二十一首 飲福用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫明明，德與天通。',40,'全唐诗/poet.song.250000.json','["赫赫明明，德與天通。", "施于孫子，福祿攸同。", "日靖四方，民和年豐。", "有秩斯祜，申錫無窮。"]'),
('61d21b7c-da0f-451e-8015-cc7b2a62307e','高宗祀明堂前朝享太廟二十一首 徹豆用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','歆我齊明，威德如存。',40,'全唐诗/poet.song.250000.json','["歆我齊明，威德如存。", "牲牷是享，圭玉其溫。", "羣公執事，亦既駿奔。", "禮成告徹，咸福黎元。"]'),
('dbe8679b-3d34-4e1c-8d64-6c4e6bd1467c','高宗祀明堂前朝享太廟二十一首 還大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神明既交，恍若有承。',40,'全唐诗/poet.song.250000.json','["神明既交，恍若有承。", "欽翼齊莊，福祿具膺。", "王業是興，祖武是繩。", "佑我億年，以莫不增。"]'),
('e60da377-5adf-401d-af5c-91a0aa1daaff','孝宗明堂前享太廟三首 徽宗室酌獻用《承元》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明徽祖，撫世升平。',40,'全唐诗/poet.song.250000.json','["明明徽祖，撫世升平。", "制禮作樂，發政施仁。", "聖靈在天，德澤在民。", "億萬斯年，保佑後人。"]'),
('28fb0668-b9cb-4121-bb28-a26c147ca009','孝宗明堂前享太廟三首 高宗室用《大德》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇時宋，自天保定。',40,'全唐诗/poet.song.250000.json','["於皇時宋，自天保定。", "高宗受之，再僕景命。", "紹開中興，翼善傳聖。", "何千萬年，永綏厥慶。"]'),
('91c4a5f2-ceb6-4d45-a3a6-cb967533ac8e','孝宗明堂前享太廟三首 還大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮既行矣，樂既成矣。',40,'全唐诗/poet.song.250000.json','["禮既行矣，樂既成矣。", "維祖維妣，安且寧矣。", "皇舉玉趾，佩鏘鳴矣。", "拜貺總章，于厥明矣。"]'),
('a534a25a-0213-49ac-8906-c67ef34ddd95','理宗明堂前朝享二首 寧宗室奠幣用《定安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇矣昭考，聖靈在天。',40,'全唐诗/poet.song.250000.json','["皇矣昭考，聖靈在天。", "稱秩宗祀，有嚴恭先。", "奉幣以薦，見之僾然。", "仁深澤厚，厥光以延。"]'),
('42068cb7-de29-4fda-9396-30825b069619','理宗明堂前朝享二首 酌獻用《考安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','假哉皇考，必世後仁。',40,'全唐诗/poet.song.250000.json','["假哉皇考，必世後仁。", "嘉靖我邦，與物皆春。", "之純之德，克配穹旻。", "餘慶淵如，佑我後人。"]'),
('3298a1ad-7440-4d1e-81f7-1f29a2089165','皇后廟十五首 迎神用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','閟宮翼翼，雅樂洋洋。',40,'全唐诗/poet.song.250000.json','["閟宮翼翼，雅樂洋洋。", "牲器肅設，几筵用張。", "飾以明備，秩其令芳。", "神兮來格，風動雲翔。"]'),
('2fd5de81-c091-4238-b56a-d94908992164','皇后廟十五首 太尉行用《舒安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','服章觀象，山龍是則。',20,'全唐诗/poet.song.250000.json','["服章觀象，山龍是則。", "容止蹌蹌，威儀翼翼。"]'),
('bcdb52a8-f7c4-4bfc-942c-04946cfcb945','皇后廟十五首 司徒捧俎用《豐安》。徹同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恪恭奉祀，祗薦犧牲。',20,'全唐诗/poet.song.250000.json','["恪恭奉祀，祗薦犧牲。", "九成爰奏，有俎斯盈。"]'),
('5e718d75-5807-49e8-9ac0-94bf7819655b','皇后廟十五首 酌獻孝明皇后室用《惠安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祀事孔明，廟室惟肅。',40,'全唐诗/poet.song.250000.json','["祀事孔明，廟室惟肅。", "鉶登籩豆，金石絲竹。", "既灌既薦，允恭允穆。", "奉神如在，以介景福。"]'),
('789287fc-d648-40b8-a889-231b5ae37069','皇后廟十五首 孝惠皇后室用《奉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','初陽作配，內助惟賢。',40,'全唐诗/poet.song.250000.json','["初陽作配，內助惟賢。", "柔順中積，英徽外宣。", "神宮有侐，明祀惟虔。", "歆誠降祐，於萬斯年。"]'),
('9b078805-f737-4b9a-88ac-5d1406b05d04','皇后廟十五首 孝章皇后室用《懿安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗那淑聖，象應資生。',40,'全唐诗/poet.song.250000.json','["猗那淑聖，象應資生。", "配天作合，與日齊明。", "椒宮垂範，彤史揚名。", "聿修毖祀，永奉粢盛。"]'),
('ee88206d-2bd7-411d-98d4-3e14f9d74903','皇后廟十五首 懿德皇后室用《順安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','王門稟慶，帝族惟賢。',40,'全唐诗/poet.song.250000.json','["王門稟慶，帝族惟賢。", "功存內治，德協靜專。", "流芳圖史，垂範紘綖。", "新廟有侐，祀禮昭然。"]'),
('eed177f5-eab4-4ecc-9ce5-d09f22162fbe','皇后廟十五首 淑德皇后室用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明英媛，德備椒庭。',40,'全唐诗/poet.song.250000.json','["明明英媛，德備椒庭。", "籩豆有踐，黍稷匪馨。", "靜嘉致薦，容與昭靈。", "精意以達，顧享來寧。"]'),
('33afb7f0-c113-4d9b-a0a2-16cfe6610bf3','皇后廟十五首 莊穆皇后室用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','曾孫襲慶，柔祇育德。',40,'全唐诗/poet.song.250000.json','["曾孫襲慶，柔祇育德。", "正位居體，其儀不忒。", "教被宮壺，化行邦國。", "祝史正辭，垂裕無極。"]'),
('167a031c-d443-424d-9a6e-feeb0f25cc2a','皇后廟十五首 莊懷皇后室用《永安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','淑德昭著，至樂和平。',40,'全唐诗/poet.song.250000.json','["淑德昭著，至樂和平。", "登豆在列，膋香薦誠。", "六變合禮，八音諧聲。", "穰穰景福，佑我休明。"]'),
('a5263841-b05b-4eec-a0c0-ee16b26b2457','皇后廟十五首 元德皇后室用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','爲太宗后，爲天下母。',40,'全唐诗/poet.song.250000.json','["爲太宗后，爲天下母。", "誕聖繼明，膺乾作主。", "玉振金相，蘭芬桂芳。", "於萬斯年，永奉烝嘗。"]'),
('8441087d-fbf6-4ad9-a52c-4928d94e5b47','皇后廟十五首 飲福用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彝尊鬯酒，慶佑遂行。',20,'全唐诗/poet.song.250000.json','["彝尊鬯酒，慶佑遂行。", "介以純嘏，允答明誠。"]'),
('7f3a16f7-eba7-419b-b3b0-bc701a2f3f5f','皇后廟十五首 亞獻用《恭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宗臣率禮，步玉鏘鏘。',20,'全唐诗/poet.song.250000.json','["宗臣率禮，步玉鏘鏘。", "吉蠲斯獻，百祿是將。"]'),
('a725e71b-a050-4b7d-a698-e7d988556b43','皇后廟十五首 終獻用《順安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','薦獻有終，禮容斯穆。',20,'全唐诗/poet.song.250000.json','["薦獻有終，禮容斯穆。", "以奉嘉觴，以膺多福。"]'),
('fbbdbb7d-e6bc-42f0-9dbf-4af8b169819a','皇后廟十五首 送神用《歸安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明禋告畢，靈輅難留。',40,'全唐诗/poet.song.250000.json','["明禋告畢，靈輅難留。", "升雲杳邈，整馭優游。", "誠深嘉栗，禮罄欽修。", "豐融垂佑，以永洪休。"]'),
('17b44d26-9402-46da-ab2c-039099b114f9','景祐以後樂章六首 章獻明肅皇太后室奠瓚用《達安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅閟宮，順時薦事。',20,'全唐诗/poet.song.250000.json','["肅肅閟宮，順時薦事。", "鬰鬯馨香，如見於位。"]'),
('43b339e4-ba65-4fcf-9ce9-72734614e7ad','景祐以後樂章六首 酌獻用《厚安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祥標曾麓，德合方儀。',40,'全唐诗/poet.song.250000.json','["祥標曾麓，德合方儀。", "萬邦展養，九御蒙慈。", "孝恭祊祏，美播聲詩。", "淑靈顧享，申錫維祺。"]'),
('c5c1c028-2eca-47ca-bd90-e10de1ce74be','景祐以後樂章六首 章懿皇太后室奠瓚用《報安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','青金玉瓚，祼將于京。',20,'全唐诗/poet.song.250000.json','["青金玉瓚，祼將于京。", "永懷罔極，夙夜齊明。"]'),
('284e827b-3e81-4cf9-9623-727ec124faf7','景祐以後樂章六首 酌獻用《衍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','翊佐先朝，章明壺教。',40,'全唐诗/poet.song.250000.json','["翊佐先朝，章明壺教。", "淑順謙勤，徽音在劭。", "樹風不止，劬勞匪報。", "黍稷令芳，嘏茲乃告。"]'),
('b2a5c446-0e91-4993-8df5-64e6b6b79978','景祐以後樂章六首 奉慈廟章惠皇太后室奠瓚用《翕安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祼圭既陳，酌鬯斯醇。',20,'全唐诗/poet.song.250000.json','["祼圭既陳，酌鬯斯醇。", "音容彷彿，奠獻惟寅。"]'),
('e1d9c41b-b071-4915-92d2-f45c9807f529','景祐以後樂章六首 酌獻用《昌安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','內輔先猷，夙昭壺則。',40,'全唐诗/poet.song.250000.json','["內輔先猷，夙昭壺則。", "保祐之勞，慈惠其德。", "榮養有終，芳風無極。", "享獻閟宮，載懷悽惻。"]'),
('66ef442b-d449-4a72-9a9e-9d2bf64060d7','真宗汾陰禮畢親謝元德皇后室三首 迎神用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','閟宮奕奕，韶樂洋洋。',40,'全唐诗/poet.song.250000.json','["閟宮奕奕，韶樂洋洋。", "牲幣虔布，几筵肅張。", "醴泉淳美，嘉肴潔香。", "俟神來格，降彼帝鄉。"]'),
('efeac86b-23ef-406d-8731-cd76355f758e','真宗汾陰禮畢親謝元德皇后室三首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','樂鏗金石，俎奉犧牲。',20,'全唐诗/poet.song.250000.json','["樂鏗金石，俎奉犧牲。", "九成斯奏，五教爰行。"]'),
('70d410bf-b51e-4d88-8b56-da872661aae5','真宗汾陰禮畢親謝元德皇后室三首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鸞驂復整，鶴駕難留。',40,'全唐诗/poet.song.250000.json','["鸞驂復整，鶴駕難留。", "白雲縹緲，紫府深幽。", "廟雖載止，神無不游。", "垂佑皇宋，以永鴻休。"]'),
('3ff08219-6ce7-41bc-900e-e14575eba4ec','元德皇后升祔一首 《顯安之曲》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','顯矣皇妣，德侔柔祇。',40,'全唐诗/poet.song.250000.json','["顯矣皇妣，德侔柔祇。", "升祔太室，協禮之宜。", "耀彼寶冊，列之尊彝。", "惟誠是厚，永佑慶基。"]'),
('7ae034b6-3b77-4359-a1d0-4ff33026e1c6','崇恩太后升祔十四首 入門用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','俔天生德，作配元符。',40,'全唐诗/poet.song.250000.json','["俔天生德，作配元符。", "儀刑壺則，輔佐帝圖。", "登崇廟祏，勒號璠璵。", "烝嘗億載，皇極之扶。"]'),
('01a8e158-964f-4ced-933a-23457013038c','崇恩太后升祔十四首 神主升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','曰嬪于京，天作之配。',40,'全唐诗/poet.song.250000.json','["曰嬪于京，天作之配。", "進賢審官，克勤其志。", "於穆清廟，本仁祖義。", "億萬斯年，神靈攸暨。"]'),
('2a996b03-bd22-47b3-82bc-851538ada4ed','崇恩太后升祔十四首 迎神用《興安》。四章。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾宮二奏〕閟宮有侐，堂筵屹崇。',47,'全唐诗/poet.song.250000.json','["〔黄鍾宮二奏〕閟宮有侐，堂筵屹崇。", "靈徽匪遐，精誠感通。", "苾芬維時，登茲明祀。", "泠然雲車，有來其馭。"]'),
('43282b88-7dc8-4542-afe6-0985c75cc5b3','崇恩太后升祔十四首 迎神用《興安》。四章。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔大呂角二奏〕羽旌風翔，翠蕤飄舉。',47,'全唐诗/poet.song.250000.json','["〔大呂角二奏〕羽旌風翔，翠蕤飄舉。", "儼其音徽，登茲位處。", "笙鏞始奏，合止柷敔。", "是享是宜，永求伊祜。"]'),
('ce991fb4-8e8c-4dfd-851e-b0db4be29f31','崇恩太后升祔十四首 迎神用《興安》。四章。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇徵二奏〕枚枚閟宮，鼎俎肆陳。',47,'全唐诗/poet.song.250000.json','["〔太簇徵二奏〕枚枚閟宮，鼎俎肆陳。", "烝畀明靈，登其嘉新。", "鼓鍾既戒，旨酒既醇。", "攸介攸止，純禧荐臻。"]'),
('39fd5bc4-5f02-4d75-a017-2c68aeabf7ad','崇恩太后升祔十四首 迎神用《興安》。四章。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔應鍾羽二奏〕旨酒嘉肴，于登于豆。',47,'全唐诗/poet.song.250000.json','["〔應鍾羽二奏〕旨酒嘉肴，于登于豆。", "是享是宜，樂既合奏。", "衎我懿德，執事溫恭。", "靈兮允格，有翼其從。"]'),
('5d5a8314-5621-40cb-bfde-6d3420dc5b1a','崇恩太后升祔十四首 罍洗用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','列爵陳俎，芬芳和羹。',40,'全唐诗/poet.song.250000.json','["列爵陳俎，芬芳和羹。", "摐金擊石，洋洋和聲。", "禮行伊始，我德惟明。", "既盥而往，於昭斯誠。"]'),
('21acfffe-7b4d-4fc5-9e5e-7dae5b5f5805','崇恩太后升祔十四首 升降殿用《熙安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','笙簫紛如，陟彼廟庭。',40,'全唐诗/poet.song.250000.json','["笙簫紛如，陟彼廟庭。", "鏘鏘佩玉，懷茲先靈。", "神保聿止，音容杳冥。", "繁禧是介，萬年惟寧。"]'),
('6b513622-dc9e-40a2-a52f-69b3084a5de8','崇恩太后升祔十四首 酌獻用《茲安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雝雝玉佩，清酤惟良。',40,'全唐诗/poet.song.250000.json','["雝雝玉佩，清酤惟良。", "粢盛具列，有飶其香。", "懷其徽範，德洽無疆。", "於茲燕止，降福穰穰。"]'),
('4cbc73dc-723f-4f29-8fc6-a216dec225e4','崇恩太后升祔十四首 亞獻用《神安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嬪于潜邸，爰正坤儀。',40,'全唐诗/poet.song.250000.json','["嬪于潜邸，爰正坤儀。", "關雎化被，思齊名垂。", "柔德益茂，家邦以熙。", "皇心追崇，永羞牲粢。"]'),
('60919b38-fdda-4b8c-ab96-822e5844a0f5','崇恩太后升祔十四首 退文舞、進武舞用《昭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','翩然干戚，揚庭陳階。',40,'全唐诗/poet.song.250000.json','["翩然干戚，揚庭陳階。", "文以經緯，武以威懷。", "其張其弛，節與音諧。", "迄茲獻享，妥靈綏來。"]'),
('e98252d1-d840-46fd-8d5c-4316bd6c2dc1','崇恩太后升祔十四首 終獻用《儀安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','珩璜之貴，褘褕之尊。',40,'全唐诗/poet.song.250000.json','["珩璜之貴，褘褕之尊。", "天作之合，內治慈溫。", "元良鍾慶，祉福乾坤。", "以享以祀，事亡如存。"]'),
('1e5d2124-8f56-4495-83c4-9f3d1433e5f6','崇恩太后升祔十四首 徹豆用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鏘洋純繹，於論鼓鍾。',40,'全唐诗/poet.song.250000.json','["鏘洋純繹，於論鼓鍾。", "周旋陟降，齊莊肅容。", "維罍既旨，維籩伊豐。", "歌徹以雍，介福來崇。"]'),
('630fee05-791e-4abd-bea9-11938398b110','崇恩太后升祔十四首 送神用《興安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','黍稷維馨，虡業充庭。',40,'全唐诗/poet.song.250000.json','["黍稷維馨，虡業充庭。", "既欽既戒，靈心是承。", "顧予烝嘗，言從之邁。", "申錫無疆，是用大介。"]'),
('b933a22d-6860-4a78-b409-7bd498d2f760','上冊寶十三首 冊寶入門用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','威儀皇止，庶尹在庭。',40,'全唐诗/poet.song.250000.json','["威儀皇止，庶尹在庭。", "爰舉徽章，遹觀厥成。", "勒崇揚休，寫之瓊瑛。", "迄于萬祀，發聞惟馨。"]'),
('6e3c6de2-9486-4a2f-aa44-53461d3bb53b','上冊寶十三首 冊寶升殿用《崇安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有猶有言，順承天則。',40,'全唐诗/poet.song.250000.json','["有猶有言，順承天則。", "聿崇號名，再揚典冊。", "朱英寶函，左右翼翼。", "千秋萬歲，保茲無極。"]'),
('c49763a1-2151-4554-ac67-5607f27e7dd7','上冊寶十三首 迎神用《歆安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾宮〕籩豆大房，犧尊將將。',45,'全唐诗/poet.song.250000.json','["〔黄鍾宮〕籩豆大房，犧尊將將。", "馨香既登，明靈迪嘗。", "其樂伊何，吹笙鼓簧。", "靈來燕娭，降福無疆。"]'),
('61feab05-b0b1-4bc6-a354-18cc79bc5aea','上冊寶十三首 迎神用《歆安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔大呂角二奏〕吉蠲惟時，禮儀既備。',47,'全唐诗/poet.song.250000.json','["〔大呂角二奏〕吉蠲惟時，禮儀既備。", "奉璋峨峨，羣公在位。", "神之格思，永錫爾類。", "展彼令德，於焉來暨。"]'),
('d2d8178e-a4dc-4e53-ac69-a31932ba53f6','上冊寶十三首 迎神用《歆安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇徵二奏〕雍雍在宮，翼翼在庭。',47,'全唐诗/poet.song.250000.json','["〔太簇徵二奏〕雍雍在宮，翼翼在庭。", "顯相休嘉，肅雍和鳴。", "神嗜飲食，明德惟馨。", "綏我思成，式燕以寧。"]'),
('278c7659-d4a6-4e86-a875-ce1eeff7b4b6','上冊寶十三首 迎神用《歆安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔應鍾羽二奏〕犧牲既成，籩豆有楚。',47,'全唐诗/poet.song.250000.json','["〔應鍾羽二奏〕犧牲既成，籩豆有楚。", "摐金擊石，式歌且舞。", "追懷懿德，令聞令儀。", "靈兮來格，是享是宜。"]'),
('eb0214ae-3f74-4400-b9d0-11a7ccb4403a','上冊寶十三首 罍洗用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉肴旨酒，潔粢豐盛。',40,'全唐诗/poet.song.250000.json','["嘉肴旨酒，潔粢豐盛。", "既盥而往，以我齊明。", "有孚顒若，黍稷非馨。", "神之格思，享于克誠。"]'),
('9011ffd4-2f25-44ea-bd75-8f4dab6eb2bd','上冊寶十三首 升降用《熙安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','佩玉鏘鏘，其來雝雝。',40,'全唐诗/poet.song.250000.json','["佩玉鏘鏘，其來雝雝。", "陟降孔時，步武有容。", "恪茲祀事，神罔時恫。", "綏我邦家，福祿來崇。"]'),
('173e806f-d58a-4387-97b2-d9e4e60da597','上冊寶十三首 酌獻用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','旨酒嘉栗，有飶其香。',40,'全唐诗/poet.song.250000.json','["旨酒嘉栗，有飶其香。", "衎我淑靈，歆此令芳。", "德貽彤管，號正椒房。", "神具醉止，降福穰穰。"]'),
('e1e0c32c-0d96-4ce1-967e-afefedb334bd','上冊寶十三首 退文舞、進武舞用《昭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','籥翟既陳，干戚斯揚。',40,'全唐诗/poet.song.250000.json','["籥翟既陳，干戚斯揚。", "進旅退旅，一弛一張。", "其儀不忒，容服有光。", "以宴以娭，德音不忘。"]'),
('20362afb-e687-46ea-9507-35d936325766','上冊寶十三首 亞、終獻用《和安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','望高六宮，位應四星。',40,'全唐诗/poet.song.250000.json','["望高六宮，位應四星。", "輔佐君子，警戒相成。", "褘衣褒崇，琛冊追榮。", "于以奠之，有椒其馨。"]'),
('5bb9a6fc-5082-44e8-bc1d-28a04a7c591a','上冊寶十三首 徹豆用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','濯濯其英，殖殖其庭。',40,'全唐诗/poet.song.250000.json','["濯濯其英，殖殖其庭。", "有來羣工，賚我思成。", "嘉肴既將，旨酒既清。", "雍徹不遲，福祿來寧。"]'),
('b911135f-b719-4ca8-84df-760d9de129c7','上冊寶十三首 送神用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮儀既備，神保聿歸。',40,'全唐诗/poet.song.250000.json','["禮儀既備，神保聿歸。", "洋洋在上，不可度思。", "神之來兮，肸蠁之隨。", "神之去兮，休嘉是貽。"]'),
('a14ad5c8-940d-4558-b180-d05c649936cc','上欽成皇后冊寶六首 入門、升殿用《顯安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上帝錫羨，寔生婉淑。',40,'全唐诗/poet.song.250000.json','["上帝錫羨，寔生婉淑。", "輔佐神皇，寵膺天祿。", "誕育泰陵，劬勞顧復。", "於昭徽音，久而彌郁。"]'),
('b7a80fa4-a564-4167-b72b-4733d0f9deca','上欽成皇后冊寶六首 迎神用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於顯惟德，徽柔懿明。',40,'全唐诗/poet.song.250000.json','["於顯惟德，徽柔懿明。", "嬪于初載，有聞惟馨。", "肆我鼓鍾，萬舞在庭。", "神保是格，來止來寧。"]'),
('fbe237b4-bebd-4000-b004-5894260211bf','上欽成皇后冊寶六首 盥洗用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有煒柔儀，率履不越。',40,'全唐诗/poet.song.250000.json','["有煒柔儀，率履不越。", "惠于初終，既明且達。", "我將我享，相盥乃登。", "胡臭亶時，攸介攸寧。"]'),
('be67d7f3-1d95-47b4-b161-51f92dcfbfff','上欽成皇后冊寶六首 升降用《熙安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','苾苾其芳，殽核維旅。',40,'全唐诗/poet.song.250000.json','["苾苾其芳，殽核維旅。", "陟降孔時，有秩斯所。", "雍容內化，維神之明。", "明則不渝，綏我思成。"]'),
('f7e2b465-9254-4d9b-97c6-85defa034f3d','上欽成皇后冊寶六首 酌獻用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天維顯思，有相于內。',40,'全唐诗/poet.song.250000.json','["天維顯思，有相于內。", "右賢去邪，夙夜儆戒。", "猗歟追冊，重翟褘衣。", "既右享之，百世是儀。"]'),
('00960896-86c9-4ff9-9c84-1a0da5d70bc1','上欽成皇后冊寶六首 亞、終獻用《和安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','酌彼玉瓚，有椒其馨。',40,'全唐诗/poet.song.250000.json','["酌彼玉瓚，有椒其馨。", "鬷假無言，雍容在庭。", "生莫與崇，於赫厥聲。", "祀事孔明，神格是聽。"]'),
('785dd0df-88ed-4b70-9b92-1f7f67b8ad9f','上明達皇后冊寶五首 迎神用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恭儉宜家，柔順承天。',40,'全唐诗/poet.song.250000.json','["恭儉宜家，柔順承天。", "德昭彤管，憂在進賢。", "寶冊褘翟，追榮壽原。", "四時祼享，何千萬年。"]'),
('dfd9fae8-0197-4944-b5e3-e50b8cbdcc12','上明達皇后冊寶五首 酌獻用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','清宮有嚴，廣樂在庭。',40,'全唐诗/poet.song.250000.json','["清宮有嚴，廣樂在庭。", "鍾鼓筦磬，九變既成。", "縮茅以獻，潔秬惟馨。", "靈遊可想，來燕來寧。"]'),
('cb1fca5e-7300-49bf-8ede-9f7656849219','上明達皇后冊寶五首 退文舞、進武舞用《昭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秉翟竣事，萬舞摐金。',40,'全唐诗/poet.song.250000.json','["秉翟竣事，萬舞摐金。", "總干揮戚，節以鼓音。", "禮容有煒，肸蠁來歆。", "淑靈是聽，雅奏愔愔。"]'),
('d528e1a6-abfa-4a34-9d48-37041af27cb9','上明達皇后冊寶五首 徹豆用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','登獻罔愆，俎豆斯徹。',40,'全唐诗/poet.song.250000.json','["登獻罔愆，俎豆斯徹。", "神具醉止，禮終樂闋。", "御事既退，珊珊佩玦。", "介我繁祉，歆此蠲潔。"]'),
('759671be-7c87-4ac5-b464-da323de7cc66','上明達皇后冊寶五首 送神用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','備成熙事，虛徐翠楹。',40,'全唐诗/poet.song.250000.json','["備成熙事，虛徐翠楹。", "神保聿歸，雲車夙征。", "鑒我休德，神交惚恍。", "留祉降祥，千秋是享。"]'),
('c908cb8d-e339-4f8f-af28-1be8baa4cc18','紹興別廟樂歌五首 升殿用《崇安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','新廟肅肅，蕆事以時。',40,'全唐诗/poet.song.250000.json','["新廟肅肅，蕆事以時。", "陟降階墄，雍容有儀。", "鞠躬周旋，罔敢不祗。", "祝史正辭，靈其格思。"]'),
('9dd45ae4-7230-4af3-8ae4-73446a5d2870','紹興別廟樂歌五首 奉俎用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肇嚴廟祀，爰圖遺芳。',40,'全唐诗/poet.song.250000.json','["肇嚴廟祀，爰圖遺芳。", "物必稱德，或陳或將。", "有縟其儀，有苾其香。", "靈兮來下，割烹是嘗。"]'),
('1de61eea-5541-446f-805f-e357f3472321','紹興別廟樂歌五首 懿節皇后室酌獻用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','曾沙表慶，正位椒庭。',40,'全唐诗/poet.song.250000.json','["曾沙表慶，正位椒庭。", "徽音杳邈，宮壺儀刑。", "虔修祀事，清酌惟馨。", "縮以包茅，昭格明靈。"]'),
('e2ccb95c-2b39-4e49-9a42-8c792e31a0ea','紹興別廟樂歌五首 亞、終獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','霄漢月墮，郊原露晞。',40,'全唐诗/poet.song.250000.json','["霄漢月墮，郊原露晞。", "徽音如在，延佇來歸。", "有酒既清，累觴載祗。", "神具醉止，燕衎怡怡。"]'),
('b2d310ef-d392-4672-820f-b968284575cb','紹興別廟樂歌五首 徹豆用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','仙馭弗返，眇邈清都。',40,'全唐诗/poet.song.250000.json','["仙馭弗返，眇邈清都。", "薦此嘉殽，既豐既腴。", "奠享有成，鼓樂愉愉。", "徹我豆籩，率禮無踰。"]'),
('3905e26b-95d7-45b5-a3d6-276ec54341c7','乾道別廟樂歌三首 詣廟用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','涓選休辰，于秋之杪。',40,'全唐诗/poet.song.250000.json','["涓選休辰，于秋之杪。", "既齊既戒，爰假祖廟。", "有侐儀坤，舊章是傚。", "享祀奚爲，天子純孝。"]'),
('1def42fc-35d2-4b39-a34c-a8af0878b9c2','乾道別廟樂歌三首 升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宗祀九筵，先薦閟宮。',40,'全唐诗/poet.song.250000.json','["宗祀九筵，先薦閟宮。", "陟自東階，煌煌衮龍。", "於穆聖善，監茲禮容。", "是享是宜，介福無窮。"]'),
('d10845a9-ca50-4cef-b2cd-9f3391b1f0b9','乾道別廟樂歌三首 懿節皇后室酌獻用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','丕顯文母，厚德維坤。',40,'全唐诗/poet.song.250000.json','["丕顯文母，厚德維坤。", "仙馭雖邈，徽音固存。", "瑟彼玉瓚，酌此鬰尊。", "簡簡穰穰，裕我後昆。"]'),
('beb15915-de6b-4e74-8b42-0c586307fe0c','紹熙別廟二首 安穆皇后室酌獻用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祥發俔天，符彰夢日。',40,'全唐诗/poet.song.250000.json','["祥發俔天，符彰夢日。", "有懷慈容，孝享廟室。", "泰尊是酌，旨酒嘉栗。", "靈其格思，祚以元吉。"]'),
('d85881c1-fc38-49e9-b9bd-02cc369a45a0','紹熙別廟二首 安恭皇后室酌獻用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','美詠河洲，德嬪媯汭。',40,'全唐诗/poet.song.250000.json','["美詠河洲，德嬪媯汭。", "徽音如存，肇修祀事。", "縮以包茅，酌以醴齊。", "靈來顧歆，降福攸備。"]'),
('f37bf466-cb4e-4b67-a0cc-869237eab011','紹興二十九年顯仁皇后祔廟一首 酌獻用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恭惟聖母，躋祔孔時。',40,'全唐诗/poet.song.250000.json','["恭惟聖母，躋祔孔時。", "陳羞宗祏，徼福坤儀。", "鍾鼓惟序，牲玉載祗。", "於皇來格，永介丕基。"]'),
('91cd2de2-49b6-4932-ab9e-a6b9c02a8f56','開禧三年成肅皇后祔廟一首 酌獻用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天合重華，內治昭融。',40,'全唐诗/poet.song.250000.json','["天合重華，內治昭融。", "承承繼繼，保佑恩隆。", "歸從阜陵，登祔太宮。", "燕我後人，福祿來崇。"]'),
('7a5ee201-d0ea-434c-9dae-174b73850622','真宗奉聖祖玉清昭應宮十一首 降聖用《真安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','巍巍真宇，奕奕殊庭。',60,'全唐诗/poet.song.250000.json','["巍巍真宇，奕奕殊庭。", "規模太紫，炳煥丹青。", "元命祗答，大猷是經。", "多儀有踐，丕應無形。", "肆設金石，聲聞杳冥。", "佇迴飈馭，永祐基扃。"]'),
('f456064c-464a-49c1-92e7-2ae4cc96f075','真宗奉聖祖玉清昭應宮十一首 奉香用《靈安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','芳氣上浹，飈馭下臨。',40,'全唐诗/poet.song.250000.json','["芳氣上浹，飈馭下臨。", "紹承丕緒，永勵精明。", "氤氳成霧，葱鬰垂陰。", "虔恭對越，介祉攸欽。"]'),
('44dc0a67-c806-4d04-8e41-75ac10d9c92d','真宗奉聖祖玉清昭應宮十一首 奉饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','發祥有自，介福無疆。',40,'全唐诗/poet.song.250000.json','["發祥有自，介福無疆。", "紛綸丕應，保佑下方。", "嘉薦斯備，雅奏具揚。", "寅威洞達，監眄昭章。"]'),
('e4a4b7ce-926c-4d58-af45-8f0222ec9b37','真宗奉聖祖玉清昭應宮十一首 玉皇位酌獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','無體之體，强名之名。',40,'全唐诗/poet.song.250000.json','["無體之體，强名之名。", "監觀萬宇，統治九清。", "真期保祐，瑞命昭明。", "乾乾翼翼，祗答財成。"]'),
('30e56c31-598b-472c-bde2-52b14bf03cb5','真宗奉聖祖玉清昭應宮十一首 聖祖位酌獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於昭靈貺，誕啟鴻源。',40,'全唐诗/poet.song.250000.json','["於昭靈貺，誕啟鴻源。", "功濟庶彙，慶流後昆。", "蘭肴登俎，桂酒盈尊。", "俯迴飈駕，永庇雲孫。"]'),
('576643be-7f43-4d19-a3b7-336f7c4edfe0','真宗奉聖祖玉清昭應宮十一首 太祖位酌獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫藝祖，受命高穹。',40,'全唐诗/poet.song.250000.json','["赫赫藝祖，受命高穹。", "威加海外，化浹區中。", "發祥宗祏，錫祐眇沖。", "欽承積德，勵翼精衷。"]'),
('91fdc2f6-4bc1-4400-90a0-0ad28821e46d','真宗奉聖祖玉清昭應宮十一首 太宗位酌獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明文考，儲精上蒼。',40,'全唐诗/poet.song.250000.json','["明明文考，儲精上蒼。", "禮樂明備，溥率賓王。", "功德累洽，歷數會昌。", "孝思罔極，丕祐無疆。"]'),
('303057e4-8af8-4cd9-a7a0-d3f5302b9206','真宗奉聖祖玉清昭應宮十一首 亞、終獻用《沖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太初非有體，至道本無聲。',72,'全唐诗/poet.song.250000.json','["太初非有體，至道本無聲。", "降迹臨下土，成功陟上清。", "至仁敦動植，丕緒啟宗祊。", "紫禁承來格，鴻基保永寧。", "發祥垂誕告，致孝薦崇名。", "廣樂伸欽奉，儲休固太平。"]'),
('f759509d-ef00-4e51-bbc9-42b60fca8303','真宗奉聖祖玉清昭應宮十一首 飲福用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明始祖，誕啟慶基。',40,'全唐诗/poet.song.250000.json','["明明始祖，誕啟慶基。", "翼翼後嗣，虔奉孝思。", "精潔斯達，祉福咸宜。", "于以報貺，于以受釐。"]'),
('15ddc040-08c5-487c-9843-889907ae8d40','真宗奉聖祖玉清昭應宮十一首 徹饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雕俎在御，飈駕聞聲。',40,'全唐诗/poet.song.250000.json','["雕俎在御，飈駕聞聲。", "真遊斯降，旨酒斯盈。", "大樂云闋，大禮云成。", "徹彼常薦，罄此明誠。"]'),
('638a6ae3-f1c1-4c3a-9348-98776c081559','真宗奉聖祖玉清昭應宮十一首 送聖用《真安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','精心既達，真遊允臻。',40,'全唐诗/poet.song.250000.json','["精心既達，真遊允臻。", "禮容斯舉，福應惟醇。", "將整僊馭，言還上旻。", "永存嘉貺，用泰烝民。"]'),
('e1362023-0ea2-46a5-8b42-f73214b898c2','迎奉聖像四首 玉皇位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉虛上帝，金像睟容。',40,'全唐诗/poet.song.250000.json','["玉虛上帝，金像睟容。", "宅真雲構，練日龜從。", "維皇對越，率禮寅恭。", "靈心丕應，福祿來崇。"]'),
('f5931d40-bfab-4276-a197-65386d991dcf','迎奉聖像四首 聖祖位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','總化在天，保昌厥緒。',40,'全唐诗/poet.song.250000.json','["總化在天，保昌厥緒。", "降格皇闈，瓊輪載御。", "藻仗星陳，睟容金鑄。", "佑我慶基，宅茲靈宇。"]'),
('ad2b5abf-c370-4afe-a94f-509d90f8457f','迎奉聖像四首 太祖位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','烝哉大君，聿懷帝祖。',40,'全唐诗/poet.song.250000.json','["烝哉大君，聿懷帝祖。", "鎔範真儀，奉尊靈宇。", "至感祥開，洪輝物臯。", "瞻謁盡恭，飛英率土。"]'),
('6d2a010d-c762-41e1-8a8d-66ee2132532f','迎奉聖像四首 太宗位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於顯神宗，德洽區中。',40,'全唐诗/poet.song.250000.json','["於顯神宗，德洽區中。", "祥金爍冶，範茲睟容。", "殊庭胥宇，備物致恭。", "明威有赫，降福來同。"]'),
('fea20f99-1199-4622-913b-8612422319e0','玉清昭應宮上尊號三首 奉告用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','登隆妙號，欽翼淵宗。',40,'全唐诗/poet.song.250000.json','["登隆妙號，欽翼淵宗。", "茂宣德禮，有恪其容。", "奉璋升薦，垂佩彌恭。", "揚休詠美，以間笙鏞。"]'),
('09fff48d-c737-4765-8509-fe8d99cd4147','玉清昭應宮上尊號三首 太初殿奉冊寶用《登安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇靈垂祐，洪福彌隆。',50,'全唐诗/poet.song.250000.json','["皇靈垂祐，洪福彌隆。", "祗率綿宇，潔祀真容。", "嚴恭奉冊，對越清躬。", "睟容肅穆，懿號尊崇。", "禮成樂舉，福祿來同。"]'),
('61303315-653e-4ba3-aae0-26bd11e65426','玉清昭應宮上尊號三首 二聖殿奉絳紗袍用《登安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫列聖，盛德巍然。',40,'全唐诗/poet.song.250000.json','["赫赫列聖，盛德巍然。", "彤彤靈宇，睟儀在焉。", "奉以龍衮，被之象天。", "重慶宗稷，億萬斯年。"]'),
('be180cb8-e814-4283-a36e-77f6261edc11','朝謁太清宮九首 太尉奉聖號冊寶用《真安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上旻降監，介祉實繁。',40,'全唐诗/poet.song.250000.json','["上旻降監，介祉實繁。", "邦家修報，妙道歸尊。", "增名霄極，奉冊靈軒。", "茂宣聖典，永祐黎元。"]'),
('628683d6-64b7-42bb-86bb-74d52aaf3436','朝謁太清宮九首 寶冊升殿用《大安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','圖書昭錫，典禮紹成。',40,'全唐诗/poet.song.250000.json','["圖書昭錫，典禮紹成。", "烝民何幸，教父儲靈。", "欽承景貺，祗奉崇名。", "致虔寶冊，垂祐基扃。"]'),
('8aeeb602-89fa-4b06-81a0-063706d49972','朝謁太清宮九首 降神用《真安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猶龍之聖，降生厲鄉。',60,'全唐诗/poet.song.250000.json','["猶龍之聖，降生厲鄉。", "教流清浄，道符混茫。", "大君肅謁，盛儀允臧。", "森羅羽衛，躬薦蕭薌。", "簪紱濟濟，鍾石洋洋。", "高真至止，介福誕祥。"]'),
('cfa54142-4a9f-456b-9470-249db0f7de40','朝謁太清宮九首 奉玉幣用《靈安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','琳宮奕奕，黼坐煌煌。',40,'全唐诗/poet.song.250000.json','["琳宮奕奕，黼坐煌煌。", "玉帛成禮，飈馭延祥。", "鴻儀有則，景福無疆。", "嘉應昭協，丕猶誕揚。"]'),
('9fd62bff-711f-4822-8684-7695ef227533','朝謁太清宮九首 奉饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金奏以諧，飈遊斯格。',40,'全唐诗/poet.song.250000.json','["金奏以諧，飈遊斯格。", "靈監章明，皇心勵翼。", "肅奉雕俎，來升綵席。", "享德有孚，凝禧無斁。"]'),
('57d3b3dd-a4ac-4b67-b9e3-effdaf5db34e','朝謁太清宮九首 酌獻用《大安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','欽崇至道，肅謁殊庭。',40,'全唐诗/poet.song.250000.json','["欽崇至道，肅謁殊庭。", "順風而拜，明德惟馨。", "飈馭來格，尊酒斯盈。", "是酌是獻，心通杳冥。"]'),
('cf54e5cc-879f-43d2-84bc-14f30f7b4371','朝謁太清宮九首 飲福用《大安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼渦之壤，指李之區。',40,'全唐诗/poet.song.250000.json','["彼渦之壤，指李之區。", "千乘萬騎，來朝密都。", "躬陳芳薦，款接仙輿。", "飲酒受福，永耀鴻圖。"]'),
('87e3d6b8-9082-4b93-8900-0d46abf3d937','朝謁太清宮九首 亞、終獻用《大安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','邈矣道祖，冥幾惚恍。',40,'全唐诗/poet.song.250000.json','["邈矣道祖，冥幾惚恍。", "常德不離，至真無象。", "引位清穹，降祥神壤。", "酌醴薦誠，控飈來享。"]'),
('290db6e1-9de4-44e0-8917-d180080c9950','朝謁太清宮九首 送神用《真安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','醴醆在戶，金奏在庭。',40,'全唐诗/poet.song.250000.json','["醴醆在戶，金奏在庭。", "籩豆有踐，黍稷非馨。", "義盡蠲潔，誠通杳冥。", "言旋風駟，祚我修齡。"]'),
('b171489f-5a90-46e8-9225-392cf60b7968','太極觀奉冊寶一首 《登安之曲》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','薦號穹冥，登名祖禰。',40,'全唐诗/poet.song.250000.json','["薦號穹冥，登名祖禰。", "陟配陽郊，協宣典禮。", "感電靈區，誕聖鴻懿。", "冊寶斯陳，福祿來暨。"]'),
('b3f41d56-7055-4d1f-a578-2c2f3e77ef18','景靈宮奉冊寶一首 《登安之曲》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆真宗，錫羨蕃昌。',40,'全唐诗/poet.song.250000.json','["穆穆真宗，錫羨蕃昌。", "飈輪臨貺，諄誨洞彰。", "虔崇懿號，祗答景祥。", "至誠致享，降福無疆。"]'),
('716a3166-338e-46e5-99d4-7bf30439c687','景祐元年親享景靈宮二首 降真用《太安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','真館奉幣，潔齊致馨。',20,'全唐诗/poet.song.250000.json','["真館奉幣，潔齊致馨。", "靈因斯格，社稷慶寧。"]'),
('cd0437b6-e28d-4b5e-864d-f2fa91126c4b','景祐元年親享景靈宮二首 送真用《太安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','椒漿尊享，珍饌精祈。',20,'全唐诗/poet.song.250000.json','["椒漿尊享，珍饌精祈。", "睟容杳邈，瑶輅霞飛。"]'),
('b79f887f-fa76-403f-913e-3cbf6a2906be','大觀三年朝獻景靈宮二首 奉饌用《吉安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','威靈洋洋，靡有常嚮。',40,'全唐诗/poet.song.250000.json','["威靈洋洋，靡有常嚮。", "於惟欽承，來假來饗。", "博碩芬香，是烝是享。", "奉器有虔，載德無爽。"]'),
('4535ec82-7de8-4573-b294-f5b864d208e8','大觀三年朝獻景靈宮二首 奉饌用《吉安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','爾牲既充，是烹是肆。',40,'全唐诗/poet.song.250000.json','["爾牲既充，是烹是肆。", "爾肴既具，是羞是饋。", "非物之重，惟德之備。", "神之格思，歆我精意。"]'),
('ac832c7a-f890-494d-a720-2c87e0411d19','高宗郊前朝獻景靈宮二十一首 皇帝入門用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維皇齊居，承神其初。',40,'全唐诗/poet.song.250000.json','["維皇齊居，承神其初。", "顒顒昂昂，龍步雲趨。", "景鍾鏗如，肅覲清都。", "肸蠁之交，神人用孚。"]'),
('60761a69-93ea-487e-ad77-7fd4ac0c889c','高宗郊前朝獻景靈宮二十一首 升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝既臨饗，罄茲精意。',40,'全唐诗/poet.song.250000.json','["帝既臨饗，罄茲精意。", "對越在天，爰升紫陛。", "孔容翼翼，保承丕緒。", "孝奉天儀，永錫爾類。"]'),
('336eb678-a990-497e-8996-ed9b092158b7','高宗郊前朝獻景靈宮二十一首 降聖用《太安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟德馨香，升聞八方。',40,'全唐诗/poet.song.250000.json','["惟德馨香，升聞八方。", "粵神臨之，來從帝鄉。", "萬靈景衛，有燁其光。", "監我精純，降福穰穰。"]'),
('cf3470af-898a-4458-a227-43c23017ffa9','高宗郊前朝獻景靈宮二十一首 盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','齋居皇皇，瓊琚鏘鏘。',40,'全唐诗/poet.song.250000.json','["齋居皇皇，瓊琚鏘鏘。", "承祭之初，其如在旁。", "挹彼注茲，儲禧迎祥。", "神之聽之，欣欣樂康。"]'),
('082c82e2-68df-420e-a586-bc8ea971587d','高宗郊前朝獻景靈宮二十一首 聖祖位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','涓選休辰，有事嘉薦。',40,'全唐诗/poet.song.250000.json','["涓選休辰，有事嘉薦。", "琅琅瓊珮，陟降巖殿。", "其陟伊何，幣玉斯奠。", "周旋中禮，千億儲羨。"]'),
('9d00447c-5f10-429e-a680-b67dfed8b1be','高宗郊前朝獻景靈宮二十一首 聖祖位奉玉幣用《靈安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上靈始祖，雲景元尊。',40,'全唐诗/poet.song.250000.json','["上靈始祖，雲景元尊。", "嚴祀夙展，六樂朱軒。", "明玉之潔，豐帛之溫。", "暢乃繼序，承德不愆。"]'),
('b4020603-0f75-42f6-a621-7ff951743454','高宗郊前朝獻景靈宮二十一首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我后臨饗，奠幣攸畢。',40,'全唐诗/poet.song.250000.json','["我后臨饗，奠幣攸畢。", "式旋其趨，榘度有式。", "禮容齋莊，孝思純實。", "天休滋至，時萬時億。"]'),
('1ab744ba-0048-4d56-9ebb-7353077d57ac','高宗郊前朝獻景靈宮二十一首 奉饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百職駿奔，來相于庭。',40,'全唐诗/poet.song.250000.json','["百職駿奔，來相于庭。", "奉盛以告，登茲芳馨。", "際天蟠地，默運三靈。", "神兮來歆，祚我休平。"]'),
('aa7dfa25-6ea1-4af1-958d-96c532d86b98','高宗郊前朝獻景靈宮二十一首 再盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有嚴大禮，對時休明。',40,'全唐诗/poet.song.250000.json','["有嚴大禮，對時休明。", "情文則粲，蠲潔必清。", "再臨觀盥，以專以精。", "真游來格，永觀厥成。"]'),
('273783e9-7ffc-4118-9aa6-bd917703d676','高宗郊前朝獻景靈宮二十一首 再詣聖祖位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於赫炎宋，十葉華耀。',40,'全唐诗/poet.song.250000.json','["於赫炎宋，十葉華耀。", "屬茲郊報，陟降在廟。", "其降伊何，椒漿桂酒。", "再拜斟酌，永御九有。"]'),
('096646c3-af14-45e8-9d19-9d550ca56d0b','高宗郊前朝獻景靈宮二十一首 聖祖位酌獻用《祖安》。御製。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瑶源誕啟，玉牒肇榮。',40,'全唐诗/poet.song.250000.json','["瑶源誕啟，玉牒肇榮。", "覆育羣有，監觀圓清。", "酒醴既洽，登薦惟誠。", "無有後艱，駿惠雲仍。"]'),
('7027f375-e3dc-4d57-99da-ecaf7928b886','高宗郊前朝獻景靈宮二十一首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奠鬯告成，式旋厥位。',40,'全唐诗/poet.song.250000.json','["奠鬯告成，式旋厥位。", "天步雍容，神人燕喜。", "九廟觀德，百靈薦祉。", "子孫其昌，垂千萬祀。"]'),
('fd508d3f-4c72-4e8c-9202-192646b2b301','高宗郊前朝獻景靈宮二十一首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇樂舞，進旅退旅。',40,'全唐诗/poet.song.250000.json','["於皇樂舞，進旅退旅。", "一弛一張，笙磬具舉。", "豈惟玩聲，象德是似。", "神鑒孔昭，福祿來予。"]'),
('a8d3f037-db9d-49c6-b18e-e5ccb975264e','高宗郊前朝獻景靈宮二十一首 亞、終獻用《沖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','五音飭奏，神既億康。',40,'全唐诗/poet.song.250000.json','["五音飭奏，神既億康。", "澹其容與，薦此嘉觴。", "有來顯相，鋗玉鏘鏘。", "奉承若宥，罔不齋莊。"]'),
('d40273d7-8396-44fa-95ff-73686aaf37e2','高宗郊前朝獻景靈宮二十一首 飲福用《報安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉薦既終，神貺斯復。',40,'全唐诗/poet.song.250000.json','["嘉薦既終，神貺斯復。", "賚我思成，靈光下燭。", "孝孫承之，載祗載肅。", "敷錫庶民，函蒙祉福。"]'),
('258b7d3d-9930-46e3-a3c4-cbadae9843e8','高宗郊前朝獻景靈宮二十一首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝臨閟庭，逆釐上靈。',40,'全唐诗/poet.song.250000.json','["帝臨閟庭，逆釐上靈。", "神羯安坐，肅若有承。", "嘉觴既申，德聞惟馨。", "靈光留俞，祚我億齡。"]'),
('9ae4b1db-a7bc-48bb-b0c3-30c9ef9096e0','高宗郊前朝獻景靈宮二十一首 徹饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','普淖既薦，苾芬孔時。',40,'全唐诗/poet.song.250000.json','["普淖既薦，苾芬孔時。", "神嗜而顧，有來燕娭。", "饗矣將徹，載欽載祗。", "展詩以侑，益臻厥熙。"]'),
('60c17a4c-ca2a-482b-a23b-9c4f97209ce1','高宗郊前朝獻景靈宮二十一首 送真用《太安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雍歌既徹，熙事備成。',40,'全唐诗/poet.song.250000.json','["雍歌既徹，熙事備成。", "神夕奄虞，忽乘青冥。", "靈心回睠，監我精禋。", "誕降嘉祉，休德昭清。"]'),
('2d897f5f-daca-4a10-aa64-9076e4828bcf','高宗郊前朝獻景靈宮二十一首 降殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我秩元祀，上推靈源。',40,'全唐诗/poet.song.250000.json','["我秩元祀，上推靈源。", "展事有侐，祲威肅然。", "丹墄既降，秉心益虔。", "荷天之休，于千萬年。"]'),
('cb0692b7-a3f6-4fbd-a0c6-0051dad938b9','高宗郊前朝獻景靈宮二十一首 望燎用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕靈宮，有嚴毖祀。',40,'全唐诗/poet.song.250000.json','["奕奕靈宮，有嚴毖祀。", "燔燎具揚，禮儀既備。", "帝心肅祗，天步旋止。", "對越在天，永膺蕃祉。"]'),
('cf91344d-9e83-45c2-a42b-16545bc1d0c2','高宗郊前朝獻景靈宮二十一首 還大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝將于郊，昭事上祀。',40,'全唐诗/poet.song.250000.json','["帝將于郊，昭事上祀。", "爰茲畢觴，復即于此。", "飈游載旋，容旌沓騎。", "維皇嘉承，錫祚昌熾。"]'),
('f3dba2cc-b15f-4593-9cb2-376ecb43369f','高宗明堂前朝獻景靈宮十首 降聖用《大安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','德惟馨香，升聞八方。',40,'全唐诗/poet.song.250000.json','["德惟馨香，升聞八方。", "粵神之從，燦然有光。", "驂飛乘蒼，啾啾蹌蹌。", "消摇從容，顧予不忘。"]'),
('f10215d2-46c0-4b67-beeb-3da1af702be6','高宗明堂前朝獻景靈宮十首 升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝既臨享，龍馭華耀。',40,'全唐诗/poet.song.250000.json','["帝既臨享，龍馭華耀。", "孝孫承之，陟降在廟。", "誠意上交，慶陰下冒。", "天休駢至，千億克紹。"]'),
('19884bf5-7947-4155-984b-affc5590d1ae','高宗明堂前朝獻景靈宮十首 聖祖位奠玉幣用《靈安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉氣如虹，豐繒充笥。',40,'全唐诗/poet.song.250000.json','["玉氣如虹，豐繒充笥。", "既奉既將，亦奠在位。", "有永羣后，實相祀事。", "何以臨下，心意不貳。"]'),
('1d694574-d962-4340-8dc2-efaced7bcc41','高宗明堂前朝獻景靈宮十首 奉饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瓊琚鏘鏘，玄衣繡裳。',40,'全唐诗/poet.song.250000.json','["瓊琚鏘鏘，玄衣繡裳。", "薦嘉升香，粢盛芬芳。", "禮儀莫愆，鼓鐘喤喤。", "曾孫之常，綏福無疆。"]'),
('cf9d1101-8b87-4197-ada6-a20d28d5f1a1','高宗明堂前朝獻景靈宮十首 聖祖位酌獻用《祖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','裴回若留，靈其有喜。',40,'全唐诗/poet.song.250000.json','["裴回若留，靈其有喜。", "薦我馨香，挹茲酒醴。", "我祖在天，執道之紀。", "申佑無疆，奏神稱禮。"]'),
('29e09233-5f7f-4dad-8b77-76ae4cfa5fab','高宗明堂前朝獻景靈宮十首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','進旅退旅，載執干戚。',40,'全唐诗/poet.song.250000.json','["進旅退旅，載執干戚。", "不愆于儀，容服有赫。", "式妥式侑，神保是格。", "靈鑒孔昭，孝思維則。"]'),
('4ae7091a-8962-4825-883e-5a8833a50d58','高宗明堂前朝獻景靈宮十首 飲福用《報安》。亞、終獻《沖安》用舊辭。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於赫大神，總司元化。',40,'全唐诗/poet.song.250000.json','["於赫大神，總司元化。", "監我純精，威光來下。", "延昌之貺，千億馮藉。", "曾孫保之，丕平是迓。"]'),
('568be014-6bd3-4966-8442-60705d3607ca','高宗明堂前朝獻景靈宮十首 徹饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','洋洋降臨，肅肅布列。',40,'全唐诗/poet.song.250000.json','["洋洋降臨，肅肅布列。", "熙事既成，嘉籩告徹。", "九天儲慶，垂佑無缺。", "寖明寖昌，綿綿瓜瓞。"]'),
('6ef67b3b-2422-4fd8-88df-bcca48bc6f66','高宗明堂前朝獻景靈宮十首 送真用《太安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','高飛安翔，持御陰陽。',40,'全唐诗/poet.song.250000.json','["高飛安翔，持御陰陽。", "幽贊圓穹，監觀四方。", "元精回復，奄虞孔良。", "畢觴降嘏，偃蹇于驤。"]'),
('402d0778-83ff-41cd-a67d-a3367e77a74b','高宗明堂前朝獻景靈宮十首 望燎用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕原祠，有嚴毖祀。',40,'全唐诗/poet.song.250000.json','["奕奕原祠，有嚴毖祀。", "禮儀孔宣，燔燎斯暨。", "帝心肅祗，天步旋止。", "熙事既成，永膺蕃祉。"]'),
('fb88aa7a-1cd0-4bf2-ab6b-5dee4d2cc517','孝宗明堂前朝獻景靈宮八首 盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','合宮之饗，報本奉先。',40,'全唐诗/poet.song.250000.json','["合宮之饗，報本奉先。", "欽惟道祖，濬發璿源。", "駕言謁款，其盥惟虔。", "尚監精衷，錫祚綿綿。"]'),
('5834cf8d-f543-4b96-b35c-068a935e25da','孝宗明堂前朝獻景靈宮八首 聖祖位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','駿命有開，慶基無窮。',40,'全唐诗/poet.song.250000.json','["駿命有開，慶基無窮。", "祗率百辟，仰瞻睟容。", "鼓鐘斯和，黍稷斯豐。", "靈其居歆，福祿來崇。"]'),
('3eb79173-7902-45ce-ae30-7714f2eecdf2','孝宗明堂前朝獻景靈宮八首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉玉既設，量幣既陳。',40,'全唐诗/poet.song.250000.json','["嘉玉既設，量幣既陳。", "彷彿靈游，來顧來寧。", "對越伊何，厥惟一純。", "佑我熙事，以迄于成。"]'),
('816d1e95-7f11-4926-8653-dfa519e81a9d','孝宗明堂前朝獻景靈宮八首 奉饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','發祥仙源，流澤萬世。',40,'全唐诗/poet.song.250000.json','["發祥仙源，流澤萬世。", "曷其報之，親饗三歲。", "相維列卿，潔粢是饋。", "匪物之尚，誠之爲至。"]'),
('0e280097-8e38-431f-8bfb-4222d1cfbfc3','孝宗明堂前朝獻景靈宮八首 再詣盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','華燈熒煌，瑞煙氤氳。',40,'全唐诗/poet.song.250000.json','["華燈熒煌，瑞煙氤氳。", "威神如在，蠲潔必親。", "再盥于罍，再帨于巾。", "皇心肅祗，其敢憚勤。"]'),
('3aa58f1c-3e17-4fa9-80eb-dd68ce3d64f5','孝宗明堂前朝獻景靈宮八首 再詣聖祖位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','歲逢有年，月旅無射。',40,'全唐诗/poet.song.250000.json','["歲逢有年，月旅無射。", "我將我饗，如幾如式。", "肅爾臣工，諧爾金石。", "本原休功，垂裕罔極。"]'),
('026c8db1-279d-40f2-abfd-0198467b615b','孝宗明堂前朝獻景靈宮八首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','旨酒思柔，神具醉止。',40,'全唐诗/poet.song.250000.json','["旨酒思柔，神具醉止。", "工祝既告，孝孫旋位。", "何以酢之，純嘏來備。", "燕及雲來，蕃衍無已。"]'),
('2faf2042-83e0-4739-8e25-7377457d6114','孝宗明堂前朝獻景靈宮八首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','象德之成，有奕其舞。',40,'全唐诗/poet.song.250000.json','["象德之成，有奕其舞。", "一弛一張，進旅退旅。", "嘒以管簫，和以鏞鼓。", "神其樂康，永錫多祜。"]'),
('9acf9364-6772-4bf5-9485-6bd808ffd2f2','寧宗郊前朝獻景靈宮二十四首 皇帝入門用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','閟幄邃深，雲景杳冥。',40,'全唐诗/poet.song.250000.json','["閟幄邃深，雲景杳冥。", "天清日晬，展容玉庭。", "締基發祥，希夷降靈。", "神其來燕，是饗是聽。"]'),
('95feddf3-2a8b-4047-895c-d5a065bb98de','寧宗郊前朝獻景靈宮二十四首 升殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝居瑶圖，璇題玉京。',40,'全唐诗/poet.song.250000.json','["帝居瑶圖，璇題玉京。", "日月經振，列宿上熒。", "桂簋飶芬，瑚器華晶。", "夤承禋祀，用戒昭明。"]'),
('e0c8bef7-a415-41cb-864b-48c55dbe3625','寧宗郊前朝獻景靈宮二十四首 降神用《太安》。六變。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鐘爲宮〕四靈晨耀，五緯夕明。',46,'全唐诗/poet.song.250000.json','["〔圜鐘爲宮〕四靈晨耀，五緯夕明。", "風雲晏和，天地粹清。", "靈兮來迎，靈兮來寧。", "啟我子孫，饗于純精。"]'),
('ba11234d-c667-4983-b18d-13816a5a5f9d','寧宗郊前朝獻景靈宮二十四首 降神用《太安》。六變。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鐘爲角〕芬枝揚烈，熉珠叶陶。',46,'全唐诗/poet.song.250000.json','["〔黄鐘爲角〕芬枝揚烈，熉珠叶陶。", "闓珍闡符，展詩舞箾。", "神哉來下，神哉來翱。", "肅若有承，靈心招摇。"]'),
('42c76c16-53ec-4ae7-aa5c-d5211a068c12','寧宗郊前朝獻景靈宮二十四首 降神用《太安》。六變。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕龍車既奏，鳳馭載翔。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕龍車既奏，鳳馭載翔。", "帝幄佇靈，天衢騰芳。", "神來留俞，神來蹇驤。", "禮鬯樂明，奏假孔將。"]'),
('cce9e66e-d128-4ba3-ae17-712e97db9504','寧宗郊前朝獻景靈宮二十四首 降神用《太安》。六變。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕虹旌蜺旄，鸞旗翠蓋。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕虹旌蜺旄，鸞旗翠蓋。", "星樞扶輪，月御叶衛。", "靈至陰陰，靈般裔裔。", "來格來饗，福流萬世。"]'),
('1da1374e-a306-46f9-a24a-ee0fadf6a7ab','寧宗郊前朝獻景靈宮二十四首 盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮文有俶，祀事孔明。',40,'全唐诗/poet.song.250000.json','["禮文有俶，祀事孔明。", "將以潔告，允惟齊精。", "自盥而往，聿觀厥成。", "靈監下臨，天德其清。"]'),
('593cde29-e9bb-4025-8931-118aeb6ed63c','寧宗郊前朝獻景靈宮二十四首 詣聖祖位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維宋肖德，欽天顧右。',40,'全唐诗/poet.song.250000.json','["維宋肖德，欽天顧右。", "於皇道祖，丕釐靈祐。", "葛藟殖繁，瓜瓞孕茂。", "克昌厥後，世世孝奏。"]'),
('2350ec3f-5751-4fd7-be41-9a6e3c025fdc','寧宗郊前朝獻景靈宮二十四首 皇帝還位用《乾安》。聖祖位奉玉幣用《靈安》，高宗御製，見前。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','桂宮耽耽，藻儀穆穆。',40,'全唐诗/poet.song.250000.json','["桂宮耽耽，藻儀穆穆。", "天回衮彩，風韶璜玉。", "咸英皦亮，容典炳煜。", "假我上靈，景命有僕。"]'),
('bdbda193-f07c-47f2-9b90-53d11ec19b97','寧宗郊前朝獻景靈宮二十四首 奉饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我簋斯盈，我簠斯實。',40,'全唐诗/poet.song.250000.json','["我簋斯盈，我簠斯實。", "或剝或烹，或燔或炙。", "有殽既將，爲俎孔碩。", "禮儀卒度，永錫爾極。"]'),
('f1aab462-097f-4c75-8191-222628a38ccd','寧宗郊前朝獻景靈宮二十四首 再盥洗用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','觴澹初勺，禮戒重盥。',40,'全唐诗/poet.song.250000.json','["觴澹初勺，禮戒重盥。", "假廟以萃，取象于觀。", "清明外暢，精肅中貫。", "我儀圖之，三靈攸贊。"]'),
('cbb5ccd3-f862-45bd-af03-c56651ff0845','寧宗郊前朝獻景靈宮二十四首 再詣聖祖位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肇基駿命，鞏右鴻業。',40,'全唐诗/poet.song.250000.json','["肇基駿命，鞏右鴻業。", "鼎玉龜符，垂固萬葉。", "靈貺具臻，神光燁燁。", "暉祚無疆，規重矩疊。"]'),
('b1a14208-5613-484b-b26a-1714518e03b5','寧宗郊前朝獻景靈宮二十四首 還位用《乾安》。聖祖位酌獻用《祖安》，高宗御製，見前。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇帝瑞慶，長發其祥。',40,'全唐诗/poet.song.250000.json','["皇帝瑞慶，長發其祥。", "纂系悠遠，遡源靈長。", "德之克明，休烈有光。", "配天作極，孝饗是將。"]'),
('eb43ab98-c043-4695-93ef-d825dbd47dc9','寧宗郊前朝獻景靈宮二十四首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','持翟成象，秉朱就列。',40,'全唐诗/poet.song.250000.json','["持翟成象，秉朱就列。", "旄乘整溢，鳳儀諧節。", "揮舒皇文，歌蹈先烈。", "合好效懽，福流有截。"]'),
('3c933c2a-e220-44c5-9e58-853c725fe6df','寧宗郊前朝獻景靈宮二十四首 亞獻用《沖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','光熉紫幄，神流玉房。',40,'全唐诗/poet.song.250000.json','["光熉紫幄，神流玉房。", "秉文侑儀，嘉虞貳觴。", "震澹醉喜，彷彿迪嘗。", "璇源之休，地久天長。"]'),
('b23d9505-b1e3-48b3-8c03-b48c19fffcf1','寧宗郊前朝獻景靈宮二十四首 終獻用《沖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈輿蹇驤，畢觴泰筵。',40,'全唐诗/poet.song.250000.json','["靈輿蹇驤，畢觴泰筵。", "貳饗允穆，祼將克竣。", "垂恩儲祉，錫羨永年。", "將以慶成，燕及皇天。"]'),
('3fc4a869-9f24-4fa0-a2b8-8a196bef43e3','寧宗郊前朝獻景靈宮二十四首 詣飲福位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','若木露英，清雲流霞。',40,'全唐诗/poet.song.250000.json','["若木露英，清雲流霞。", "蔓蔓芝秀，馮馮桂華。", "綿瑞無疆，産嘏孔奢。", "皇則受之，鞏我帝家。"]'),
('05117c77-5f65-4b73-a509-0dc56742892b','寧宗郊前朝獻景靈宮二十四首 飲福酒用《報安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','旨酒惟蘭，勺漿惟椒。',40,'全唐诗/poet.song.250000.json','["旨酒惟蘭，勺漿惟椒。", "福流瓚斝，光燭琨瑶。", "拜貺清宮，凝輝慶霄。", "神其如在，徘徊招摇。"]'),
('4227760f-2776-4c79-916a-03397467f942','寧宗郊前朝獻景靈宮二十四首 還位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','烝哉我皇，繼天毓聖。',40,'全唐诗/poet.song.250000.json','["烝哉我皇，繼天毓聖。", "逆釐玄都，對越靈慶。", "如天斯久，如日斯盛。", "瑶圖濬邈，永隆駿命。"]'),
('94739840-13d6-42b3-a560-6854cce9d18e','寧宗郊前朝獻景靈宮二十四首 徹饌用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','房鉶陳列，室簋登奉。',40,'全唐诗/poet.song.250000.json','["房鉶陳列，室簋登奉。", "告饗具歆，展徹惟拱。", "祥光奕奕，嘉氣懞懞。", "受嘏不諐，燕天之寵。"]'),
('c912c4ec-fcc7-448d-a643-cb6c0c2fc98f','寧宗郊前朝獻景靈宮二十四首 送真用《太安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雲車風馬，靈其來游。',40,'全唐诗/poet.song.250000.json','["雲車風馬，靈其來游。", "天門軼蕩，神其莫留。", "遺慶陰陰，祉發祥流。", "康我有宋，與天匹休。"]'),
('2d051628-fc9f-4845-9bc4-0986184a0fae','寧宗郊前朝獻景靈宮二十四首 降殿用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','璇庭爛景，紫殿流光。',40,'全唐诗/poet.song.250000.json','["璇庭爛景，紫殿流光。", "禮洽乾回，福應日昌。", "聖系厖鴻，景命溥將。", "德茂功成，率祀無疆。"]'),
('a5adabad-6d5d-4573-93c2-8c467abc0785','寧宗郊前朝獻景靈宮二十四首 詣望燎位用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','厥初生民，淵濬唯祖。',40,'全唐诗/poet.song.250000.json','["厥初生民，淵濬唯祖。", "芳薦既輟，明燎具舉。", "德馨升聞，靈貺蕃詡。", "懷濡上靈，佑周之祜。"]'),
('cd68da23-1af5-45a6-8905-27d2826e0b68','寧宗郊前朝獻景靈宮二十四首 還大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝假于宮，彝承清祀。',40,'全唐诗/poet.song.250000.json','["帝假于宮，彝承清祀。", "天暉臨幄，宸衛森峙。", "行繇大室，旋趨紫畤。", "率禮不違，式旉靈祉。"]'),
('73e4bebd-859d-42fd-b13e-78f364578f46','理宗明堂前朝獻景靈宮二首 升殿登歌《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我享我將，罄茲精意。',40,'全唐诗/poet.song.250000.json','["我享我將，罄茲精意。", "陟降左右，維天與契。", "齋明乃心，祗肅在位。", "於萬斯年，百福來備。"]'),
('6d0805bb-8d61-4e54-b796-7652b003f7ff','理宗明堂前朝獻景靈宮二首 亞獻宮架《沖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','慶雲鬰鬰，鳴璆琅琅。',40,'全唐诗/poet.song.250000.json','["慶雲鬰鬰，鳴璆琅琅。", "澹其容與，申薦貳觴。", "奉承若宥，神其樂康。", "錫以多祉，源深流長。"]'),
('aba4448a-2e64-4cf5-8046-334174c4a700','大中祥符封禪十首 山上圜臺降神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','巖巖泰山，配德于天。',40,'全唐诗/poet.song.250000.json','["巖巖泰山，配德于天。", "奉符展采，翼翼乾乾。", "滌濯靜嘉，罔有弗蠲。", "上帝顧諟，冷風肅然。"]'),
('10725c86-bf46-4c4b-946a-140308c367ec','大中祥符封禪十首 昊天上帝坐酌獻用《奉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇天上帝，陰騭下民。',40,'全唐诗/poet.song.250000.json','["皇天上帝，陰騭下民。", "道崇廣覆，化洽鴻鈞。", "靈文誕錫，寶命惟新。", "增高欽事，式奉嚴禋。"]'),
('34f6bca7-2d91-49ad-b7b7-4872549e3a06','大中祥符封禪十首 太祖配坐酌獻用《封安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆聖祖，肇開鴻業。',40,'全唐诗/poet.song.250000.json','["於穆聖祖，肇開鴻業。", "我武惟揚，皇威有曄。", "四隩混同，百靈震疊。", "陟配高穹，明靈是接。"]'),
('34978cc0-c42e-410a-bf53-c4efcd8241db','大中祥符封禪十首 太宗配坐酌獻用《封安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祗若封祀，神宗配天。',40,'全唐诗/poet.song.250000.json','["祗若封祀，神宗配天。", "禮樂明備，奠獻精虔。", "景靈來格，休祥藹然。", "於昭垂慶，億萬斯年。"]'),
('45442921-be7a-4fc4-a80f-f9b1fc64623d','大中祥符封禪十首 亞獻用《恭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','因高定位，禮修物備。',40,'全唐诗/poet.song.250000.json','["因高定位，禮修物備。", "薦鬯卜牲，虔恭寅畏。", "八音克諧，天神咸暨。", "降福穰穰，永錫爾類。"]'),
('e25afa42-f163-4add-b40b-1f1e5ab1a91f','大中祥符封禪十首 終獻用《順安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','浩浩元精，無臭無聲。',40,'全唐诗/poet.song.250000.json','["浩浩元精，無臭無聲。", "臨下有赫，得一以清。", "備物致享，薦茲至誠。", "泰尊奠獻，夙夜齊明。"]'),
('794828a0-1db7-48db-af01-955fdf769339','大中祥符封禪十首 社首壇降神用《靖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至哉坤元，資生伊始。',40,'全唐诗/poet.song.250000.json','["至哉坤元，資生伊始。", "博厚稱德，沈潜柔止。", "降禪方位，聿修明祀。", "寅恭吉蠲，永錫蕃祉。"]'),
('cff8d98f-7211-4de9-9f05-2314bcfeb17a','大中祥符封禪十首 皇地祇坐酌獻用《禪安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤德直方，博厚無疆。',40,'全唐诗/poet.song.250000.json','["坤德直方，博厚無疆。", "秉陰得一，靜而有常。", "寶藏以發，乃育百昌。", "肅祗禪祭，錫祉穰穰。"]'),
('cbaf3894-c087-44ca-a44b-1b649da6f840','大中祥符封禪十首 太祖配坐酌獻用《禪安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇矣聖祖，丕赫神武。',40,'全唐诗/poet.song.250000.json','["皇矣聖祖，丕赫神武。", "秉運宅中，威加九土。", "德厚功崇，頌聲載路。", "陟配方祗，對天之祜。"]'),
('ddb85632-05a2-42ee-850e-b264ff6405c2','大中祥符封禪十首 太宗配坐酌獻用《禪安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','毖祀柔祇，報功厚載。',40,'全唐诗/poet.song.250000.json','["毖祀柔祇，報功厚載。", "思文太宗，侑神嚴配。", "鐘石斯和，籩豆咸在。", "永錫坤珍，資生爲大。"]'),
('f15d4e53-a475-4a6e-810a-05bc68bf1848','汾陰十首 降神用《靖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','茫茫坤載，粵惟太寧。',40,'全唐诗/poet.song.250000.json','["茫茫坤載，粵惟太寧。", "資生光大，品物流形。", "瞻言汾曲，允宅神靈。", "聖皇躬享，明德惟馨。"]'),
('e85c2080-33a6-4fb6-8b01-635cadac891f','汾陰十首 奠玉幣登歌《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至誠旁達，柔祇格思。',20,'全唐诗/poet.song.250000.json','["至誠旁達，柔祇格思。", "奉以琮幣，致誠在茲。"]'),
('7a5b1ff8-9981-43db-8319-7785214e3411','汾陰十首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','博碩者牲，載純其色。',20,'全唐诗/poet.song.250000.json','["博碩者牲，載純其色。", "體薦登俎，聿崇坤德。"]'),
('e518527e-c8e0-412a-8f2f-76dfd2ab6ce1','汾陰十首 后土地祇坐酌獻用《博安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秉陰成德，敏樹宣功。',40,'全唐诗/poet.song.250000.json','["秉陰成德，敏樹宣功。", "應變審諦，神力無窮。", "沈潜剛克，流謙示中。", "潔茲奠獻，妙物玄通。"]'),
('aa9c7914-80e8-494b-85e8-72246db2ab80','汾陰十首 太祖配坐酌獻用《博安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤元茂育，植物成形。',40,'全唐诗/poet.song.250000.json','["坤元茂育，植物成形。", "於穆聖祖，功齊三靈。", "嚴恭配侑，厚德攸寧。", "永懷錫羨，歆此惟馨。"]'),
('8afdd713-2fe6-4081-99c8-d55ec51675a0','汾陰十首 太宗配坐酌獻用《博安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','報功厚載，祀事惟明。',40,'全唐诗/poet.song.250000.json','["報功厚載，祀事惟明。", "思文烈考，道濟羣生。", "侑神定位，協德安平。", "馨潔並薦，享于克誠。"]'),
('7b618f96-c241-4501-8c55-32ef53e53aec','汾陰十首 飲福用《博安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寅威寶命，明祀惟虔。',40,'全唐诗/poet.song.250000.json','["寅威寶命，明祀惟虔。", "協神備物，罔不吉蠲。", "后祇格思，靈飈肅然。", "誕受景福，遐哉億年。"]'),
('f3fe492b-4ec0-4174-a44a-bddf81c4edd3','汾陰十首 亞、終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至哉柔祇，滋生蕃錫。',40,'全唐诗/poet.song.250000.json','["至哉柔祇，滋生蕃錫。", "滌濯靜嘉，寅恭夕惕。", "金奏純如，萬舞有奕。", "立我烝民，莫匪爾極。"]'),
('bfe6845d-3ebb-4c4e-a5dd-74a22040150f','汾陰十首 后土廟降神用《靖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','博厚流形，秉陰成德。',40,'全唐诗/poet.song.250000.json','["博厚流形，秉陰成德。", "柔順利正，直方維則。", "明祇格思，素汾之側。", "祗載吉蠲，宸心翼翼。"]'),
('726f831e-1d9e-413e-a9d0-b2b93ae6c610','汾陰十首 酌獻用《博安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至哉物祖，設象隆脽。',40,'全唐诗/poet.song.250000.json','["至哉物祖，設象隆脽。", "動靜之德，翕闢攸宜。", "嘉栗以薦，精禱洪釐。", "茂宣陰貺，五穀蕃滋。"]'),
('c971c7cb-7d5a-40cb-8858-9b80e3d59660','祗奉天書六首 朝元殿酌獻用《瑞安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','妙道非常，神變無方。',40,'全唐诗/poet.song.250000.json','["妙道非常，神變無方。", "惟天輔德，靈貺誕章。", "玄文昭錫，寶曆彌昌。", "禮崇明祀，式薦馨香。"]'),
('d9bcbc3a-6533-46f7-80f9-2eafbaf8270f','祗奉天書六首 含芳園用《瑞安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','運格熙盛，將封介丘。',40,'全唐诗/poet.song.250000.json','["運格熙盛，將封介丘。", "禮神之域，瑞命殊尤。", "靈文荐降，丕顯皇猷。", "聖心肅奉，永洽鴻休。"]'),
('de828fdb-b596-419c-802b-21b5c38d399f','祗奉天書六首 泰山社首壇升降用《瑞安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','玄穹眷懷，寶符申錫。',40,'全唐诗/poet.song.250000.json','["玄穹眷懷，寶符申錫。", "垂露騰文，粲然靈迹。", "發祥吉圖，純熙寫奕。", "登薦欽崇，式昭天曆。"]'),
('2a6e6cce-fcf0-4ce7-938b-ad61cb9ed802','祗奉天書六首 奉香酌獻用《瑞安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','謂天蓋高，惟皇合德。',40,'全唐诗/poet.song.250000.json','["謂天蓋高，惟皇合德。", "倬彼靈章，圖書是錫。", "眷命諄諄，被以遐曆。", "膺籙告成，虔恭欽翼。"]'),
('b44f018b-c309-495f-a521-707d4597cc60','祗奉天書六首 奉香酌獻用《瑞安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','地屆興王，祥開圖籙。',40,'全唐诗/poet.song.250000.json','["地屆興王，祥開圖籙。", "典禮昭成，祺祥交屬。", "大輅逶迤，卿雲紛鬰。", "祐我含靈，錫茲介福。"]'),
('faf51de5-d079-4782-a8b3-0a2c5e6e6635','祗奉天書六首 升降用《靈文》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','旻穹無聲，惟德是輔。',40,'全唐诗/poet.song.250000.json','["旻穹無聲，惟德是輔。", "降監錫符，垂文篆素。", "孝瑞紀封，英聲載路。", "既壽而昌，篤天之祜。"]'),
('13ccf6d1-6aea-410c-92f3-9f5431459168','祭九鼎十二首 帝鼐降神用《景安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','日號丙丁，方號中央。',40,'全唐诗/poet.song.250000.json','["日號丙丁，方號中央。", "德惟其時，蠲吉是將。", "夫何飲之，黄流玉瓚。", "夫何食之，有陳伊饌。"]'),
('544cde15-c09d-4664-bf1b-3b44539442d6','祭九鼎十二首 奉饌用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','粢盛既豐，牲牢既充。',40,'全唐诗/poet.song.250000.json','["粢盛既豐，牲牢既充。", "展茲熙事，溫溫其恭。", "惟明欣欣，燔炙芬芬。", "保乎天子，繁祉荐臻。"]'),
('1ffde1d3-ea0e-4cb6-b26b-d4e80dedae24','祭九鼎十二首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','工祝致辭，黄流協鬯。',40,'全唐诗/poet.song.250000.json','["工祝致辭，黄流協鬯。", "爰登清歌，載期神享。", "噫予誠心，精禋是虔。", "嘉予陳祀，豐盈豆籩。"]'),
('0953d032-dba9-4797-af34-da2fd9e732b7','祭九鼎十二首 春分，蒼鼎亞、終獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','法乾剛兮，鑄鼎奠方。',40,'全唐诗/poet.song.250000.json','["法乾剛兮，鑄鼎奠方。", "涓嘉旦兮，齊明迎祥。", "胡爲持幣，維箱及筥。", "胡爲和羹，有錡維釜。"]'),
('50529ed3-c31f-471a-8d9a-aef77a1de1ec','祭九鼎十二首 立夏，岡鼎迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我方東南，我日朱明。',40,'全唐诗/poet.song.250000.json','["我方東南，我日朱明。", "爰因其時，鼎以岡名。", "粢盛既馨，牲牷既盈。", "佑我皇家，巽令風行。"]'),
('c658bd60-10f6-435f-8cdc-05911e49f279','祭九鼎十二首 亞、終獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','黄流在中，惟馨香祀。',40,'全唐诗/poet.song.250000.json','["黄流在中，惟馨香祀。", "於薦于神，爰祗厥事。", "禮從多儀，以進爲文。", "尊斝三獻，昭示孔勤。"]'),
('3f05f6b8-c9d9-42b3-820e-13058786fb51','祭九鼎十二首 夏至，彤鼎酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','犧尊將將，徂基自堂。',40,'全唐诗/poet.song.250000.json','["犧尊將將，徂基自堂。", "牲牷肥腯，鼓鐘喤喤。", "肆予醴齊，椒馨飶香。", "聿來歆顧，天祚永昌。"]'),
('b0d57793-f0b7-43fd-9379-f2a15974c952','祭九鼎十二首 立秋，阜鼎酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明德崇享，磬筦鏘鏘。',40,'全唐诗/poet.song.250000.json','["明德崇享，磬筦鏘鏘。", "鏗兮佩舉，峨冠齊莊。", "肆陳有序，承箱是將。", "其牲伊何，籩豆大房。"]'),
('b73da2f3-1e82-473f-b241-807473b5f083','祭九鼎十二首 秋分，皛鼎亞、終獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神宮巍巍，庭燎有輝。',40,'全唐诗/poet.song.250000.json','["神宮巍巍，庭燎有輝。", "聲諧備樂，物陳豐儀。", "清酤既載，酌言獻之。", "惟神醉止，聿來蕃釐。"]'),
('047c65b0-d0e0-4b8d-beea-4246a52c9caf','祭九鼎十二首 立冬，魁鼎迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','時運而冬，乃神玄冥。',40,'全唐诗/poet.song.250000.json','["時運而冬，乃神玄冥。", "陰陽相推，豐年以成。", "越陳嘉肅，牲牢粢盛。", "來享來依，監于明誠。"]'),
('9712c01f-3583-4754-9dde-9cc48f216288','祭九鼎十二首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','罍之初登，其儀昭陳。',40,'全唐诗/poet.song.250000.json','["罍之初登，其儀昭陳。", "罍之既祼，其香升聞。", "神心嘉止，於焉欣欣。", "貽我有年，穰穰其仁。"]'),
('00227f2a-07a2-4c7a-8e7a-cc83e18f7d8c','祭九鼎十二首 冬至，寶鼎奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秉心齊明，奉牲博碩。',40,'全唐诗/poet.song.250000.json','["秉心齊明，奉牲博碩。", "匏絲鏗陳，冠佩儼飾。", "其肆其將，明神來格。", "執奠維何，猗歟幣帛。"]'),
('06c6e605-f93f-446e-b3b6-32d1e61c8165','大中祥符五嶽加帝號祭告八首 迎神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鍾石既作，俎豆在前。',40,'全唐诗/poet.song.250000.json','["鍾石既作，俎豆在前。", "雲旗飛揚，神光肅然。", "當駕飈欻，來乎青圓。", "言備縟禮，享茲吉蠲。"]'),
('4a064834-89f7-4f68-a9e4-309093b29e74','大中祥符五嶽加帝號祭告八首 冊入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','節彼喬嶽，神明之府。',40,'全唐诗/poet.song.250000.json','["節彼喬嶽，神明之府。", "秩秩威儀，肅肅靈宇。", "懿號克崇，庶物咸臯。", "帝籍升名，式綏九土。"]'),
('8fa75e75-0edb-44e7-b268-c9b558f3a918','大中祥符五嶽加帝號祭告八首 酌獻東嶽用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','節彼岱宗，有嚴廟貌。',40,'全唐诗/poet.song.250000.json','["節彼岱宗，有嚴廟貌。", "惟辟奉天，依神設教。", "帝典焜煌，嘉薦普淖。", "至靈格思，殊祥是效。"]'),
('2f960ba2-3d1a-42cb-8fba-44db6a20a8a1','大中祥符五嶽加帝號祭告八首 南嶽。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u8861\u5c71"]','作鎮炎夏，畜茲靈光。',40,'全唐诗/poet.song.250000.json','["作鎮炎夏，畜茲靈光。", "敷與萬物，既阜既昌。", "爰刻溫玉，式薦徽章。", "昭嘏神意，福熙穰穰。"]'),
('ed43cd9e-2328-4b27-904c-a680e9296be4','大中祥符五嶽加帝號祭告八首 西嶽。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u534e\u5c71"]','瞻言太華，奠方作鎮。',40,'全唐诗/poet.song.250000.json','["瞻言太華，奠方作鎮。", "典冊是膺，等威以峻。", "上公奉儀，祀宗薦信。", "介祉萬邦，永配坤順。"]'),
('b4fdee29-aa69-4d96-bec1-e5ba0eda5501','大中祥符五嶽加帝號祭告八首 北嶽。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','仰止靈嶽，鎮于朔方。',40,'全唐诗/poet.song.250000.json','["仰止靈嶽，鎮于朔方。", "增崇懿號，度越彝章。", "祗薦嘉樂，式陳令芳。", "永資純佑，國祚蕃昌。"]'),
('d5b545c2-a0b1-46ab-a339-4280c467b955','大中祥符五嶽加帝號祭告八首 中嶽。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','巖巖神嶽，作鎮中央。',40,'全唐诗/poet.song.250000.json','["巖巖神嶽，作鎮中央。", "肅奉徽冊，尊名孔章。", "聿降飈駕，載獻蘭觴。", "熙事允洽，寶祚彌昌。"]'),
('7e56220a-3931-42ff-a3da-86631cdd655d','大中祥符五嶽加帝號祭告八首 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祗薦鴻名，寅威明祀。',40,'全唐诗/poet.song.250000.json','["祗薦鴻名，寅威明祀。", "有楚之儀，如在之祭。", "奠獻既終，禮容克備。", "神鑒孔昭，福禧來暨。"]'),
('11298107-5403-49cb-8a64-a1cece97dd95','天安殿冊封五嶽帝一首 神出入用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','名嶽奠方，帝儀克舉。',40,'全唐诗/poet.song.250000.json','["名嶽奠方，帝儀克舉。", "吉日惟良，九賓咸旅。", "溫玉鏤文，纁裳正宁。", "禮備樂成，篤神之祜。"]'),
('87eb7846-993b-478a-8e29-a7a80543c184','熙寧望祭嶽鎮海瀆十七首 東望迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盛德惟木，勾芒御神。',40,'全唐诗/poet.song.250000.json','["盛德惟木，勾芒御神。", "沂岱淮海，厥功在民。", "爰熙壇坎，裒對庶神。", "于以歆格，靈貽具臻。"]'),
('e5cf6e50-8f0a-4801-a3fc-b4bfeb894cc8','熙寧望祭嶽鎮海瀆十七首 升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','紳韠襜兮，玉珮橤兮。',40,'全唐诗/poet.song.250000.json','["紳韠襜兮，玉珮橤兮。", "于我將事，神燕喜兮。", "帝命望祀，敢有不共。", "往返于位，肅肅雍雍。"]'),
('91c4efda-fab4-4e93-93c5-87b142b6c1bc','熙寧望祭嶽鎮海瀆十七首 奠玉幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祀以崇德，幣則有儀。',40,'全唐诗/poet.song.250000.json','["祀以崇德，幣則有儀。", "肅我將事，登降孔時。", "精明純潔，罔有弗祗。", "史辭無愧，神用來娭。"]'),
('6ee8688f-3980-430c-817c-84e969c2bf74','熙寧望祭嶽鎮海瀆十七首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肇茲東土，含潤無疆。',40,'全唐诗/poet.song.250000.json','["肇茲東土，含潤無疆。", "維時發春，嘉薦令芳。", "祭用薶沈，順性含藏。", "不涸不童，誕降祺祥。"]'),
('ad754862-c675-4b02-96ca-b072eb543575','熙寧望祭嶽鎮海瀆十七首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之至止，熙壇爲春。',40,'全唐诗/poet.song.250000.json','["神之至止，熙壇爲春。", "神之將歸，旂服振振。", "欻兮迴飈，窅兮旋雲。", "祐于東方，永施厥仁。"]'),
('0a06f7eb-7d8c-4650-9854-25f9620adece','熙寧望祭嶽鎮海瀆十七首 南望迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嵩嵇衡霍，暨厥海江。',40,'全唐诗/poet.song.250000.json','["嵩嵇衡霍，暨厥海江。", "時維長養，惠我南邦。", "肆嚴牲幣，神式來降。", "以侑以妥，百福是龐。"]'),
('16e37bd8-c912-44da-81ee-8a1afbfdb7d3','熙寧望祭嶽鎮海瀆十七首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','景風應律，朱鳥開辰。',40,'全唐诗/poet.song.250000.json','["景風應律，朱鳥開辰。", "肅肅明祀，嘉籩列陳。", "牲用牷物，樂奏蕤賓。", "克綏永福，祐此下民。"]'),
('de118dc0-840b-4df2-9d46-9b72a21f6a3e','熙寧望祭嶽鎮海瀆十七首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鼓鍾云云，龡管伊伊。',40,'全唐诗/poet.song.250000.json','["鼓鍾云云，龡管伊伊。", "神既醉飽，曰送言歸。", "山有厚藏，水有靈德。", "物其永依，往奠炎宅。"]'),
('e7b4a5c7-49ca-4e51-adb2-9a1a37fc21ff','熙寧望祭嶽鎮海瀆十七首 中望迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維土作德，維帝御行。',40,'全唐诗/poet.song.250000.json','["維土作德，維帝御行。", "含養載育，萬物以成。", "有嚴祀典，薦我德馨。", "神其歆止，永用億寧。"]'),
('0e9e8a76-cd6b-4cd6-817f-fd627da87a21','熙寧望祭嶽鎮海瀆十七首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','高廣融結，實維中央。',40,'全唐诗/poet.song.250000.json','["高廣融結，實維中央。", "宣氣報功，利彼一方。", "坎壇以祀，六樂鏘鏘。", "靈其有喜，酌以大璋。"]'),
('238f7dbf-650f-49ec-b1f8-8296c89fbfce','熙寧望祭嶽鎮海瀆十七首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','言旋其處，以奠中域。',40,'全唐诗/poet.song.250000.json','["言旋其處，以奠中域。", "無替厥靈，四方是則。", "神永不息，祀永不愆。", "以享以報，于萬斯年。"]'),
('af3a1c5d-1214-4d6b-9d1a-d2e93d1f15d4','熙寧望祭嶽鎮海瀆十七首 西望迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','品物順說，時司金行。',40,'全唐诗/poet.song.250000.json','["品物順說，時司金行。", "于郊迎氣，以望庶靈。", "雅歌維樂，圭薦惟牲。", "作民之祉，永相厥成。"]'),
('fc058c94-0b99-4393-a548-7e1bea506cdc','熙寧望祭嶽鎮海瀆十七首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','西顥沆碭，執矩司秋。',40,'全唐诗/poet.song.250000.json','["西顥沆碭，執矩司秋。", "諏言協靈，時祀孔修。", "禮有薦獻，爰視公侯。", "秩而祭之，百福是遒。"]'),
('73ad15e3-6c9d-4645-9cb3-5460a6acd260','熙寧望祭嶽鎮海瀆十七首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我樂我神，簋俎腥饔。',40,'全唐诗/poet.song.250000.json','["我樂我神，簋俎腥饔。", "曰神之還，西土是宮。", "于蕃禽魚，于衍草木。", "富我藪隰，滋我高陸。"]'),
('8309004e-c15e-4b7c-a2c6-0fb500b4d325','熙寧望祭嶽鎮海瀆十七首 北望迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝德乘坎，時御閉藏。',40,'全唐诗/poet.song.250000.json','["帝德乘坎，時御閉藏。", "爰潔牲醴，兆茲北方。", "海山攸宅，神施無疆。", "具享蠲吉，降福孔穰。"]'),
('4bce1c3f-ea29-4731-8459-c9a74132819d','熙寧望祭嶽鎮海瀆十七首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','淒寒凝陰，隕籜滌場。',40,'全唐诗/poet.song.250000.json','["淒寒凝陰，隕籜滌場。", "百物順成，黍稷馨香。", "款于北郊，爰因其方。", "何以侑神，薦此嘉觴。"]'),
('da785ad2-2a52-417e-940b-a1d098da9fb3','熙寧望祭嶽鎮海瀆十七首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維山及川，奠宅幽方。',40,'全唐诗/poet.song.250000.json','["維山及川，奠宅幽方。", "我度其靈，降止靡常。", "肅肅坎壇，既迎既將。", "促樂徹俎，是送是望。"]'),
('a6e06f27-1cf1-4e1d-80ed-a9218f144364','紹興祀嶽鎮海瀆四十三首 東方迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝奠九廛，孰匪我疆。',40,'全唐诗/poet.song.250000.json','["帝奠九廛，孰匪我疆。", "繄我東土，山川相望。", "祀事孔時，肅雍不忘。", "嶪峨濛鴻，郁哉洋洋。"]'),
('05b47a3c-3198-4534-9fb7-5cad44907884','紹興祀嶽鎮海瀆四十三首 初獻盥洗用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','青陽肇開，祀事孔飭。',40,'全唐诗/poet.song.250000.json','["青陽肇開，祀事孔飭。", "鬰人贊溉，其馨苾苾。", "敬爾威儀，亦孔之則。", "神之格思，無我有斁。"]'),
('c9c21d6c-86bf-4f40-a856-46555e8514aa','紹興祀嶽鎮海瀆四十三首 奠玉幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','司曆告時，惟孟之春。',40,'全唐诗/poet.song.250000.json','["司曆告時，惟孟之春。", "爰舉時祀，旅于有神。", "鼓鍾既設，珪帛具陳。", "阜蕃庶物，以福我民。"]'),
('cc305187-cfac-41e9-8e9a-6d5bc4412340','紹興祀嶽鎮海瀆四十三首 東嶽位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','巖巖天齊，自古在昔。',40,'全唐诗/poet.song.250000.json','["巖巖天齊，自古在昔。", "膚寸之雲，四方其澤。", "惟時東作，祀事迺飭。", "惠我無疆，恩霑動植。"]'),
('91ae6965-8ae6-49cc-81b2-479d3e6e0a40','紹興祀嶽鎮海瀆四十三首 東鎮位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟山有鎮，雄於其方。',40,'全唐诗/poet.song.250000.json','["惟山有鎮，雄於其方。", "東孰爲雄，于沂之疆。", "祀事有時，爰舉舊章。", "我望匪遥，庶幾燕饗。"]'),
('2835be85-f7cf-49e1-921c-89bea490d1ee','紹興祀嶽鎮海瀆四十三首 東海位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','澒洞鴻濛，天與無極。',40,'全唐诗/poet.song.250000.json','["澒洞鴻濛，天與無極。", "導納江漢，節宣南北。", "順助其功，善下惟德。", "我祀孔時，以介景福。"]'),
('6a45a4ce-e172-48b3-803b-c5865496626f','紹興祀嶽鎮海瀆四十三首 東瀆位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我祀伊何，于彼長淮。',40,'全唐诗/poet.song.250000.json','["我祀伊何，于彼長淮。", "導源桐柏，委注蓬萊。", "扞齊護楚，宣威示懷。", "豆籩列陳，亦孔之偕。"]'),
('15be862a-c76a-41ac-85fb-1dbefca27dc2','紹興祀嶽鎮海瀆四十三首 亞、終獻，酌獻。四位并同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我祀孔肅，神其安留。',40,'全唐诗/poet.song.250000.json','["我祀孔肅，神其安留。", "容與裴回，若止若浮。", "洽此重觴，申以百羞。", "無我斁遺，萬邦之休。"]'),
('71f7b09d-931d-42e5-afbb-677dae93b757','紹興祀嶽鎮海瀆四十三首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蹇兮紛紛，神實戾止。',40,'全唐诗/poet.song.250000.json','["蹇兮紛紛，神實戾止。", "以飲以食，以享以祀。", "𣅺兮冥冥，神亦歸止。", "以醉以飽，以錫爾祉。"]'),
('dc416d2f-9f6e-4022-8e3e-96c3865aa028','紹興祀嶽鎮海瀆四十三首 南方迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','朱明盛長，我祀用飭。',40,'全唐诗/poet.song.250000.json','["朱明盛長，我祀用飭。", "厥祀伊何，山川咸秩。", "如將見之，繩繩齊栗。", "神哉沛兮，消摇來格。"]'),
('6d89ccc0-ad70-442a-a4cc-5fc3dc357c17','紹興祀嶽鎮海瀆四十三首 初獻盥洗、升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','爰熙嘉壇，揭虔毖祀。',40,'全唐诗/poet.song.250000.json','["爰熙嘉壇，揭虔毖祀。", "鬰人沃盥，贊我祼事。", "于降于登，以作以止。", "莫不肅雍，告靈饗矣。"]'),
('7680cf8d-4393-4cd2-9610-6687c4883c5f','紹興祀嶽鎮海瀆四十三首 奠玉幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我祀我享，儀物孔周。',40,'全唐诗/poet.song.250000.json','["我祀我享，儀物孔周。", "一純斯舉，二精聿修。", "璞兮其溫，絲兮其紑。", "是薦潔蠲，神兮安留。"]'),
('52db5dde-966d-4951-b58f-fce0fe24231c','紹興祀嶽鎮海瀆四十三首 南嶽位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u8861\u5c71"]','神曰司天，居南之衡。',40,'全唐诗/poet.song.250000.json','["神曰司天，居南之衡。", "位焉則帝，于以奠方。", "南訛秩事，望禮有常。", "庶幾嘉虞，介福無疆。"]'),
('7133ca9c-a4f9-4d6f-93be-979abf347db3','紹興祀嶽鎮海瀆四十三首 南鎮位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維南有山，于彼會稽。',40,'全唐诗/poet.song.250000.json','["維南有山，于彼會稽。", "作鎮在昔，神則司之。", "厥有舊典，以祀以時。", "百味維旨，靈其燕娭。"]'),
('a91a4346-45fc-4b2f-a3d0-955759eeb4bb','紹興祀嶽鎮海瀆四十三首 南海位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維水善下，利物曰功。',40,'全唐诗/poet.song.250000.json','["維水善下，利物曰功。", "逶迤百川，誰歟朝宗。", "蕩蕩大受，於焉會同。", "膋蕭列陳，以答鴻濛。"]'),
('7f85687f-c9c0-44c8-8ef7-0748d82a652c','紹興祀嶽鎮海瀆四十三首 南瀆位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四瀆之利，經營中國。',40,'全唐诗/poet.song.250000.json','["四瀆之利，經營中國。", "南曰大江，險兮天設。", "維爾有神，隃其廟食。", "望秩孔時，我心翼翼。"]'),
('630be637-7e1c-4327-bc7d-88af6a15321c','紹興祀嶽鎮海瀆四十三首 亞、終獻，酌獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之游兮，洋洋對越。',40,'全唐诗/poet.song.250000.json','["神之游兮，洋洋對越。", "澹乎容與，肸蠁斯答。", "乃奏既備，八音攸節。", "重觴申陳，百禮以洽。"]'),
('1ef4e5cf-7f15-476d-b24f-c6a8ab9006f5','紹興祀嶽鎮海瀆四十三首 送神。曲同迎神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','薦徹豆籩，熙事備成。',40,'全唐诗/poet.song.250000.json','["薦徹豆籩，熙事備成。", "靈兮將歸，羽旄紛紜。", "飄其逝矣，浮空籋雲。", "悵然顧瞻，有撫懷心。"]'),
('21ae381a-1af1-4a5c-8f64-d01a7774ff44','紹興祀嶽鎮海瀆四十三首 中央迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天作高山，屹然中峙。',40,'全唐诗/poet.song.250000.json','["天作高山，屹然中峙。", "經營厥宇，萬億咸遂。", "火熙土王，爰舉時祀。", "繩繩宣延，彷彿來止。"]'),
('bbc5e6ea-37be-467d-9538-8f66fe284d83','紹興祀嶽鎮海瀆四十三首 初獻盥洗、升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思來感格，肅雍不忘。',40,'全唐诗/poet.song.250000.json','["思來感格，肅雍不忘。", "禮儀既備，濟濟蹌蹌。", "潔蠲致敬，往薦其芳。", "交若有承，神兮孔饗。"]'),
('26afabfd-ed2d-400f-9501-9eb569abc268','紹興祀嶽鎮海瀆四十三首 奠玉幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','練日有望，高靈來下。',40,'全唐诗/poet.song.250000.json','["練日有望，高靈來下。", "何以告誠，心惟物假。", "有篚斯實，有寶斯籍。", "于以奠之，神光燭夜。"]'),
('5d989623-442b-4dcf-bdd9-d7fee48a29f5','紹興祀嶽鎮海瀆四十三首 中嶽位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','與天齊極，伊嵩之高。',40,'全唐诗/poet.song.250000.json','["與天齊極，伊嵩之高。", "顯靈效異，神休孔昭。", "飭我祀事，實俎鸞膋。", "以侑旨酒，其馨有椒。"]'),
('0bda170c-f731-4c4a-8f5f-22769e0a97d0','紹興祀嶽鎮海瀆四十三首 中鎮位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禹畫九州，河內曰冀。',40,'全唐诗/poet.song.250000.json','["禹畫九州，河內曰冀。", "霍山崇崇，作鎮積勢。", "我祀如何，百末旨味。", "承神燕娭，諸神畢至。"]'),
('64bcd8ce-9c32-4796-afa3-9d396f794fa1','紹興祀嶽鎮海瀆四十三首 亞、終獻，酌獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮樂既成，肅容有常。',40,'全唐诗/poet.song.250000.json','["禮樂既成，肅容有常。", "奄留消摇，申畢重觴。", "仰臚所求，降福滂洋。", "師象山則，以況皇章。"]'),
('771c60a6-2b5a-48fb-ab7a-168b70a835b5','紹興祀嶽鎮海瀆四十三首 送神。曲同迎神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','虞至旦兮，靈亦有喜。',40,'全唐诗/poet.song.250000.json','["虞至旦兮，靈亦有喜。", "蹇欲驤兮，象輿已轙。", "粥音送兮，靈聿歸矣。", "長無極兮，錫我以祉。"]'),
('b727f354-1956-49ac-9ce1-7b2fe5761784','紹興祀嶽鎮海瀆四十三首 西方迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有岌斯安，有涵斯洽。',40,'全唐诗/poet.song.250000.json','["有岌斯安，有涵斯洽。", "聿相厥成，允祀是答。", "爰飭迺奏，迺奏既協。", "於昭降止，是遵是接。"]'),
('f3da3eb8-7b3e-4229-a6e0-e332000c34b2','紹興祀嶽鎮海瀆四十三首 初獻盥洗、升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靡實不新，靡陳不濯。',40,'全唐诗/poet.song.250000.json','["靡實不新，靡陳不濯。", "人之弗蠲，矧敢將酌。", "載晞之帨，載濡之勺。", "洗儀告備，陟降時若。"]'),
('14ca23da-6273-4237-bb24-4996f49458fc','紹興祀嶽鎮海瀆四十三首 奠玉幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼林有庪，彼澤有沈。',40,'全唐诗/poet.song.250000.json','["彼林有庪，彼澤有沈。", "猗與西望，弗菲弗淫。", "迺追斯邸，迺㡛斯尋。", "卬禮既卒，是用是歆。"]'),
('7b14a1d1-a1ae-41c2-a371-59d2f8173329','紹興祀嶽鎮海瀆四十三首 西嶽位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u534e\u5c71"]','屹削厥方，風雲斯所。',40,'全唐诗/poet.song.250000.json','["屹削厥方，風雲斯所。", "陰邑有宮，侐侐俁俁。", "清酤在尊，靈眷在下。", "于俎獻兮，則莫我吐。"]'),
('c4b52fa0-b210-4469-a45a-4b6fcbdff421','紹興祀嶽鎮海瀆四十三首 西鎮位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維吳崇崇，于汧之西。',40,'全唐诗/poet.song.250000.json','["維吳崇崇，于汧之西。", "瞻彼有隴，赫赫不迷。", "克裨于嶽，我酌俶齊。", "於凡有旅，眡公維躋。"]'),
('b0c94b1f-e010-428b-97cc-5ae07b6775c0','紹興祀嶽鎮海瀆四十三首 西海位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奄浸坤軸，滋殖其濊。',40,'全唐诗/poet.song.250000.json','["奄浸坤軸，滋殖其濊。", "而典斯稽，有陛有壝。", "弗替時舉，元斝斯酹。", "胡先于河，實委之會。"]'),
('5c4bc754-e4ca-480b-9c1e-9f527638817d','紹興祀嶽鎮海瀆四十三首 西瀆位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','自彼崑虛，于以潜流。',40,'全唐诗/poet.song.250000.json','["自彼崑虛，于以潜流。", "念茲誕潤，豈侯不猶。", "在昔中府，暨海聿脩。", "迄既望止，神保先卣。"]'),
('68458eea-08ee-4a13-9232-0ed4b6f5eb1a','紹興祀嶽鎮海瀆四十三首 亞、終獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅其乂，既旨既溢。',40,'全唐诗/poet.song.250000.json','["肅肅其乂，既旨既溢。", "迨其畢酌，偏茲博碩。", "祀事既遂，不敢誶射。", "神或醉止，我心斯懌。"]'),
('3100f2ef-5087-4205-9d36-a372732a1119','紹興祀嶽鎮海瀆四十三首 送神。曲同迎神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','迺羞既徹，迺奏及闋。',40,'全唐诗/poet.song.250000.json','["迺羞既徹，迺奏及闋。", "無餕斯俎，式聽致謁。", "不蹇不蹶，不沸不决。", "厲魃其祛，永庇有截。"]'),
('501d8d5b-2c14-46bf-b5ca-d9734a10057d','紹興祀嶽鎮海瀆四十三首 北方迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我土綿綿，孰匪疆理。',40,'全唐诗/poet.song.250000.json','["我土綿綿，孰匪疆理。", "惟時幽都，匪曰隃只。", "滌哉艮月，朔風其同。", "曷阻曷深，其亦來降。"]'),
('9b7311c8-a8e3-4a63-a602-36254fe84eb3','紹興祀嶽鎮海瀆四十三首 初獻盥洗、升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','壽宮煇煌，聿修時祀。',40,'全唐诗/poet.song.250000.json','["壽宮煇煌，聿修時祀。", "繽其臨矣，吉蠲以竢。", "居乎昂昂，行乎遂遂。", "敬爾攸司，展采錯事。"]'),
('cf37ff7c-1134-4d7b-8852-727114fd1741','紹興祀嶽鎮海瀆四十三首 奠玉幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','相予陰威，厥功浩浩。',40,'全唐诗/poet.song.250000.json','["相予陰威，厥功浩浩。", "一歲之功，何以爲報。", "府有珪幣，我其敢私。", "肅肅孔懷，于以將之。"]'),
('b85cb384-451b-4883-8f4d-f15bac791240','紹興祀嶽鎮海瀆四十三首 北嶽位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瞻彼芒芒，曰北之常。',40,'全唐诗/poet.song.250000.json','["瞻彼芒芒，曰北之常。", "既高既厚，迺紀迺綱。", "薦鬯伊始，靈示孔將。", "玄服鐵駕，覽此下方。"]'),
('18ae82a1-670c-469e-bd2b-59ef6b48133f','紹興祀嶽鎮海瀆四十三首 北鎮位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫作鎮，幽朔之垂。',40,'全唐诗/poet.song.250000.json','["赫赫作鎮，幽朔之垂。", "兼福我民，食哉具宜。", "克配彼岳，有嚴等衰。", "蠲我灌禮，其敢不祗。"]'),
('c895a16f-e0cc-496f-957c-18fe0509edd4','紹興祀嶽鎮海瀆四十三首 北海位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','八裔皆水，此一會同。',40,'全唐诗/poet.song.250000.json','["八裔皆水，此一會同。", "沄沄天墟，洞蕩洪濛。", "至哉維坎，不有斯功。", "所秩伊何，黄流在中。"]'),
('38ee6b0a-314a-4735-b08a-6c3bfed4a6ca','紹興祀嶽鎮海瀆四十三首 北瀆位。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','水星之精，播液發靈。',40,'全唐诗/poet.song.250000.json','["水星之精，播液發靈。", "不脅于河，既介以清。", "翼翼盥薦，椒糈芬馨。", "載止載留，爰弭翠旌。"]'),
('828e3678-b3f3-48a1-924e-d15eb0e71297','紹興祀嶽鎮海瀆四十三首 亞、終獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','俎豆紛披，金石繁會。',40,'全唐诗/poet.song.250000.json','["俎豆紛披，金石繁會。", "侑以貳尊，匪瀆匪怠。", "我儀既周，我心孔戒。", "憺兮容與，彷彿如在。"]'),
('4d6ca448-cebb-4fb9-8f4b-24698c3255dc','紹興祀嶽鎮海瀆四十三首 送神。曲同迎神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈既醉飽，禮斯徹兮。',40,'全唐诗/poet.song.250000.json','["靈既醉飽，禮斯徹兮。", "靈亦樂康，樂斯闋兮。", "雲征飈舉，不可尼兮。", "薦福錫祉，曷有極兮。"]');
